INSERT INTO `o_assets` (`id`, `name`, `prompt`, `remark`, `type`, `describe`, `scriptId`, `imageId`, `assetsId`, `projectId`, `flowId`, `startTime`, `promptState`, `audioBindState`, `promptErrorReason`) VALUES
(1, '陈平安', '**基础参数：**\n**角色设定：**\n- 角色名称:陈平安\n- 角色描述:十四五岁少年，身形清瘦，粗布衣衫打着补丁但浆洗得干净，虎口和指腹布满拉坯老茧，眼神沉静如深潭，气质隐忍坚韧\n\n**3D超精致建模 通用角色四视图标准：**\n\n纯色背景，独立角色展示图，均匀光照，无投影。四视图完整展示：正视图、侧视图、后视图、3/4侧视图。角色为十四五岁少年，身形清瘦，粗布衣衫打着补丁，眼神沉静，气质隐忍坚韧。\n\n**3D超精致建模 角色正面特写生成：**\n一位14岁的泥瓶巷少年陈平安，身形清瘦但脊梁挺直，如一根压不弯的劲竹，粗布衣衫打着补丁但浆洗得干净，虎口和指腹布满拉坯留下的老茧，面容清秀却透着一股与年龄不符的沉稳，眼神沉静如深潭能映照人心，常年抿着的嘴角透出骨子里的倔强，气质隐忍坚韧如荒野里的野草，生来平凡却自有气度，五官清俊，青涩隐忍坚韧标签，3D超精致建模，无表情，正对镜头，超特写', NULL, 'role', '十四五岁少年，身形清瘦，粗布衣衫打着补丁但浆洗得干净，虎口和指腹布满拉坯老茧，眼神沉静如深潭，气质隐忍坚韧', NULL, 1, NULL, 1779904318831, NULL, 1779908070222, '已完成', NULL, NULL),
(2, '宋集薪', '一位12岁的少年，泥瓶巷没落贵族子嗣，旧锦暗纹流转于袖口，常蹲墙头如栖鸦俯视众生，性情倨傲刻薄暗自矛盾，眉眼细长微挑，薄唇紧抿，带三分不屑七分孤清，锦衣·乌鸦·刻薄·骄子，3D超精致建模，无表情，超特写。', NULL, 'role', '与陈平安年龄相仿的锦衣少年，衣衫虽旧但质地考究，袖口隐隐有暗纹流转，蹲墙头姿态如乌鸦，神情倨傲刻薄', NULL, 2, NULL, 1779904318831, NULL, 1779908070222, '已完成', NULL, NULL),
(3, '稚圭', '一位14的女，婢女，杏眼怯怯如幼鹿惊惧，常后退，四肢发抖，怕四脚蛇，十四龄婢女胆怯如小兽，怯弱，胆小，敏感，杏眼，薄唇，紧绷的脸庞、柔弱、惊惶、不安、惊怯婢女3D超精致建模，无表情，正对镜头，超特写。', NULL, 'role', '约莫十三四岁的婢女，一双杏眼怯怯的，像察觉到危险的小兽，面对锦衣少年时会下意识后退，对四脚蛇之事有本能恐惧', NULL, 3, NULL, 1779904318831, NULL, 1779908070222, '已完成', NULL, NULL),
(4, '锦衣少年', '一位15岁的男，锦衣少年，一袭月白长衫袖口领缘绣暗金色云纹眉眼含笑神态闲适从容，锦衣少年含笑从容，含笑闲适，精致眉眼，从容优雅，3D超精致建模，无表情，正对镜头，超特写。', NULL, 'role', '十五六岁，一袭月白长衫，袖口领缘绣暗金色云纹，面料中嵌有微缩星辰般的光点缓缓流动，眉眼含笑，神态闲适从容', NULL, 4, NULL, 1779904318831, NULL, 1779908070222, '已完成', NULL, NULL),
(5, '阮铁匠', '一位45岁的男性，经验丰富的铁匠，方脸宽额，锐利双眼如刀，眉有缺痕，皮肤汗渍遍布，铁匠铺中幽火注视之人，务实而带神秘感，粗犷五官、硬朗神秘、铁匠幽火3D超精致建模，无表情，正对镜头，超特写。', NULL, 'role', '膀大腰圆的中年汉子，肩搭汗巾，目光打量人如打量工具，铁匠铺中火星四溅时，炉膛火光带一丝诡异的幽蓝', NULL, 5, NULL, 1779904318831, NULL, 1779908070222, '已完成', NULL, NULL),
(6, '吴爷爷', '一位65岁的男性，饱经世故却深藏不露的家族掌门人，与世无争的表象下暗流涌动，以慈眉善目为铠甲，以锐利审视作佩剑，从容掌控全局的谋略家，面容白皙，须发灰白梳得一丝不苟，眼睛常眯成细缝，嘴角挂和蔼笑意，目光却暗藏审视，五官舒展透着福相，气质儒雅清癯却隐含威严，儒雅猎手，3D超精致建模，无表情，正对镜头，超特写。\n\n（正面视角：无表情，正对镜头，超特写）面容白皙，灰白须发梳理得一丝不苟，银丝根根分明；眼睛眯成细缝，深藏锐利审视；嘴角习惯性挂着一丝和蔼笑意。防同模：独特瘦削却饱满的脸型，高挺鼻梁，唇边深刻法令纹。3D超精致建模，无表情，正对镜头，超特写，无动作。\n\n（背面视角：无表情，正对镜头，超特写）身形高大的老者背影，银灰色短发和长须梳得一丝不苟，完美贴合脖颈与后背线条；宽阔平直的肩背轮廓，尽显稳健从容。防同模：独特的颅骨形状与后颈皱纹，挺拔如山的身姿。纯色背景，顶级CG渲染，无动作。\n\n（侧面视角：无表情，正对镜头，超特写）清癯而威严的侧脸轮廓，灰白须发一丝不苟，高挺的鼻梁与紧抿的唇角线条分明。眼睛眯成细缝，侧面更能捕捉那审视的余光。防同模：完美雕刻般的侧面骨相，微凸的眉骨与内收的下颌。3D超精致建模，无表情，正对镜头，超特写，无动作。\n\n（3/4侧身视角：无表情，正对镜头，超特写）儒雅而暗藏锋芒的面孔，视角绝佳地捕捉到眯起的眼缝中一闪而过的审视。须发灰白，一丝不苟，似笑非笑的嘴角，组合出一种不怒自威的气场。防同模：动态光影下独一无二的脸部结构，骨骼与皮肤肌理细节雕琢，辨识度极强。3D超精致建模，无表情，正对镜头，超特写，无动作。\n\n（总结）角色特性：面容白皙，须发灰白梳得一丝不苟，眼睛常眯成细缝，目光暗藏审视；呈现形式：四视图（正面/背面/侧面/3/4侧身），均为3D超精致建模，无表情，正对镜头，超特写，无动作，保持静止状态，不容任何动作破坏角色的神秘感与威严感。四视图风格绝对统一，精准锁定面容白皙、须发灰白、眼睛眯缝、目光审视等核心特征的建模一致性，防同模参数生效，绝不平庸。', NULL, 'role', '身形高大的老者，面容白皙，须发灰白梳得一丝不苟，眼睛常眯成细缝，嘴角挂和蔼笑意，目光却暗藏审视', NULL, 6, NULL, 1779904318831, NULL, 1779908070222, '已完成', NULL, NULL),
(7, '中年人', '一位45岁的男性，穿粗布短褂拎鱼篓在骑龙巷叫卖的鱼贩，沟壑皮肤横额纹鱼尾眼角左眉有疤方下颌古铜色，鱼贩短褂拎篓叫卖市井，精明随和开朗，粗糙皮肤深眼窝厚唇圆鼻头鱼尾纹、市井质朴生活气息、市井鱼贩3D超精致建模，无表情，正对镜头，超特写。', NULL, 'role', '穿粗布短褂的鱼贩，拎着鱼篓在骑龙巷叫卖，被陈平安追着讨价还价，最终因锦衣少年五十文截走鲤鱼而眉开眼笑', NULL, 7, NULL, 1779904318831, NULL, 1779908070222, '已完成', NULL, NULL),
(8, '老宅屋内', '好的，收到你的场景设定。这并非一个需要“生成”的场景，而是一个已经存在且极具叙事潜力的空间原点。我的任务是，依据手册中“3D国风赛博”的核心美学，为这个“黄土老宅”注入未来主义的灵魂，并严格按照规范，生成一套完整的场景设定图方案。\n\n这是一个典型的“古风场景赛博化改造”案例，我会紧扣“古今共生”与“质感至上”的原则。\n\n---\n\n### **3D国风赛博场景图 · 约束手册执行方案**\n\n**场景名称：** 赛博蛰居 · 黄土老宅\n**风格定位：** 秦汉风骨 + 底层赛博遗存改造\n**季节/时间：** 深秋 / 暮色初临\n**色调映射：** 主色调：赭石(夯土墙) + 残旧全息金(电子金)；辅色调：锈铁红(窗棂/车骸) + 月白(全息月光) + 冰蓝(冷霓虹)。\n\n---\n\n#### **场景美学 & 空间叙事执行**\n\n1.  **空间叙事：** 此场景承载一个“被时代遗弃的隐居者或守旧派”的叙事。它并非赛博都市的繁华，而是被巨型都市遗忘的边陲老宅。赛博科技在这里不是升级，而是苟延残喘的遗存，体现了强烈的东方宿命感与赛博朋克的“高科技低生活”。\n2.  **层次纵深：**\n    *   **前景：** 散落在地、落满灰尘的轱辘车残骸，其木质辐条上缠绕着早已不亮的光纤线缆，如同枯藤。一块碎裂的、闪烁着雪花噪点的全息信息板（展示着过期的旧闻或模糊的家庭影像）斜靠在车辕旁。\n    *   **中景：** 房间的核心，那张硬木板床。床上铺着磨损的、带有织锦暗纹的被褥，被褥一角连接着几根纤细的充电和数据管线，延伸至墙角的能源接口。墙上褪色的釉线暗纹，其沟壑中有极微弱的靛蓝色冷霓虹在流淌。\n    *   **后景：** 破败的木质窗棂，通过它可以看到远处，如同巨兽般灯火辉煌、悬浮天际的赛博都市轮廓，与屋内的晦暗形成极致的反差。\n3.  **古今共生：** 所有赛博元素都呈现出“后天改造”和“年久失修”的状态。科技是为了让这个古老空间勉强维持基本功能，而非变得光鲜亮丽。\n4.  **质感至上：**\n    *   **黄土墙：** PBR物理材质，体现夯土的颗粒感、脱落、碱化和风化痕迹。\n    *   **木板床/轱辘车：** 表现木材的干燥开裂、失去光泽的包浆、坚硬冰冷的触感。\n    *   **釉线暗纹：** 釉质的龟裂与剥落，内部渗出的冷霓虹光与暮色的暖形成对比。\n    *   **光纤/全息屏：** 表现光纤的塑料老化、发黄，全息屏的故障频闪、低分辨率和半透明质感。\n5.  **3D为锚：** 以3A游戏的废墟场景建模标准执行。强调暮色余晖从破窗射入的体积光（丁达尔效应），与墙上釉线微弱的自发光、全息屏的故障光形成复杂的环境光遮蔽。\n\n---\n\n#### **四视图设定图构建方案**\n\n**摄像机设定：** 放置于房间几何中心，采用**人眼平视**的固定视点，营造身处其中的沉浸感。\n\n*   **左上 - 前视图 (0°)**\n    *   **视角：** 正对木板床和床后的墙。\n    *   **画面内容：** 前景为碎裂的全息信息板；中景为床铺及垂下的管线，墙上的釉线暗纹是视觉焦点，正以微弱的冰蓝霓虹光勾勒出古老的图腾；后景为窗外模糊的都市场景。暮光从画面左侧射入，形成体积光。\n\n*   **右上 - 右视图 (90°)**\n    *   **视角：** 正对堆放轱辘车残骸的墙角。\n    *   **画面内容：** 前景是车骸最清晰的一侧，可见缠绕的老化光纤；中景是斑驳的黄土墙角，墙皮剥落露出内部的老砖；后景远处，窗棂的侧面框架限制了视野，但仍可见部分都市远景。光影逻辑与0度保持一致，暮光从该视角的远方（左后方）而来。\n\n*   **左下 - 后视图 (180°)**\n    *   **视角：** 正对破败的木质窗棂和窗外的赛博都市。\n    *   **画面内容：** 前景是床尾、简陋的陶罐等物品；中景为作为剪影的窗棂框架；后景是窗外清晰可见的、流光溢彩的摩天楼群、浮空轨道和光污染的夜空，与屋内的暗形成对比。画面应呈现逆光剪影效果，但屋内釉线光源仍在。\n\n*   **右下 - 左视图 (270°)**\n    *   **视角：** 正对房间的另一面空荡荡的斑驳墙壁和部分入口。\n    *   **画面内容：** 前景是车骸的另一侧和地上的杂物；中景是空旷的夯土地面和带有裂缝的墙，墙上可能挂着一件早已停止运转的赛博蓑衣或工具；后景同样是窗棂提供的远处都市轮廓。光影逻辑全程统一，光源位置、强度、阴影方向完全一致。\n\n---\n\n#### **提示词模板 (可直接用于AI绘图工具)**\n\n3D国风赛博场景四视图设定图，\n3A游戏级3D渲染，RTX路径追踪，全局光照，高精度硬表面建模，PBR物理材质，国风赛博3D，电影级CG光影，东方未来主义，低科技生活感，\n3D rendered, cyberpunk guofeng, oriental futurism, low-life high-tech, volumetric lighting, RTX path tracing, global illumination, PBR materials, ancient ruins with cyberpunk remnants,\ndepth of field, natural lens vignette, subtle chromatic aberration, dust motes in volumetric light, lens flare,\n超高清8K纹理，暮色体积光，残旧全息投影补光，物理级精准光影，环境光遮蔽，\nscene design sheet, environment concept art, no people, no characters, no human figures, no creatures,\n古风室内，{秦汉风骨 + 底层赛博遗存改造}，深秋，暮色,\n前景：{落灰且缠绕老化光纤的轱辘车骸/故障闪烁的全息信息板}, 中景：{硬木板床/连接着管线的旧被褥/如血管般流淌霓虹的褪色釉线暗纹}, 后景：{破败的木窗棂/窗外灯火辉煌的巨型赛博都市天际线},\n赭石夯土墙映衬残旧全息金光，墙上暗纹流淌冰蓝冷霓虹，暮光暖色与赛博冷光对冲,\n黄土墙风化碱化、木板干裂包浆、釉线龟裂、光纤老化、故障全息屏噪点, 空气透视, 8K超高清纹理细节, 材质物理属性准确,\n夯土严重风化，窗棂木框朽坏，釉线沟壑积尘，全息屏低分辨率频闪，霓虹光管轻微光衰，\n全息体积光，RTX全局光照，环境光遮蔽，暮光自然漫射，暗纹霓虹自发光补光，极致的暖冷光影对冲，\n同一画面2×2网格均匀排列：从场景中心点360°环视，前视图+右视图+后视图+左视图，\n四视图均从同一中心点人眼平视拍摄，斑驳墙体结构一致，废弃赛博装置布局一致，釉线霓虹光效位置一致，窗外都市轮廓一致，材质老旧程度一致，光影逻辑完全一致，\n画面中无任何人物、人影、人体轮廓，\n图中不要有任何文字、水印、logo、标注', NULL, 'scene', '黄土夯成的破败老宅，四壁空空，一张硬木板床，墙角堆着落灰的轱辘车残骸，墙上褪色釉线暗纹如干裂血管，窗棂破败渗入暮色', NULL, 8, NULL, 1779904318831, NULL, 1779908070222, '已完成', NULL, NULL),
(9, '院中', '**3D国风赛博场景四视图设定图** · **泥瓶巷 · 院中 (春夜)**\n\n**核心叙事与视觉基调：**\n本场景锚定“小尺度古风场景的赛博化改造”，以陈平安童年记忆中的破败院落为空间内核，承载“贫寒中的一丝暖色”这一情绪叙事。采用春季夜景色调，通过全息桃花、嵌入土墙的微光釉线等克制而有机的赛博符号，在破败的黄土墙垣上点染东方未来主义的温情，实现“古风为核，赛博为用”的古今共生。\n\n**四视图空间结构 (人眼平视视点统一)：**\n*   **前景：** 黄土矮墙墙头，几株全息桃花斜伸而出，花瓣边缘泛着微弱的荧光桃红，在月光下呈现半透明的数据质感。\n*   **中景：** 院中破败的石阶，阶旁搁着那枝作为核心叙事点的桃枝。黄土矮墙与石阶的缝隙里，嵌着几条微光釉线，光线暗淡，如呼吸般缓慢流转。\n*   **后景：** 沿山脊起伏的龙窑轮廓，其剪影在月色与赛博光雾中愈发神秘。远处，龙窑的窑口和窑身上，有规律的阵列着星星点点的霓虹青与电子青绿光点，勾勒出巨龙盘踞的形体，与天际清冷的月亮形成古今对照。\n\n**2x2网格四视图布局：**\n*   **左上 (前视图 0°):** 从院中心正对院门方向。以上方垂下的全息桃枝为前景框架，穿过画面主体——破败石阶和那枝关键的桃枝，望向背景中龙窑雄伟有力的“龙头”和蜿蜒的“龙身”起点。\n*   **右上 (右视图 90°):** 视角转向院墙右侧。前景是嵌有釉线暗纹的斑驳土墙，中景看到石阶侧面，后景是龙窑中部连绵起伏的山脊线，窑体上的赛博光点此起彼伏。\n*   **左下 (后视图 180°):** 从院中心望向院落后方。前景是更显破败的后院土墙和丛生的全息苔藓（电子青绿色），中景是老旧的屋宅后墙和墙角破损的光膜装置，后景是龙窑的尾部，逐渐隐没在远处的电子薄雾之中。\n*   **右下 (左视图 270°):** 视角转向院墙左侧。前景是另一段黄土墙，墙头搁着一个废弃的、表面氧化磨损的赛博装置。中景看到石阶的另一侧，那枝桃枝仍在中景视觉焦点处。后景是龙窑的另一侧山脊，其上的赛博光点在此角度形成了更密集的光带。\n\n**全维度合规自检：**\n1.  **场景融合度:** 遵循**古今共生**原则。以泥瓶巷破败黄土墙、石阶、龙窑等**极贫寒**的古风元素为**绝对核心与情绪基底**，赛博元素以“内敛的微光”（釉线暗纹、全息桃花、龙窑上的光点）形式出现，是服务于情绪的**点缀与升级**，绝非炫技堆砌，杜绝风格割裂。\n2.  **风格适配:** 完全符合**小尺度古风场景**要求，采用**人眼平视**视点，营造身临其境的沉浸感。季节设置为**春季 · 夜晚**，色调遵循手册规定（青绿+朱红，辅以月白、荧光桃红、电子青），以清冷的月白光膜质感与温暖的桃红荧光、龙窑的青绿光点形成**赛博冷暖撞色**。\n3.  **材质与质感:** 严格遵循**质感至上**与**瑕疵感**要求。土墙的夯土肌理、石阶的风化裂纹、木门上自然的包浆与开裂、全息光膜的垂褶感、釉线的物理磨损，均以**8K/PBR级物理质感**呈现，真实可信。\n4.  **四视图一致性:** 四视图均从院中心**人眼平视**的同一中心点出发拍摄。土墙结构、石阶位置、桃枝的视觉焦点、龙窑的山脊轮廓、赛博元素的位置及光影方向**100%完全一致**，空间逻辑自洽。\n5.  **禁止项检查:**\n    *   **无人物:** 画面中无任何人、人影或生物。\n    *   **无风格割裂:** 未出现纯西式赛博朋克元素，赛博与国风有机共生。\n    *   **无完美塑料感:** 材质100%带有岁月与使用痕迹。\n    *   **有体积光与景深:** 强制包含月光穿过全息桃枝的**体积光**、远景龙窑的**空气透视**及因镜头虚化产生的荧光**散景**。', NULL, 'scene', '泥瓶巷黄土矮墙围成的破败院子，石阶旁搁桃枝，月光清冷洒落，远处可见连绵龙窑沿山脊起伏，墙上釉线暗纹在月色下泛微弱光泽', NULL, 9, NULL, 1779904318831, NULL, 1779908070222, '已完成', NULL, NULL),
(10, '骑龙巷铁匠铺', '好的，这是为您生成的「骑龙巷铁匠铺」3D国风赛博场景图设定与提示词。\n\n### **艺术约束手册**\n\n---\nname: qilong_ally_blacksmith\ndescription: 骑龙巷铁匠铺 · 3D国风赛博场景四视图设定\nmetaData: art_skills\n---\n# 骑龙巷铁匠铺 · 3D国风赛博场景四视图设定\n\n---\n\n## 一、场景美学原则\n\n1.  **空间叙事** — 场景聚焦于骑龙巷口一个临时搭建的铁匠铺，通过诡异幽蓝的炉火与门外形成的“光墙”，营造神秘东方未来主义下的市井一角。铺内是高温锻造的赛博日常，铺外是清冷的巷口，光影对比承载叙事张力。\n2.  **层次纵深** — 前景为巷口石板路与散落的金属零件，中景为铁匠铺核心工作区（炉膛、铁砧、风箱），后景为延伸入黑暗的骑龙巷与远处霓虹微光，立体展现空间深度。\n3.  **古今共生** — 传统铁匠铺的夯土墙、木结构、铁砧与赛博改造后的蓝焰炉膛、光膜风箱、量子淬火槽有机融合。门框作为结界，分隔铺内炽烈与巷外清冷，体现“古今-光暗”共生。\n4.  **质感至上** — 强调粗糙与光滑的对比：龟裂的夯土墙、包浆的木柄铁锤、氧化的黄铜风箱，与光滑的阳极氧化铝淬火槽、发光的全息温度面板形成8K级肌理对比。\n5.  **3D为锚** — 以3A级3D渲染为标准，通过RTX路径追踪精确计算炉膛蓝焰的体积光与金属表面的反射，利用景深效果强化铺内外“光墙”的视觉奇观。\n\n---\n\n## 二、季节色调映射\n\n*   **季节**: 仲秋\n*   **主色调**: 赭石（夯土/锈铁）+ 幽蓝（炉膛核心焰）\n*   **辅色调**: 暖霓虹橙（飞溅火星）、墨黑（巷口深处）、青灰（石板路）\n*   **提示词**: 赛博秋夜、电子薄雾、巷口冷风、铺内高温扭曲空气、幽蓝火光与暖橙火星对冲、全息温度警示橙\n\n---\n\n## 三、室外场景空间规范\n\n| 维度 | 约束 | 提示词 |\n|---|---|---|\n| **类型** | 古巷口、临时铁匠铺的赛博化改造，属于“赛博集市/霓虹长街”的微观特写，保留市井肌理，融入赛博工业科技 | 国风赛博巷口铁匠铺，仲秋，深夜，古风市井赛博化改造 |\n| **天候** | 深夜，阴，有电子薄雾弥漫在巷中，铺内高温与外部冷空气在门口形成空气对流与光扭曲 | 深夜电子薄雾弥漫，门口热气蒸腾扭曲光线，光墙内外温差 |\n| **植被** | 墙角生有发光的电子青苔，墙根堆着废弃的赛博零件 | 电子青苔微光、废弃金属零件、赛博工业废料 |\n| **水体** | 淬火槽内盛有发光的蓝色液体，表面张力异常，溅出时在半空凝结为全息蒸汽 | 全息淬火液、幽蓝液态光、溅射冷却的发光蒸汽 |\n| **建筑** | 临时搭建的棚铺，夯土墙基与钢架结构，悬挂全息招牌「鍛」字，门框因长期高温微微碳化，门内外形成光墙界面 | 夯土墙赛博钢架棚、碳化木门框、全息「鍛」字招牌、光墙结界 |\n| **空气感** | 铺内空气因高温产生扭曲波纹，与巷中冷雾在门口激烈对冲，形成可见的光影切割面，近处火星四溅清晰，远处巷景模糊 | 热浪扭曲空气、冷雾遇热蒸腾、门口光墙分割、近实远虚透视 |\n| **光照** | 主光源为炉膛内诡异的幽蓝火焰，辅光为飞溅的暖橙色火星。铺外是清冷昏暗的巷口环境光，由远处霓虹招牌漫反射补光。强制体积光呈现幽蓝光束穿透热雾的效果。 | 幽蓝体积光、暖橙火星四溅、炉火为核心主光源、巷口冷光漫反射、路径追踪显示光墙效果 |\n| **镜头感** | 镜头聚焦于铁匠铺内部，对门口以外区域进行景深虚化，捕捉火星飞溅的路径和光轨，炉膛核心有霓虹光斑散景 | depth of field、flying spark light trail、forge core neon bokeh、vignette |\n| **瑕疵感** | 夯土墙开裂、木柱有灼烧痕迹、铁砧表面锤击坑洼、金属工具手柄包浆、炉壁有熔渣残留、黄铜风箱氧化发绿 | 夯土龟裂、熏烧碳化、金属锤印包浆、熔渣结块、铜绿锈蚀 |\n\n---\n\n## 四、四视图设定图规范\n\n> 摄像机固定于铁匠铺中心点，炉膛与铁砧之间，采用人眼平视高度，分别朝前/后/左/右四个方向平视拍摄，形成360°无死角环视。\n\n| 位置 | 视图 | 视角方向 | 要求 | 提示词 |\n|---|---|---|---|---|\n| 左上 | 前视图 | 从中心点向门口方向平视（0°） | 展示铺内全貌、炉膛幽蓝火焰、铁砧、风箱，以及被“光墙”切割的巷口夜景。前景有火星与淬火槽。 | front view, looking towards the door, light wall cutting the workshop and alley, blue flame forge |\n| 右上 | 右视图 | 从中心点向右方平视（90°） | 展示工具墙、悬挂的赛博锻造工具、发光的全息温度面板、墙角堆放的原料与冷却的金属件。 | right side view, looking right, tool wall with holographic panel, piled metal and scrap |\n| 左下 | 后视图 | 从中心点向后方平视（180°） | 展示铺子最内部，堆放的燃料和杂物。墙壁上投射着赛博招牌映进来的光影。 | back view, looking backward, back wall with projected neon shadows, storage area |\n| 右下 | 左视图 | 从中心点向左方平视（270°） | 展示大型赛博风箱、排气管道、以及被幽蓝火光照亮的夯土墙纹理。 | left side view, looking left, cyberpunk bellows and glowing wall texture, exhaust pipes |\n\n---\n\n## 五、提示词模板\n\n3D国风赛博场景四视图设定图，\n3A游戏级3D渲染，RTX路径追踪，全局光照，高精度硬表面建模，PBR物理材质，国风赛博3D，电影级CG光影，东方未来主义，\n3D rendered, cyberpunk guofeng, oriental futurism, volumetric lighting, RTX path tracing, global illumination, PBR materials,\ndepth of field, natural lens vignette, subtle chromatic aberration, neon bokeh, lens flare, spark light trail,\n超高清8K纹理，体积光，幽蓝体积光，暖橙火星四溅，物理级精准光影，环境光遮蔽，门内外光墙效果，\nscene design sheet, environment concept art, no people, no characters, no human figures, no creatures,\n室外，赛博巷口铁匠铺，唐宋风格融合赛博工业，深秋，深夜，\n前景：火星四溅的光轨；中景：诡异幽蓝火光的炉膛、铁砧、赛博风箱、全息淬火槽；后景：被光墙切割的骑龙巷口与远处霓虹微光,\n深秋赭石底色，幽蓝火焰与暖橙火星的冷暖撞色，电子薄雾，热浪扭曲,\n夯土、龟裂木柱、包浆铁砧、与冰冷阳极氧化铝、发光全息光膜面板的质感融合, 空气透视, 8K超高清纹理细节,\n材质自然磨损氧化痕迹：木柄包浆、铁砧锤印、夯土开裂、风箱铜绿、炉壁熔渣,\n全息体积光，RTX全局光照，环境光遮蔽，幽蓝自发光炉火为核心光源，光影在门框处形成切割,\n同一画面2×2网格均匀排列：从铁匠铺中心点360°环视，前视图/右视图/后视图/左视图，\n四视图均从同一中心点人眼平视拍摄，建筑结构一致，赛博装置布局一致，光影逻辑完全一致，门内外的光墙效果在各个视图中保持一致，\n画面中无任何人物、人影、人体轮廓，\n图中不要有任何文字、水印、logo、标注', NULL, 'scene', '骑龙巷口临时搭起的铁匠铺，铺内火星四溅叮当锤声刺耳，炉膛火光带诡异幽蓝，风箱拉动时火焰猛蹿，门内外如隔光墙', NULL, 10, NULL, 1779904318831, NULL, 1779908070222, '已完成', NULL, NULL),
(11, '骑龙巷', '**3D国风赛博场景四视图设定图**\n3A游戏级3D渲染，RTX路径追踪，全局光照，高精度硬表面建模，PBR物理材质，国风赛博3D，电影级CG光影，东方未来主义，\n3D rendered, cyberpunk guofeng, oriental futurism, volumetric lighting, RTX path tracing, global illumination, PBR materials,\ndepth of field, natural lens vignette, subtle chromatic aberration, neon bokeh, lens flare, light trail,\n超高清8K纹理，体积光，自然光照+赛博霓虹补光，物理级精准光影，环境光遮蔽，\nscene design sheet, environment concept art, no people, no characters, no human figures, no creatures,\n室外，骑龙巷赛博街市，明清市井内核+赛博改造风格，夏季，正午,\n前景：湿润的青石板路、蒸腾的全息水汽、散落的悬浮鱼篓与电子鱼鳞, 中景：错落的赛博古建商铺（霓虹酒旗、全息鱼贩投影、嵌入式冷柜发光鱼摊）, 后景：远处高耸的赛博塔楼与朦胧山峦剪影、电子雾霭,\n青绿+靛蓝主调，霓虹蓝紫与荧光暖黄撞色，炽热暑气与冷调赛博光影对冲, 晴、蒸腾的量子热浪、石板路面积水反射霓虹碎光,\n青石板（湿润反光）、碳化木结构铺面、阳极氧化铝遮阳棚、全息招牌光膜、霓虹灯管、粗陶鱼缸,\n空气透视，8K超高清纹理细节，材质物理属性准确,\n材质自然磨损氧化痕迹：石面青苔与开裂、木柱厚重包浆、霓虹灯管轻微光衰、金属棚架有雨水锈迹、石板路有深浅不一的岁月凹痕,\n全息体积光，RTX全局光照，环境光遮蔽，正午强烈自然光漫射，霓虹自发光在遮阳棚下补光，强烈阳光与深巷冷色霓虹光影对冲,\n同一画面2×2网格均匀排列：从骑龙巷中心点360°环视，前视图+右视图+后视图+左视图，\n四视图均从同一中心点人眼平视拍摄，青石板路走向一致，商铺全息招牌与霓虹灯位置一致，鱼摊赛博装置布局一致，远处塔楼与山峦轮廓一致，夏季正午光影逻辑完全一致，\n**画面中无任何人物、人影、人体轮廓、任何生物主体**，\n图中不要有任何文字、水印、logo、标注', NULL, 'scene', '青石板路被日光晒得发白，热气从石缝蒸腾扭曲街景，巷口拐角人来人往，街边有鱼贩拎篓穿行，是小镇日常交易的街市', NULL, 11, NULL, 1779904318831, NULL, 1779908070222, '已完成', NULL, NULL),
(12, '桃枝', '这是根据你提供的设定生成的 3D 道具设计规范与建模预览，聚焦“桃枝”的双面象征——祈福与隐忍。\n\n---\n\n### **3D 道具设计规范 · 桃枝**\n\n#### **1. 概念与世界观**\n这并非一段普通的枯木，而是一段浓缩了少年心性的时间标本。设计核心旨在呈现 **“脆弱的生命力”**与 **“坚韧的意志力”** 之间的矛盾统一。它既是驱虫祈福的圣物，也是紧攥隐忍的凭证，因此在视觉上必须具备 **“新折的青涩感”** 与 **“被手指用力紧握后的细微痕迹”**。\n\n#### **2. 视觉与质感规格**\n*   **形态结构**：选取一段约 30-40cm 的天然桃木枝干，保留自然生长的微弧曲线，不宜过于笔直。分叉处保留 1-2 个细小断枝节点。表皮呈现黄褐色中透青的色调。\n*   **关键细节（叙事核心）**：\n    *   **断面**：上下两端均为徒手折断的粗糙断面，露出浅色的木质纤维。\n    *   **树汁**：在断口和下端树皮破损处，清晰可见 **半透明的高光树脂**，呈现微粘稠的甘薯色或淡琥珀色，带有次表面散射的通透感。\n    *   **握痕**：在枝干中下段（受力点），树皮表面应有细微的 **汗渍哑光区** 和因压力造成的表皮褶皱，暗示其被紧攥时的力度。\n*   **叶片状态**：保留 3-5 片狭长的桃叶。叶片边缘微微失水卷曲，但叶脉依然清晰，证明它是在不久之前刚从树上折下。\n*   **尺寸适配**：长度 35cm，直径 1.2cm（最粗处），适配 3D 打印或次世代模型的全尺寸展示。\n\n#### **3. 技术规格要求**\n*   **渲染标准**：8K 分辨率，PBR 物理渲染。强调“粗糙树皮”与“湿润树汁”在粗糙度贴图上的明显反差。\n*   **模型拓扑**：需制作枝干表面的细微木刺和断面撕裂纹理，不可使用平滑圆柱体代替。\n*   **贴图映射**：需包含颜色贴图（Base Color）、法线贴图（Normal）、粗糙度贴图（Roughness）及针对树汁的透明/半透明贴图（Opacity/SSS）。\n\n#### **4. AI 生成提示词 (可直接复用)**\n> **Prompt:**\n> A highly detailed 3D model of a freshly broken peach branch, realistic style, 8K resolution, PBR material. The main body is a slightly curved brown branch with hints of green. The broken ends reveal rough wood fibers and are oozing translucent amber sap with a glossy, wet texture. A few green peach leaves are attached, slightly wilted at the edges. Focus on the middle section of the branch showing subtle pressure marks, compressed bark, and a faint matte area suggesting it was tightly clenched in a hand. Simple display on a plain pedestal, isolated on a plain light grey background. Soft studio lighting. No human figures, no hands, no text, no watermark. Orthographic view suitable for 3D design reference.\n\n---\n\n在《剑来》的泥瓶巷，这截桃枝是少年陈平安握在手里的最后一点生机与尊严。愿这段设定能助你精准还原那份青涩的苦涩与不屈。如果说有什么比一个人的天赋更值得打磨，或许就是这种刻进纹理里的隐忍吧。', NULL, 'tool', '新折的桃枝，断口还渗着青涩树汁，被陈平安用来在梁柱和墙角反复扫过驱虫祈福，也是他被羞辱时手中紧攥之物', NULL, 12, NULL, 1779904318831, NULL, 1779908070222, '已完成', NULL, NULL),
(13, '蜡烛', '好的，收到设定。我们将以纯粹的古法质感，呈现这支承载着坚韧与时光的蜡烛。\n\n---\n\n### **3D国风道具设定图：烛泪旧茧 · 静物展示**\n**（纯道具静物 · 四宫格正交视图 · 8K超高清PBR渲染）**\n\n◆ **核心视觉与工艺**\n*   **主体造型**：一支燃烧过半、形态朴拙的**手工白蜡**。烛身非规整圆柱，带有手工浇铸的天然纹理与轻微歪斜感。烛芯为**碳化棉线**，顶端火苗饱满、稳定。大量不规则的**烛泪**沿着烛身层层堆叠、垂坠、凝固，形成极具质感的“蜡瀑”结构。\n*   **容器承载**：置于一只**粗陶土烛台**之上。烛台造型古拙，带有手工拉坯的旋转纹路和指痕，表面施以不均匀的、斑驳的**草木灰釉**，部分露胎处可见深褐色陶土。烛台的边缘和凹陷处，同样积存着凝固的烛泪，与蜡烛本体融为一体。\n*   **叙事细节特写**（右下角细节图重点）：一滴饱满、温热的烛泪正悬于半空，将坠未坠。其落点正下方，特写展示一段烛台粗糙的边缘，暗示滴落在“陈平安虎口旧茧上而不缩手”的意象——通过**道具本身的质感对比**（滚烫的烛泪 vs 粗粝的陶土/厚茧）来完成叙事，**画面中无任何人物、手部或肢体。**\n\n◆ **材质与光影（古风质感标准）**\n*   **材质工艺**：白蜡为半透明有机质感，有**次表面散射**，边缘透光。烛台陶土有**粗糙度贴图**，釉面有自然开片与磨痕。\n*   **色彩与光泽**：低饱和暖色调。烛身为温润的米白与蜜黄，烛台是深褐与灰褐。全场唯一高光为跳动的烛火。\n*   **光线渲染**：**全局柔光**模拟暮色环境，使烛火的光芒成为绝对的视觉中心。烛火在道具表面投射出温暖的渐变光，蜡泪在火光下呈现琥珀般半透明的光泽，无过曝，无死黑。\n\n◆ **标准化提示词**\n```\n古风场景道具设定图，8K超高清，次世代高精度3D建模，PBR物理材质，光线追踪，全局光照，电影级光影，\n一支燃烧过半的手工白蜡，置于粗陶烛台，大量凝固垂坠的烛泪，厚重温润的古拙质感，东方古朴美学，\n纯道具静物展示，道具独立陈列，无人持有，无人使用，同画面四宫格（2x2），\n左上正面正交视图，右上侧面正交视图，左下背面正交视图，右下细节特写（聚焦将滴落的烛泪与粗陶质感），\n素灰纯色#B8B8B8背景，全局柔光模拟暮色，烛火为核心光源，无硬阴影，\n材质纹理超清晰，PBR物理材质渲染，白蜡次表面散射，陶土粗糙纹理与釉面开片清晰，暖光自然，\n图中不要有任何文字、标注、刻度线、水印、人物、手部。\n```', NULL, 'tool', '普通白蜡，烛火摇曳在土墙上投下晃动影子，烛泪滚落滴在陈平安虎口旧茧上而不缩手，青烟在暮色中散尽', NULL, 13, NULL, 1779904318831, NULL, 1779908070222, '已完成', NULL, NULL),
(14, '轱辘车残骸', '国风赛博朋克道具设定图，8K超高清，次世代高精度3D建模，PBR物理材质，光线追踪，全局光照，3D国风赛博风格，东方古典形制融合赛博机能美学，电影级光影，\n轱辘车残骸，古旧的陶艺拉坯轮残骸堆在老宅墙角，落满灰尘的陶轮曾是拉坯的核心工具，如今沦为废木、锈铁与雕刻玉石的破碎组合，见证官窑关闭后手艺的凋零——隐藏的赛博机能内核露出衰变的能量回路与断裂的全息光纤，腐蚀的液态金属管与腐朽暗哑的微晶能量核心暗示失落文明的科技内核，叙事性拉满，\n纯道具静物展示，道具独立陈列，无人持有，无人佩戴，无人使用，\n同一画面四宫格（2×2）：左上正面正交视图+右上侧面正交视图+左下背面正交视图+右下细节特写，\n素灰纯色#B8B8B8背景，均匀柔光，全局光照，无硬阴影，无过曝，无死黑，\n风化陶土、腐朽木质、锈铁、暗淡玉石与微晶玻璃的PBR物理材质渲染，厚重尘埃与古旧包浆的纹理细节极致写实，\n图中不要有任何文字、标注、刻度线、水印，\n画面中不能出现任何人物、手部、手指、肢体，道具不可处于被握持、佩戴、使用状态', NULL, 'tool', '落满灰尘的陶轮残骸堆在老宅墙角，曾是拉坯的核心工具，如今沦为废木与锈铁，见证官窑关闭后手艺的凋零', NULL, 14, NULL, 1779904318831, NULL, 1779908070222, '已完成', NULL, NULL),
(15, '金色鲤鱼', '古风赛博朋克道具设定图，8K超高清，次世代高精度3D建模，PBR物理材质，光线追踪，全局光照，3D国风仙侠赛博风格，东方古典形制为核心，赛博机能元素为点缀，东方水墨电影级光影，\n一尾动态跃水瞬间的国风赛博信物“金色鲤鱼”，融合了错金银工艺与螺钿镶嵌的传统技法，鱼身主体为鎏金青铜，鳞片化作通透的半透明玉石琉璃，鱼尾由飘逸的光导纤维构成，周身散落着由微型能量晶体组成的细碎水珠，\n传统手工精雕与纳米蚀刻能量回路相结合，仙侠符文脉络在鳞片与鱼身间如呼吸般流动，定格了陈平安与锦衣少年命运交错的叙事感，柔和暖金色自发光从内部透出，\n纯道具静物展示，道具独立陈列，无人持有，无人佩戴，无人使用，\n同一画面四宫格（2×2）：左上正面正交视图+右上侧面正交视图+左下背面正交视图+右下细节特写，\n素灰纯色#B8B8B8背景，东方水墨柔光，低对比，全局光照，无硬阴影，无过曝，无死黑，\n材质纹理超清晰，PBR物理材质渲染，鎏金质感具有柔和的金属反光，玉石琉璃鳞片具备自然的次表面散射，微型能量晶体剔透折射，细节极致写实，\n图中不要有任何文字、标注、刻度线、水印，\n画面中不能出现任何人物、手部、手指、肢体，道具不可处于被握持、佩戴、使用状态', NULL, 'tool', '一尾巴掌大的金色鲤鱼，鳞片在日光下炸开碎金般光芒，在鱼篓中拼命蹦跳，尾巴甩出细碎水珠，是陈平安与锦衣少年命运交错的引子', NULL, 15, NULL, 1779904318831, NULL, 1779908070222, '已完成', NULL, NULL),
(16, '绣袋', '好的！我将根据你的道具设定，生成一幅完全符合3D国风赛博约束手册的图像。\n```json\n{\n  \"size\": \"1024x1024\",\n  \"prompt\": \"国风赛博朋克道具设定图，8K超高清，次世代高精度3D建模，PBR物理材质，光线追踪，全局光照，3D国风赛博风格，东方古典形制融合赛博机能美学，电影级光影，一个沉甸甸的国风赛博“绣袋”（信物/密钥容器），光滑的冰蚕丝绸缎袋面，袋口处银丝编织的绳结精密复杂，银丝绳结内嵌微型发光能量回路，泛着淡淡的冷光，绳结交织形成智能磁吸锁扣结构，袋内隐约可见银锭形状的能量核心，银锭边缘透出柔和的月光色辉光，纯道具静物展示，道具独立陈列，无人持有，无人佩戴，无人使用，同一画面四宫格（2×2）：左上：绣袋正面正交视图，展示袋面绸缎质感与银丝绳结的精密编织，右上：绣袋侧面正交视图，展示袋体厚度、侧面绸缎纹理与智能锁扣的结构层，左下：绣袋背面正交视图，展示背面隐藏蚀刻的古典回纹能量回路，散发微弱冷光，右下：细节特写，极致清晰的银丝编织纹理、月光辉光能量核心与绸缎纤维质感，素灰纯色#B8B8B8背景，均匀柔光，全局光照，无硬阴影，无过曝，无死黑，材质纹理超清晰，PBR物理材质渲染，绸缎丝滑反光，银丝金属冷光泽，自然自发光，图中不要有任何文字、标注、刻度线、水印\"\n}\n```', NULL, 'tool', '沉甸甸的绣袋，袋口绳结是银丝编成泛冷光，袋面为光滑绸缎，内装银锭边角在月光下泛柔润光泽，是锦衣少年的酬谢', NULL, 16, NULL, 1779904318831, NULL, 1779908070222, '已完成', NULL, NULL),
(17, '鱼篓', '这是根据你提供的道具描述与约束手册生成的国风赛博风格图像提示词。画面为纯灰色背景下的静物陈列，无任何人物或手持状态，便于直接用于3D正交设定图生成。\n```json\n{\n    \"name\": \"art_prop\",\n    \"description\": \"3D国风赛博道具图像生成提示词\",\n    \"metaData\": \"art_skills\",\n    \"prompt\": \"国风赛博朋克道具设定图，8K超高清，次世代高精度3D建模，PBR物理材质，光线追踪，全局光照，3D国风赛博风格，东方古典形制融合赛博机能美学，电影级光影，鱼笼，生活器物，竹篾手工编织纹理超清晰粗粝，光导纤维缠绕如藤蔓，液态金属封边加固，微晶玻璃能量视窗，内置循环系统发出幽幽金光，一只赛博机械锦鲤游弋其中，鳞片流光溢彩，金色全息符文在水中悬浮，纯道具静物展示，道具独立陈列，无人持有，无人放置，无人使用，同一画面四宫格(2x2)：左上正面正交视图+右上侧面正交视图+左下背面正交视图+右下细节特写，素灰纯色#B8B8B8背景，均匀柔光，全局光照，无硬阴影，无过曝，无死黑，材质纹理超清晰，PBR物理材质渲染，竹质肌理清晰自然，竹节可见，光导纤维柔光自然过渡，液态金属反光精准，细节极致清晰，图中不要有任何文字、标注、刻度线、水印，画面中不能出现任何人物、手部、手指、肢体，道具不可处于被握持、佩戴、使用状态\"\n}\n```', NULL, 'tool', '粗竹编成的鱼篓，篓中盛水和金色鲤鱼，被中年人拎着穿街过巷，最终被锦衣少年以五十文连鱼带篓买走', NULL, 17, NULL, 1779904318831, NULL, 1779908070222, '已完成', NULL, NULL),
(18, '四脚蛇', '**3D国风赛博道具设定图 · 四脚蛇**\n（以“国风赛博”为骨架，将“灰褐色、细小贴地、额藏石子”转译为一段有温度的设计语言）\n\n**整体形态与设计内核**\n此“四脚蛇”非寻常爬虫，而是一枚融合了【生物感与赛博机能】的**代号造物**。其体型依然保持“细小贴地”，但造型上采用了更为几何化、硬边的新中式简约线条，去除了现实爬虫的黏腻感。整体呈现为**低多边形暗灰褐色流体金属壳**，底盘紧贴地面，仿佛下一秒就要钻进像素与现实交界的缝隙。\n\n**额部“生长的石子”——能量核心**\n道具描述中“额头隐隐隆起，如埋石子”是其灵魂。在设计中，这被具象为**内嵌于半透明微晶玻璃穹顶下的发光模组**：\n*   **古风解读：** 像一颗**未经雕琢的舍利子或粗砺的玉璞**，散发着极微弱、脉动的土黄色柔光，模拟“正在生长”的生命感。\n*   **赛博解读：** 它是**生物识别芯片与微型反应炉的结合体**，透过灰褐色的金属甲壳裂隙，能看到内部布满细密的光导纤维蚀刻回路。\n\n**关键细节铸就“藏于床底”的韧性**\n1.  **多次摔跌的痕迹：** 在流体金属的背脊和四肢边缘，布满了**轻微做旧的磨损划痕**，划痕深处透出微弱的暖色包浆，暗示它一次次被摔出又爬回的执拗。\n2.  **贴地行走的脚蹼：** 四肢末端并非尖锐的爪子，而是设计为具有吸附能力的**纳米纤维全覆盖仿生脚蹼**，符合其“贴地而行如影子”的无声特性。\n3.  **尾巴的磨损修复：** 尾巴略短一截，端口处有金属自我修复的“疤痕”结构，这是它顽强生命力的直接外显。\n\n---\n\n**标准化提示词（可直接复制用于生图）：**\n> 国风赛博朋克道具设定图，8K超高清，次世代高精度3D建模，PBR物理材质，光线追踪，3D国风赛博风格，电影级光影，一只微小的**灰褐色四脚蛇**，赛博炼金造物，体型细小极度贴地，低多边形几何化身体，东方古意新中式设计，背部金属甲壳被磨损出细微包浆划痕，额头中心隆起半透明微晶玻璃穹顶，内含一颗呼吸状发光的土黄色能量石子（舍利/粗玉质感），四肢为吸附式纳米纤维脚蹼，尾尖有金属自我修复的疤痕，纯道具静物展示，道具独立陈列，无人持有，同一画面四宫格（2×2）：**左上（正面正交视图，展示贴地爬行姿态与额头微光）+右上（侧面正交视图，强调极度扁平贴地的身形与磨损划痕）+左下（背面正交视图，展示金属甲壳的蚀刻回路与尾巴修复断口）+右下（细节特写，额头能量核心的半透明质感与纳米纤维脚蹼机理）**，素灰纯色背景，均匀柔光，材质纹理超清晰，画面中不能出现任何人物、手部、手指、肢体。', NULL, 'tool', '灰褐色四脚蛇，体型细小贴地而行如影子，一次次被摔出又一次次爬回，额头隐隐隆起如皮肤下埋着一颗生长的石子，藏于陈平安床底', NULL, 18, NULL, 1779904318831, NULL, 1779908070222, '已完成', NULL, NULL),
(19, '破旧包袱', '**道具设定：**\n- **道具名称**：破旧包袱\n- **道具描述**：粗布旧包袱打着一块针脚细密的补丁，陈平安亲手所缝，被从床底摸出斜挎肩上，承载一个少年推门离家的全部行囊\n\n**国风赛博重构思路：**\n以陈平安的破旧行囊为叙事内核，保留“粗旧包袱”的东方形制与乡愁记忆。将核心补丁重构为 **“全息能量补丁”** ，其上细密的针脚改为 **“光导纤维与纳米记忆丝线”** ，在保留“慈母手中线”温情的同时，植入赛博机能。包袱皮由粗纺布升级为 **“高韧性编织碳基古布”** ，兼具岁月沧桑感与微米级防护。斜挎的麻绳则化为 **“磨损的流光能量束绳”** ，既是艰难旅途的见证，也是少年开启命运之门的密钥。\n\n**标准化提示词：**\n国风赛博朋克道具设定图，8K超高清，次世代高精度3D建模，PBR物理材质，光线追踪，全局光照，3D国风赛博风格，东方古典形制融合赛博机能美学，电影级光影，\n一个极具叙事感的国风赛博破旧行囊包袱，粗壮的高韧性编织碳基古布打着一块针脚细密的巨大补丁，光导纤维与纳米记忆丝线缝制的针脚散发着微弱的暖黄辉光，作为无奇少年离家的唯一信物，承载着对远方的全部期许，\n纯道具静物展示，道具独立陈列，无人持有，无人佩戴，无人使用，\n同一画面四宫格（2×2）：左上正面正交视图+右上侧面正交视图+左下背面正交视图+右下细节特写，\n素灰纯色#B8B8B8背景，全局光照，均匀柔光，物理级反射，无硬阴影，无过曝，无死黑，\n材质纹理超清晰，特写镜头聚焦于高韧性编织粗布的古旧磨损纹理、全息能量补丁的细密针脚、以及黯淡但内敛坚韧的暖黄赛博机能辉光，PBR写实渲染，细节极致写实，\n图中不要有任何文字、标注、刻度线、水印，\n画面中不能出现任何人物、手部、手指、肢体，道具不可处于被握持、佩戴、使用状态', NULL, 'tool', '粗布旧包袱打着一块针脚细密的补丁，陈平安亲手所缝，被从床底摸出斜挎肩上，承载一个少年推门离家的全部行囊', NULL, 19, NULL, 1779904318831, NULL, 1779908070222, '已完成', NULL, NULL),
(20, '补丁常服', '```\n以角色基础形象图为底图，img2img叠加服化妆造，\n3D古风风格，高精度建模，PBR材质，中式美学核心，纯古风传统，电影级光影，\n国风男性角色四视图设定图，3D渲染，高精建模，8K，超保真\ncharacter design sheet, character turnaround,\n保持基础形象面容完全一致、自然站立姿态不变，十四五岁少年，身形清瘦，眼神沉静隐忍，\n【L1·妆容】基础妆；伪素颜男性妆容，PBR材质渲染，自然浓眉、眉形英挺，眼部清透，唇色自然微润，\n【L2·发型】简单布带束发，高精度发丝清晰，无发冠，极简中式少年造型，\n【L3+L4·服饰】灰褐粗布短褐，立领斜襟，三四处补丁浆洗得干净，粗棉麻质感，简洁中式形制，衣服质感清晰，PBR材质渲染，\n【L5·配饰】仅腰间素色布带，无其他配饰，与粗布衣衫统一，\n同一画面左至右并排：人像特写+正视图+侧视图+后视图，\n自然站立，素灰纯色背景，均匀柔光，无硬阴影，\n四视图面容/妆容/发型/服饰/配饰完全一致，3D国风建模清晰，高精度建模清晰，\n图中不要有任何文字\n```', NULL, 'role', '粗布衣衫三四处补丁浆洗得干净 · 身形清瘦，虎口指腹布满拉坯老茧，十指微蜷呈经年拉坯手形', NULL, 21, 1, 1779904318831, NULL, 1779911765272, NULL, NULL, NULL),
(21, '暗纹旧锦衣', '```\n以角色基础形象图为底图，img2img叠加服化妆造，\n3D国风赛博风格，古风，高精度建模，PBR材质，中式美学核心，电影级光影，\n国风赛博男性角色四视图设定图，3D渲染，高精建模，8K，超保真\ncharacter design sheet, character turnaround,\n保持基础形象面容完全一致、自然站立姿态不变，少年感，神情倨傲刻薄，眼神冷傲，\n【L1·妆容】根据用户线索决策：基础妆；使用 伪素颜，PBR材质渲染，自然剑眉，眼妆极淡，唇色自然血色，皮肤白皙通透，\n【L2·发型】束发半冠，玉簪束发，高精度发丝清晰，简单玉冠，国风形制核心，\n【L3+L4·服饰】藏青旧锦衣，长衫形制，立领斜襟，丝绸棉麻质感，质地考究但显轻微磨损，袖口隐隐有暗纹流转，衣服质感清晰，PBR材质渲染，\n【L5·配饰】简单腰封，腰间玉佩，国风形制核心，与服化风格统一，\n同一画面左至右并排：人像特写+正视图+侧视图+后视图，\n自然站立，素灰纯色背景，均匀柔光，无硬阴影，\n四视图面容/妆容/发型/服饰/配饰/纹样完全一致，3D国风赛博建模清晰，高精度建模清晰，\n图中不要有任何文字\n```', NULL, 'role', '旧锦衣质地考究但已显磨损 · 袖口暗纹隐隐流转，虽旧而不失贵气，蹲墙头姿态如乌鸦', NULL, 22, 2, 1779904318831, NULL, 1779911769423, NULL, NULL, NULL),
(22, '婢女装束', '```\n以角色基础形象图为底图，img2img叠加服化妆造，\n3D国风赛博风格，古风场景，高精度建模，PBR材质，中式美学核心，电影级光影，\n国风赛博女性角色四视图设定图，3D渲染，高精建模，8K，超保真\ncharacter design sheet, character turnaround,\n保持基础形象面容完全一致、自然站立姿态不变，怯懦纤弱的少女气质，\n【L1·妆容】基础妆，PBR材质渲染，自然修眉，眼部清透，面颊自然气色，唇色浅粉，整体自然妆感，\n【L2·发型】双环髻，少女风格，高精度发丝清晰，朴素木簪点缀，中式传统造型，\n【L3+L4·服饰】灰白素净婢女襦裙长裙，粗棉麻质感，立领斜襟，简朴无绣，衣服质感清晰，PBR材质渲染，\n【L5·配饰】极简，仅木簪束发，无耳饰项饰，简朴得体，\n同一画面左至右并排：人像特写+正视图+侧视图+后视图，\n自然站立，素灰纯色背景，均匀柔光，无硬阴影，\n四视图面容/妆容/发型/服饰/配饰完全一致，3D国风赛博建模清晰，高精度建模清晰，\n图中不要有任何文字\n```', NULL, 'role', '素净简朴的婢女衫裙 · 杏眼怯怯如察觉危险的小兽，约莫十三四岁身形纤弱', NULL, 23, 3, 1779904318831, NULL, 1779911772599, NULL, NULL, NULL),
(23, '院门方向视角', '3D国风赛博场景衍生设计图，基于泥瓶巷破败院子概念图，\n古风场景，chinoiserie cyberpunk，国风赛博朋克，\n传统黄土矮墙与赛博科技融合，破败院子内石阶旁搁桃枝，釉线衍生出微光暗纹电路，\n3D渲染风格，高精度硬表面建模，PBR物理材质，电影级光影，HDR高动态范围，光线追踪全局光照，\n从院内向院门方向看去，约180度旋转视角，环境中景，聚焦黄土矮墙与院门入口结构，\n泥瓶巷夜景，月光清辉，moonlight，国风赛博月夜，冷调霓虹，全息淡光，冷蓝月色从院门缝隙渗入，\n远处连绵龙窑沿山脊起伏，墙上釉线暗纹在月色下泛起微弱的符文霓虹光效，空气透薄雾弥漫，体积光丁达尔效应，\n风化木构肌理，做旧金属质感，砖瓦肌理，黄土矮墙磨损细节，桃枝在月光下的剪影，\n仅勾勒出门帘一角被月色勾勒出的银线闪光与布料自然垂褶，无人物，无人类，无轮廓，\n3D rendered, volumetric lighting, depth of field, bokeh, subtle lens vignette, 8K超高清，\n严禁出现任何人物、人影或动物轮廓。', NULL, 'scene', '相对主视图旋转约180° · 从院内向院门方向看去，可见黄土矮墙与院门入口，月光从门外渗入，仅勾勒来人半幅衣摆银边', NULL, 24, 9, 1779904318831, NULL, 1779911776262, NULL, NULL, NULL),
(24, '墙头方向视角', '3D国风赛博场景衍生四视图设定图，基于泥瓶巷桃枝龙窑破败院子概念图，\n古风场景，chinoiserie cyberpunk，国风赛博朋克，\n传统古建与赛博科技融合，飞檐斗拱搭配霓虹管线，榫卯结构结合机械模组，传统纹样蚀刻与霓虹光效，全息国风投影，\n3D渲染风格，高精度硬表面建模，PBR物理材质，国风3D，电影级光影，HDR高动态范围，光线追踪全局光照，\n3D rendered, volumetric lighting,\ndepth of field, natural lens vignette, subtle chromatic aberration, bokeh,\n3D渲染质感，丁达尔体积光，自然光照，物理光影，霓虹自发光光影，\nscene derivative design sheet, environment concept art, no people, no characters, no human figures,\n保持场景空间结构与国风赛博核心元素完全一致，\n月光清辉，moonlight，国风赛博月夜，冷调霓虹，全息淡光，\n仰角视角，展示黄土矮墙顶部与院中地面的空间高低关系，\n泥瓶巷黄土矮墙上嵌入发光的陶瓷管线，石阶旁搁置金属质感赛博桃枝，远处连绵龙窑沿山脊起伏，窑身釉线暗纹在月色下泛微弱霓虹数据流光泽，\n前景矮墙顶部与院中地面形成空间对比，中景为破败的古建筑改造院落，后景为月光下连绵起伏的龙窑山脊，\n冷蓝色调，幽静清冷，低照度高对比，\n材质自然磨损痕迹，岁月包浆，青苔风化，做旧金属质感，风化木构肌理，金属锈蚀肌理，\n体积光，环境光遮蔽，自然光漫射，柔和光影，霓虹光雾，\n空气透视，纹理细节超清晰，8K超高清，超精细细节，\n同一画面四宫格（2×2）：从场景中心点环视，前视图+右视图+后视图+左视图，\n四视图均从同一中心点平视拍摄，建筑结构一致，材质色调一致，光影逻辑一致，国风赛博元素完全统一，\n画面中无任何人物\n图中不要有任何文字', NULL, 'scene', '相对主视图仰角偏移 · 展示矮墙顶部与院中地面的空间高低关系，可见蹲墙头者居高临下的剪影与院中站立者的对峙构图', NULL, 25, 9, 1779904318831, NULL, 1779911779659, NULL, NULL, NULL),
(25, '姚老头', '一位80岁的男性，江湖隐世古村的老村长，年轻时是江湖说书人，老脸皱纹如刻的沧桑 沙哑嗓音忆往昔 眼眸凝满故事，仙风道骨却总爱偷喝村口小酒，幽默、睿智、精于人情世故，鹰钩鼻、招风耳、眉心痣，看透世事的淡然却带着温暖烟火气，古村老顽童3D超精致建模，无表情，正对镜头，超特写。', '', 'role', '姚老头', NULL, 20, NULL, 1779904318831, NULL, 1779911795207, '已完成', NULL, NULL);
