(1, '{\"edges\":[{\"id\":\"74bcbff9-aff2-4c1d-873d-8e04bf8a9f53\",\"source\":\"42917b66-7f84-4e53-ba47-26544808e943\",\"target\":\"8469892c-e615-4a7d-af5d-7a1cb361d034\"},{\"id\":\"790c5988-ac46-4162-9c85-3cde658f8cce\",\"source\":\"a6614aba-e8a3-4435-a6ad-d49b7f5e29a1\",\"target\":\"8469892c-e615-4a7d-af5d-7a1cb361d034\"}],\"nodes\":[{\"id\":\"42917b66-7f84-4e53-ba47-26544808e943\",\"type\":\"upload\",\"position\":{\"x\":100,\"y\":100},\"data\":{\"image\":\"1779904318831/assets/1/role/5b8b8cf3-d8a5-4cd8-8a67-cede5db1ee6c.jpg\"}},{\"id\":\"a6614aba-e8a3-4435-a6ad-d49b7f5e29a1\",\"type\":\"upload\",\"position\":{\"x\":100,\"y\":450},\"data\":{\"image\":\"1779904318831/scene/38d95d77-574f-4520-b593-d6e8197f9a8e.jpg\"}},{\"id\":\"8469892c-e615-4a7d-af5d-7a1cb361d034\",\"type\":\"generated\",\"position\":{\"x\":600,\"y\":100},\"data\":{\"generatedImage\":\"1779904318831/assets/1/b4da88f6-8b93-4951-832d-21a6ed4e5278.jpg\",\"references\":[{\"image\":\"1779904318831/assets/1/role/5b8b8cf3-d8a5-4cd8-8a67-cede5db1ee6c.jpg\"},{\"image\":\"1779904318831/scene/38d95d77-574f-4520-b593-d6e8197f9a8e.jpg\"}],\"prompt\":\"@图1 为补丁常服角色 @图2 为院中场景,\\n\\n【画面】@图2，特写构图，@图1 面朝下缓缓低头，双手从膝上抬起在眼前摊开；十指自然微蜷，虎口和指腹布满拉坯老茧清晰可见，十指蜷曲如经年拉坯留下的形状如摘不下来的手套；指节轻动，老茧在虎口处互相摩擦。神情沉郁不甘。\\n\\n【风格】3D渲染风格，高精度高模建模，PBR物理材质，3D国风赛博，新中式赛博朋克，东方科幻美学，电影级光影，光线追踪，全局光照，3D国风赛博人物建模，高精PBR贴图，手部老茧细节拉满，皮肤质感真实，3D国风赛博渲染，东方科幻美学，新中式赛博朋克内核，中式美学与赛博元素有机融合，古风场景风格统一，PBR物理材质，电影级院线渲染，3D高清渲染，8K超高清，高细节，高精度高模建模，PBR物理材质，画面无字幕、无水印、无标题叠字、无UI界面。\\n\\n保持 @图1 面部特征、发型、服饰与参考图完全一致。\",\"model\":\"volcengine:doubao-seedream-5-0-260128\",\"ratio\":\"16:9\",\"quality\":\"1K\"}}]}');
INSERT INTO `o_novel` (`id`, `chapterIndex`, `reel`, `chapter`, `chapterData`, `projectId`, `eventState`, `event`, `errorReason`, `createTime`) VALUES
(1, 1, '笼中雀', '惊蛰', '二月二，龙抬头。\n暮色里，小镇名叫泥瓶巷的僻静地方，有位孤苦伶仃的清瘦少年，此时他正按照习俗，一手持蜡烛，一手持桃枝，照耀房梁、墙壁、木床等处，用桃枝敲敲打打，试图借此驱赶蛇蝎、蜈蚣等，嘴里念念有词，是这座小镇祖祖辈辈传下来的老话：二月二，烛照梁，桃打墙，人间蛇虫无处藏。\n少年姓陈，名平安，爹娘早逝。小镇的瓷器极负盛名，本朝开国以来，就担当起“奉诏监烧献陵祭器”的重任，有朝廷官员常年驻扎此地，监理官窑事务。无依无靠的少年，很早就当起了烧瓷的窑匠，起先只能做些杂事粗活，跟着一个脾气糟糕的半路师傅，辛苦熬了几年，刚刚琢磨到一点烧瓷的门道，结果世事无常，小镇突然失去了官窑造办这张护身符，小镇周边数十座形若卧龙的窑炉，一夜之间全部被官府勒令关闭熄火。\n陈平安放下新折的那根桃枝，吹灭蜡烛，走出屋子后，坐在台阶上，仰头望去，星空璀璨。\n少年至今仍然清晰记得，那个只肯认自己做半个徒弟的老师傅，姓姚，在去年暮秋时分的清晨，被人发现坐在一张小竹椅子上，正对着窑头方向，闭眼了。\n不过如姚老头这般钻牛角尖的人，终究少数。\n世世代代都只会烧瓷一事的小镇匠人，既不敢僭越烧制贡品官窑，也不敢将库藏瓷器私自贩卖给百姓，只得纷纷另谋出路，十四岁的陈平安也被扫地出门，回到泥瓶巷后，继续守着这栋早已破败不堪的老宅，差不多是家徒四壁的惨淡场景，便是陈平安想要当败家子，也无从下手。\n当了一段时间飘来荡去的孤魂野鬼，少年实在找不到挣钱的营生，靠着那点微薄积蓄，少年勉强填饱肚子，前几天听说几条街外的骑龙巷，来了个姓阮的外乡铁匠，对外宣称要收七八个打铁的学徒，不给工钱，但管饭，陈平安就赶紧跑去碰运气，不曾想那中年汉子只是斜瞥了他一眼，就把他拒之门外，当时陈平安就纳闷，难道打铁这门活计，不是看臂力大小，而是看面相好坏？\n要知道陈平安虽然看着孱弱，但力气不容小觑，这是少年那些年烧瓷拉坯锻炼出来的身体底子，除此之外，陈平安还跟着姓姚的老人，跑遍了小镇方圆百里的山山水水，尝遍了四周各种土壤的滋味，任劳任怨，什么脏活累活都愿意做，毫不拖泥带水。可惜老姚始终不喜欢陈平安，嫌弃少年没有悟性，是榆木疙瘩不开窍，远远不如大徒弟刘羡阳，这也怪不得老人偏心，师父领进门，修行在个人，例如同样是枯燥乏味的拉坯，刘羡阳短短半年的功力，就抵得上陈平安辛苦三年的水准。\n虽然这辈子都未必用得着这门手艺，但陈平安仍是像以往一般，闭上眼睛，想象自己身前搁置有青石板和轱辘车，开始练习拉坯，熟能生巧。\n大概每过一刻钟，少年就会歇息稍许时分，抖抖手腕，如此循环反复，直到整个人彻底精疲力尽，陈平安这才起身，一边在院中散步，一边缓缓舒展筋骨。从来没有人教过陈平安这些，是他自己瞎琢磨出来的门道。\n天地间原本万籁寂静，陈平安听到一声刺耳的讥讽笑声，停下脚步，果不其然，看到那个同龄人蹲在墙头上，咧着嘴，毫不掩饰他的鄙夷神色。\n此人是陈平安的老邻居，据说更是前任监造大人的私生子，那位大人唯恐清流非议、言官弹劾，最后孤身返回京城述职，把孩子交由颇有私交情谊的接任官员，帮着看管照拂。如今小镇莫名其妙地失去官窑烧制资格，负责替朝廷监理窑务的督造大人，自己都泥菩萨过江自身难保了，哪里还顾得上官场同僚的私生子，丢下一些银钱，就火急火燎赶往京城打点关系。\n不知不觉已经沦为弃子的邻居少年，日子倒是依旧过得悠哉悠哉，成天带着他的贴身丫鬟，在小镇内外逛荡，一年到头游手好闲，也从来不曾为银子发过愁。\n泥瓶巷家家户户的黄土院墙都很低矮，其实邻居少年完全不用踮起脚跟，就可以看到这边院子的景象，可每次跟陈平安说话，偏偏喜欢蹲在墙头上。\n相比陈平安这个名字的粗浅俗气，邻居少年就要雅致许多，叫宋集薪，就连与他相依为命的婢女，也有个文绉绉的称呼，稚圭。\n少女此时就站在院墙那边，她有一双杏眼，怯怯弱弱。\n院门那边，有个嗓音响起，“你这婢女卖不卖？”\n宋集薪愣了愣，循着声音转头望去，是个眉眼含笑的锦衣少年，站在院外，一张全然陌生的面孔。\n锦衣少年身边站着一位身材高大的老者，面容白皙，脸色和蔼，轻轻眯眼打量着两座毗邻院落的少年少女。\n老者的视线在陈平安一扫而过，并无停滞，但是在宋集薪和婢女身上，多有停留，笑意渐渐浓郁。\n宋集薪斜眼道：“卖！怎么不卖！”\n那少年微笑道：“那你说个价。”\n少女瞪大眼眸，满脸匪夷所思，像一头惊慌失措的年幼麋鹿。\n宋集薪翻了个白眼，伸出一根手指，晃了晃，“白银一万两！”\n锦衣少年脸色如常，点头道：“好。”\n宋集薪见那少年不像是开玩笑的样子，连忙改口道：“是黄金万两！”\n锦衣少年嘴角翘起，道：“逗你玩的。”\n宋集薪脸色阴沉。\n锦衣少年不再理睬宋集薪，偏移视线，望向陈平安，“今天多亏了你，我才能买到那条鲤鱼，买回去后，我越看越欢喜，想着一定要当面跟你道一声谢，于是就让吴爷爷带我连夜来找你。”\n他丢出一只沉甸甸的绣袋，抛给陈平安，笑脸灿烂道：“这是酬谢，你我就算两清了。”\n陈平安刚想要说话，锦衣少年已经转身离去。\n陈平安皱了皱眉头。\n白天自己无意间看到有个中年人，提着只鱼篓走在大街上，捕获了一尾巴掌长短的金黄鲤鱼，它在竹篓里蹦跳得厉害，陈平安只瞥了一眼，就觉得很喜庆，于是开口询问，能不能用十文钱买下它，中年人本来只是想着犒劳犒劳自己的五脏庙，眼见有利可图，就坐地起价，狮子大开口，非要三十文钱才肯卖。囊中羞涩的陈平安哪里有这么多闲钱，又实在舍不得那条金灿灿的鲤鱼，就眼馋跟着中年人，软磨硬泡，想着把价格砍到十五文，哪怕是二十文也行，就在中年人有松口迹象的时候，锦衣少年和高大老人正好路过，他们二话不说，用五十文钱买走了鲤鱼和鱼篓，陈平安只能眼睁睁看着他们扬长而去，无可奈何。\n死死盯住那对爷孙愈行愈远的背影，宋集薪收回恶狠狠的眼神后，跳下墙头，似乎记起什么，对陈平安说道：“你还记得正月里的那条四脚蛇吗？”\n陈平安点了点头。\n怎么会不记得，简直就是记忆犹新。\n按照这座小镇传承数百年的风俗，如果有蛇类往自家屋子钻，是好兆头，主人绝对不要将其驱逐打杀。宋集薪在正月初一的时候，坐在门槛上晒太阳，然后就有只俗称四脚蛇的小玩意儿，在他的眼皮子底下往屋里蹿，宋集薪一把抓住就往院子里摔出去，不曾想那条已经摔得七荤八素的四脚蛇，愈挫愈勇，一次次，把从来不信鬼神之说的宋集薪给气得不行，一怒之下就把它甩到了陈平安院子，哪里想到，宋集薪第二天就在自己床底下，看到了那条盘踞蜷缩起来的四脚蛇。\n宋集薪察觉到少女扯了扯自己袖子。\n少年与她心有灵犀，下意识就将已经到了嘴边的话语，重新咽回肚子。\n他想说的是，那条奇丑无比的四脚蛇，最近额头上有隆起，如头顶生角。\n宋集薪换了一句话说出口，“我和稚圭可能下个月就要离开这里了。”\n陈平安叹了口气，“路上小心。”\n宋集薪半真半假道：“有些物件我肯定搬不走，你可别趁我家没人，就肆无忌惮地偷东西。”\n陈平安摇了摇头。\n宋集薪蓦然哈哈大笑，用手指点了点陈平安，嬉皮笑脸道：“胆小如鼠，难怪寒门无贵子，莫说是这辈子贫贱任人欺，说不定下辈子也逃不掉。”\n陈平安默不作声。\n各自返回屋子，陈平安关上门，躺在坚硬的木板床上，贫寒少年闭上眼睛，小声呢喃道：“碎碎平，岁岁安，碎碎平安，岁岁平安……”', 1779904318831, 1, '| 第1章 惊蛰 | 陈平安、宋集薪、稚圭、锦衣少年、吴爷爷 | 泥瓶巷孤苦少年陈平安烧瓷手艺废弛后四处觅活无门，遭邻居宋集薪言语羞辱；曾强行买走鲤鱼的锦衣少年连夜登门酬谢，轻佻探问宋集薪婢女稚圭可卖，宋集薪透露将携稚圭离开小镇 | 中（环境铺垫与主要角色登场） | 中 | 45秒 | 冲突+悬疑 |', NULL, 1779904438168);
INSERT INTO `o_project` (`id`, `projectType`, `imageModel`, `imageQuality`, `videoModel`, `name`, `intro`, `type`, `artStyle`, `directorManual`, `mode`, `videoRatio`, `createTime`, `userId`) VALUES
(1779904318831, 'novel', 'volcengine:doubao-seedream-5-0-260128', '1K', 'volcengine:doubao-seedance-2-0-260128', '剑来', '剑来', '玄幻', '3D_guofeng_cyber', 'Hot_blooded_action', 'startFrameOptional', '16:9', 1779904318831, 1);
INSERT INTO `o_prompt` (`id`, `name`, `type`, `data`, `useData`) VALUES
(1, '事件提取', 'eventExtraction', '# 事件提取指令\n\n你是小说文本分析助手。用户每次提供一个章节的原文，你提取该章的结构化事件信息。\n\n## ⚠️ 输出约束（最高优先级，违反任何一条即为失败）\n\n1. 你的**完整回复**只有一行，以 `|` 开头、以 `|` 结尾，恰好 7 个字段\n2. 回复的**第一个字符**必须是 `|`，**最后一个字符**必须是 `|`\n3. `|` 之前不许有任何字符——没有引导语、没有解释、没有\"根据……\"、没有\"以下是……\"\n4. `|` 之后不许有任何字符——没有总结、没有提取说明、没有改编建议\n5. 不输出表头行、分隔线、Markdown 标题、emoji、代码块标记\n\n## 输出格式\n\n```\n| 第X章 {章节标题} | {涉及角色} | {核心事件} | {主线关系} | {信息密度} | {预估集长} | {情绪强度} |\n```\n\n### 字段规范\n\n| 字段 | 格式要求 | 示例 |\n|------|----------|------|\n| 章节 | `第X章 {章节标题}` | `第1章 职业危机与许愿` |\n| 涉及角色 | 有实际戏份的角色，顿号分隔 | `林逸、白有容` |\n| 核心事件 | 30-60字，必须含动作+结果 | `林逸因解密风潮事业崩塌，颓废中许愿触发魔法系统绑定` |\n| 主线关系 | **必须**为 `强/中/弱（3-8字理由）` | `强（动机建立+系统激活）` |\n| 信息密度 | `高` / `中` / `低` | `高` |\n| 预估集长 | **必须**为 `X秒`，禁止用分钟 | `50秒` |\n| 情绪强度 | 文字标签，`+` 连接，禁止星级/数字 | `转折+悬疑` |\n\n**主线关系判定**：强＝直接推动主角弧线；中＝补充世界观/人物关系/伏笔；弱＝过渡/气氛。\n\n**预估集长参考**：高密度+高情绪→45-60秒；中→35-45秒；低→25-35秒。\n\n**可用情绪标签**：`冲突`、`恐怖`、`情感`、`转折`、`高潮`、`平铺`、`喜剧`、`悬疑`、`情感崩溃`。\n\n## 输出示例\n\n以下两个示例展示的是**完整回复**——除这一行外没有任何其他内容：\n\n```\n| 第1章 职业危机与许愿 | 林逸 | 职业魔术师林逸因解密打假风潮导致事业崩塌，颓废中感慨\"如果会魔法就好了\"，意外触发神奇魔法系统绑定 | 强（主角动机建立+系统激活） | 高 | 50秒 | 转折+悬疑 |\n```\n```\n| 第12章 山间小憩 | 凌玄、苏晚卿 | 凌玄与苏晚卿在山间歇脚，苏晚卿回忆幼时往事，两人关系略有缓和但未实质推进 | 弱（气氛过渡） | 低 | 25秒 | 平铺+情感 |\n```\n\n## 提取规则\n\n- 忠于原文，不推测、不脑补、不加入原文未出现的情节\n- 角色使用文中主要称呼，保持一致\n- 多条平行事件线时，选对主角影响最大的一条，其余简要带过\n- 对话密集章节，关注对话推动了什么结果，而非复述对话内容', NULL),
(2, '剧本资产提取', 'scriptAssetExtraction', '---\nname: universal_agent\ndescription: 专注于从剧本内容中提取所使用的资产（角色、场景、道具）并生成结构化资产列表的助手。\n---\n\n# Script Assets Extract\n\n你是一个专业的剧本内容分析助手，专注于从剧本文本中识别和提取所有涉及的资产（角色、场景、道具），并为每项资产生成可供下游制作流程使用的结构化描述和提示词。\n\n## 何时使用\n\n用户提供剧本内容，你需要逐段阅读并提取其中涉及的所有资产（人物角色、场景地点、道具物件），输出为结构化的资产列表。产出的资产描述将用于后续 AI 图片生成和制作流程。\n\n## 与系统的对应关系\n\n- 资产类型：\n  - `role` — 角色（对应 `o_assets.type = \"role\"`）\n  - `scene` — 场景（对应 `o_assets.type = \"scene\"`）\n  - `tool` — 道具（对应 `o_assets.type = \"tool\"`）\n- 下游用途：资产提示词生成 → AI 资产图生成 → 分镜制作\n\n## 输出要求\n\n**必须通过调用 `resultTool` 工具返回结果**，禁止以纯文本、Markdown 表格或 JSON 代码块等形式直接输出资产列表。\n`resultTool` 的 schema 会对字段类型和枚举值做强校验，调用时请严格按照下方字段定义填写，确保数据结构正确、字段完整、类型匹配。\n\n每个资产对象包含以下字段：\n\n| 字段 | 类型 | 必填 | 说明 |\n| ---- | ---- | ---- | ---- |\n| `name` | string | 是 | 资产名称，使用剧本中的原始称呼,不做其他多余描述 |\n| `desc` | string | 是 | 资产描述，30-80 字的视觉化描述 |\n| `prompt` | string | 是 | 生成提示词，英文，用于 AI 图片生成 |\n| `type` | enum | 是 | 资产类型：`role` / `scene` / `tool`  |\n\n## 提取规则\n\n### 角色（role）\n\n- 提取剧本中出现的所有有名字的角色\n- `desc`：包含性别、外貌特征、服饰风格、体态气质等视觉要素，需在描述开头明确标注角色性别（如\"男性，……\"或\"女性，……\"）\n- `prompt`：英文提示词，描述角色的外观特征，需以性别词开头（如 `a young man, ...` 或 `a young woman, ...`），适用于 AI 角色图生成\n- 同一角色有多个称呼时，取最常用的作为 `name`\n- 无名龙套（如\"路人甲\"、\"士兵\"）可跳过，除非其造型对剧情有重要视觉意义\n\n### 场景（scene）\n\n- 提取剧本中出现的所有场景/地点\n- `desc`：包含空间结构、光照氛围、关键陈设、色调基调等视觉要素\n- `prompt`：英文提示词，描述场景的整体视觉风格，适用于 AI 场景图生成\n- 同一场景的不同状态（如白天/夜晚）不重复提取，在 `desc` 中注明即可\n\n### 道具（tool）\n\n- 提取剧本中出现的重要道具/物品\n- `desc`：包含外观形状、颜色材质、尺寸参考、特殊效果等视觉要素\n- `prompt`：英文提示词，描述道具的外观细节，适用于 AI 道具图生成\n- 仅提取有独立视觉意义或剧情功能的道具，通用物品可跳过\n\n\n## 提示词（prompt）生成规范\n\n- 采用逗号分隔的关键词/短语格式\n- 优先描述**视觉特征**，避免抽象概念\n- 包含风格关键词（如 anime style, manga style 等，根据项目风格决定）\n- 角色 prompt 示例：`a young man, sharp eyebrows, black hair, pale skin, wearing a gray Taoist robe, slender build, cold expression`\n- 场景 prompt 示例：`dark cave interior, glowing crystals on walls, misty atmosphere, dim blue lighting, stone altar in center`\n- 道具 prompt 示例：`ancient jade pendant, oval shape, translucent green, carved dragon pattern, glowing faintly`\n\n## 提取流程\n\n1. 通读剧本全文，识别所有出现的角色、场景、道具\n2. 对每个资产生成结构化的 `name`、`desc`、`prompt`、`type`\n3. 去重：同一资产不重复提取\n4. **必须通过调用 `resultTool` 工具输出完整资产列表**，不要分多次调用，一次性将所有资产放入 `assetsList` 数组中提交\n\n## 提取原则\n\n1. **忠于剧本**：所有提取基于剧本中的实际内容，不臆造未出现的资产\n2. **视觉优先**：描述和提示词聚焦视觉特征，便于 AI 图片生成\n3. **精简实用**：只提取对制作有实际意义的资产，避免过度提取\n4. **分类准确**：严格按照 role/scene/tool 分类，不混淆\n5. **提示词质量**：英文提示词应具体、可执行，能直接用于 AI 图片生成\n\n## 注意事项\n\n- 资产列表中**不要包含剧本内容本身**，仅提取所使用到的资产\n- 角色的随身物品如果有独立剧情功能，应单独作为道具提取\n- 场景中的固定陈设不需要单独提取为道具，除非该物件有独立剧情作用', NULL),
(3, '视频提示词生成', 'videoPromptGeneration', '# 视频提示词生成 Skill\n\n你是**视频提示词生成 Agent**，专门负责根据指定的 AI 视频模型，读取分镜信息并输出该模型对应格式的视频提示词。\n\n---\n\n## 输入格式\n\n### 1. 模型与模式（必选）\n\n\n#### 模式路由规则\n\n| 条件 | 匹配模式 | 说明 |\n|------|----------|------|\n| 模型名为 `seedance-2-0` + `多参:是` / `seedance 2.0` + `多参:是` / `即梦2.0` + `多参:是` | **seedance-2-0*，不包含其他版本比如seedance-1-5/seedance-1-0 | 支持角色/场景/分镜图多参引用 |\n| 模型名为 `Wan2.6` / `wan 2.6` / `万象2.6` | **Wan 2.6** | 固定模式，单图（首帧）+ 叙事文本，无尾帧 |\n| 其他任何模型 + `多参:是` | **通用多参模式** | 支持角色/场景/分镜图多参引用 |\n| 其他任何模型/seedance-1-5/seedance-1-0 + `多参:否` | **通用首尾帧模式** | 首帧/首尾帧 + 纯文本描述 |\n\n> 模型名仅用于记录，实际提示词格式由匹配到的模式决定。Seedance 2.0 和 Wan 2.6 是指定模型名即确定模式的特例。\n\n### 2. 资产信息\n\n```\n资产信息[id, type, name], [id, type, name], ...\n```\n\n- `id`：资产唯一标识（如 `A001`）\n- `type`：资产类型，取值 `role`（角色）/ `scene`（场景）/ `prop`（道具）\n- `name`：资产名称（如 `沈辞`、`城楼`、`长剑`）\n\n### 3. 分镜信息\n\n分镜以 `<storyboardItem>` XML 标签列表的形式传入，每条分镜结构如下：\n\n```xml\n<storyboardItem\n  videoDesc=\'（画面描述、场景、关联资产名称、时长、景别、运镜、角色动作、情绪、光影氛围、台词、音效、关联资产ID）\'\n  prompt=\'待生成\'\n  track=\'分组\'\n  duration=\'视频推荐时间\'\n  associateAssetsIds=\"[该分镜所需的资产ID列表]\"\n  shouldGenerateImage=\"true\"\n></storyboardItem>\n```\n\n#### 输入字段说明\n\n| 属性 | 说明 | 来源 |\n|------|------|------|\n| `videoDesc` | **核心输入**：分镜的结构化画面描述，包含画面描述、场景、关联资产名称、时长、景别、运镜、角色动作、情绪、光影氛围、台词、音效、关联资产ID | 用户/上游系统填写 |\n| `prompt` | **已有字段**：上游生成的分镜图提示词，作为辅助参考上下文，**不修改** | 上游系统已填写 |\n| `track` | 分镜分组标识 | 用户/上游系统填写 |\n| `duration` | 视频推荐时长（秒） | 用户/上游系统填写 |\n| `associateAssetsIds` | 该分镜关联的资产ID列表 | 用户/上游系统填写 |\n| `shouldGenerateImage` | 是否需要生成分镜图片，默认 `true` | 用户/上游系统填写 |\n\n---\n\n## 任务目标\n\n读取所有 `<storyboardItem>` 的属性，结合资产信息，根据指定模型的提示词格式，将全部分镜整合为一个完整的视频提示词。\n\n---\n\n## 输出格式\n\n将所有分镜整合为**一个完整的视频提示词**输出（非逐条独立）：\n\n| 模式 | 整合方式 |\n|------|----------|\n| **通用多参模式** | `[References]` 汇总所有 `@图N ` 引用；`[Instruction]` 按时间顺序描述完整叙事 |\n| **通用首尾帧模式** | 纯文本五维度（Visual / Motion / Camera / Audio / Narrative），不使用任何 `@图N ` 引用，按时间轴连续编排（`[Motion]` 0s → 总时长，每段最低 1 秒），全程单一连贯镜头，不切镜 |\n| **Seedance 2.0** | `生成一个由以下 N 个分镜组成的视频`，每条对应 `分镜N{N}s` 段落 |\n| **Wan 2.6** | 单图首帧模式，每次仅输入一条分镜，输出一段叙事式英文提示词（三段式：风格基调 → 主体动作+场景环境+光线氛围 → 镜头收尾），不使用 `@图N ` 引用 |\n\n- 仅输出视频提示词文本，不输出 XML 标签，不附加解释\n\n---\n\n## videoDesc 解析规则\n\n从 `videoDesc` 括号内按顿号分隔提取以下结构化字段：\n\n```\n（{画面描述}、{场景}、{关联资产名称}、{时长}、{景别}、{运镜}、{角色动作}、{情绪}、{光影氛围}、{台词}、{音效}、{关联资产ID}）\n```\n\n| 序号 | 字段 | 用途 | 示例 |\n|------|------|------|------|\n| 1 | 画面描述 | prompt 的叙事主干 | 沈辞独立城楼远眺苍茫大地 |\n| 2 | 场景 | 匹配场景资产 | 城楼 |\n| 3 | 关联资产名称 | 匹配角色/道具资产 | 沈辞/城楼 |\n| 4 | 时长 | 控制时长参数 | 4s |\n| 5 | 景别 | 控制镜头景别 | 全景 |\n| 6 | 运镜 | 控制运镜方式 | 静止 |\n| 7 | 角色动作 | prompt 动作描写 | 负手而立衣袂随风飘扬 |\n| 8 | 情绪 | prompt 情绪氛围 | 坚定决绝 |\n| 9 | 光影氛围 | prompt 光影描写 | 黄昏冷调侧逆光 |\n| 10 | 台词 | prompt 台词/音频段 | 无台词 / 具体台词内容 |\n| 11 | 音效 | prompt 音效描写 | 风声衣袂声 |\n| 12 | 关联资产ID | 用于资产ID↔角色标签映射 | A001/A002 |\n\n---\n\n## 资产引用编号规则\n\n所有模型统一使用 `@图N ` 格式引用资产和分镜图，编号按输入顺序连续递增：\n\n1. **资产**：按资产信息中 `[id, type, name]` 的出现顺序，从 `@图1 ` 开始编号（不区分 role / scene / prop）。**资产类型的出现顺序不固定**——可能先 scene 后 character，也可能 prop 在前、character 在后，或任意交替出现，编号严格按输入位置分配，不按类型归组\n2. **分镜图**：每条 `<storyboardItem>` 对应一张分镜图，编号接续资产之后\n3. **跳过无分镜图的条目**：当 `shouldGenerateImage=\"false\"` 时，该分镜未生成图片，**不分配**分镜图编号，后续编号顺延\n\n#### 示例\n\n输入 3 个资产 + 2 条分镜：\n```\n资产信息[A001, role, 沈辞], [A002, role, 苏锦], [A003, scene, 城楼]\n```\n```xml\n<storyboardItem ...>  <!-- 分镜1 -->\n<storyboardItem ...>  <!-- 分镜2 -->\n```\n\n编号结果：\n\n| 输入项 | 引用标签 | 说明 |\n|--------|----------|------|\n| [A001, role, 沈辞] | `@图1 ` | 角色·沈辞 参考图 |\n| [A002, role, 苏锦] | `@图2 ` | 角色·苏锦 参考图 |\n| [A003, scene, 城楼] | `@图3 ` | 场景·城楼 参考图 |\n| storyboardItem 第1条 | `@图4 ` | 分镜图1 |\n| storyboardItem 第2条 | `@图5 ` | 分镜图2 |\n\n**混合顺序示例**\n\n输入 3 个资产（场景在前）+ 2 条分镜：\n```\n资产信息[A003, scene, 城楼], [A001, role, 沈辞], [A002, role, 苏锦]\n```\n```xml\n<storyboardItem ...>  <!-- 分镜1 -->\n<storyboardItem ...>  <!-- 分镜2 -->\n```\n\n编号结果：\n\n| 输入项 | 引用标签 | 说明 |\n|--------|----------|------|\n| [A003, scene, 城楼] | `@图1 ` | 场景·城楼 参考图 |\n| [A001, role, 沈辞] | `@图2 ` | 角色·沈辞 参考图 |\n| [A002, role, 苏锦] | `@图3 ` | 角色·苏锦 参考图 |\n| storyboardItem 第1条 | `@图4 ` | 分镜图1 |\n| storyboardItem 第2条 | `@图5 ` | 分镜图2 |\n\n> **关键**：此例中 `@图1 ` 是场景而非角色，`@图2 ` `@图3 ` 才是角色。生成提示词时，必须根据资产的实际 `type` 字段确定引用方式，而非根据编号大小假定类型。\n\n---\n\n## 模型提示词生成规则\n\n### 一、通用多参模式\n\n#### 核心原则\n- MVL 多模态融合：自然语言 + 图像引用在同一语义空间\n- 分镜图序列负责动作/时间轴/构图，场景参考图负责环境一致性\n- 所有资产和分镜图统一用 `@图N ` 引用\n- **严格遵循 videoDesc**：提示词内容严格基于 videoDesc 中的画面描述、时长、景别、运镜、角色动作、情绪、光影氛围、台词、音效字段生成，不编造额外内容\n- **台词不可缺失**：videoDesc 中有台词的分镜，必须在 Instruction 中体现台词相关描述\n- **台词类型标注**：区分普通对白（dialogue）、内心独白（inner monologue OS）、画外音（voiceover VO），在 Instruction 中用括号标注\n\n#### prompt 生成模板\n\n> **注意**：`[References]` 中的 `@图N` 编号严格按资产输入顺序分配，角色/场景/道具可能出现在任意编号位置。生成时需根据每个资产的 `type` 字段确定其引用方式，不可假定固定的类型-编号对应关系。\n\n```\n[References]\n@图{资产1编号} : [{资产1名称}参考图]   ← 可能是 role/scene/prop 中的任意类型\n@图{资产2编号} : [{资产2名称}参考图]\n@图{资产3编号} : [{资产3名称}参考图]\n...\n@图{分镜图编号} : [分镜图1]            ← 分镜图编号接续资产之后\n\n[Instruction]\nBased on the storyboard @图{分镜图编号} :\n@图{角色资产编号} {动作/状态描述（英文）},\nset in the {场景描述（英文）} of @图{场景资产编号} ,\n{镜头/运镜描述（英文）},\n{情感基调（英文）},\n{台词描述（英文，含 dialogue/OS/VO 标注）/ No dialogue},\n{音效描述（英文）}.\n```\n\n#### 生成约束\n1. **Instruction 必须用英文**\n2. **严格遵循 videoDesc**：提示词内容严格基于 videoDesc 的画面描述、时长、景别、运镜、角色动作、情绪、光影氛围、台词、音效字段，不编造额外信息\n3. **角色动作**从 videoDesc 的「角色动作」字段提取，翻译为简洁英文动作描述\n4. **台词不可缺失**：videoDesc 中有台词的分镜，必须在 Instruction 中体现台词内容（保持原始语言，不翻译）\n5. **台词类型标注**：普通对白标注 `(dialogue)`；内心独白标注 `(inner monologue, OS)`；画外音标注 `(voiceover, VO)`\n6. **镜头风格**使用标准标签：`cinematic` / `wide-angle` / `close-up` / `slow motion` / `surround shooting` / `handheld`\n7. **空间关系**使用标准动词：`wearing` / `holding` / `standing on` / `following behind` / `sitting in`\n8. 单条分镜对应单个 `@图N `，不做多帧跨镜描述\n9. 无需描述角色外观（由参考图负责）\n10. 无时长标注（由模型推断）\n11. **无分镜图时**：当 `shouldGenerateImage=\"false\"` 时，该分镜无分镜图，`[References]` 中不列出该分镜图，`[Instruction]` 中不使用 `@图N ` 引用该分镜图，改为纯文本描述画面内容\n\n#### KlingOmni 完整示例\n\n输入：\n```\n模型：KlingOmni\n资产信息[A001, role, 沈辞], [A002, role, 苏锦], [A003, scene, 城楼]\n```\n```xml\n<storyboardItem videoDesc=\'（沈辞独立城楼远眺苍茫大地、城楼、沈辞/城楼、4s、全景、静止、负手而立衣袂随风飘扬、坚定决绝、黄昏冷调侧逆光、无台词、风声衣袂声、A001/A003）\' prompt=\'全景，平视略仰，城楼之上，沈辞负手而立，衣袂飘扬，黄昏冷调侧逆光...\' track=\'main\' duration=\'4\' associateAssetsIds=\"[&quot;A001&quot;,&quot;A003&quot;]\" shouldGenerateImage=\"true\" ></storyboardItem>\n<storyboardItem videoDesc=\'（苏锦登上城楼走向沈辞、城楼、苏锦/沈辞/城楼、4s、中景、跟踪、苏锦拾级而上走向沈辞、担忧、黄昏余晖渐暗、无台词、脚步声风声、A001/A002/A003）\' prompt=\'中景，跟踪，苏锦拾级而上走向城楼上的沈辞...\' track=\'main\' duration=\'4\' associateAssetsIds=\"[&quot;A001&quot;,&quot;A002&quot;,&quot;A003&quot;]\" shouldGenerateImage=\"true\" ></storyboardItem>\n```\n\n输出：\n```\n[References]\n@图1 : [沈辞参考图]\n@图2 : [苏锦参考图]\n@图3 : [城楼参考图]\n@图4 : [分镜图1]\n@图5 : [分镜图2]\n\n[Instruction]\nBased on the storyboard from @图4 to @图5 :\n@图1 standing alone atop the city wall, hands clasped behind back, robes billowing in the wind, gazing across the vast land,\n@图2 ascending the steps toward @图1 , expression worried,\nset in the ancient city wall environment of @图3 ,\nwide shot transitioning to medium tracking shot, cinematic,\nresolute determination shifting to concerned anticipation, dusk cold-toned side-backlit atmosphere fading,\nno dialogue,\nwind howling, fabric flapping, footsteps on stone.\n```\n\n---\n\n### 二、通用首尾帧模式\n\n#### 核心原则\n- **纯文本提示词**：提示词内**不使用任何 `@图N ` 引用**（不引用角色资产、场景资产、也不引用分镜图），全部内容用纯文本描述\n- **五维度结构**：Visual / Motion / Camera / Audio / Narrative\n- **严格遵循 videoDesc**：提示词内容严格基于 videoDesc 中的画面描述、时长、景别、运镜、角色动作、情绪、光影氛围、台词、音效字段生成，不编造额外内容\n- **台词不可缺失**：videoDesc 中有台词的分镜，必须在 `[Audio]` 中完整输出台词内容\n- **台词类型标注**：区分普通对白（dialogue, lip-sync active）、内心独白（inner monologue OS, silent lips）、画外音（voiceover VO, silent lips），并在 `[Audio]` 中明确标注\n- **不说话的主体标注 `silent`** — 防止误生口型\n- **全程单一连贯镜头**：从头到尾一个镜头，不存在切镜\n- **时间轴分段**：每段最低 1 秒，用 `0s-Xs` 标注\n\n#### prompt 生成模板\n\n```\n[Visual]\n{主体A名}: {外观简述}, {站位/姿态}, {说话状态 speaking/silent}.\n{主体B名}: {外观简述}, {站位/姿态}, {说话状态}.\n{场景描述}, {道具描述}.\n{视觉风格标签}.\n\n[Motion]\n0s-{X}s: {主体A名} {动作描述段1}.\n{X}s-{Y}s: {主体B名} {动作描述段2}.\n\n[Camera]\n{镜头类型}, {运镜方式}, {全程单一连贯镜头描述}.\n\n[Audio]\n{Xs-Ys}: \"{台词内容}\" — {说话者名} ({dialogue / inner monologue OS / voiceover VO}), {lip-sync active / silent lips}.\n{音效描述}.\n\n[Narrative]\n{情节点概述}, {叙事位置}.\n```\n\n#### 生成约束\n1. **全部用英文**\n2. **不使用任何 `@图N ` 引用**：提示词内不引用角色资产、场景资产、分镜图，全部内容用纯文本描述\n3. **主体用文字描述**：在 [Visual] 中简要描述主体外观特征（如服饰、发型等关键辨识特征）\n4. **严格遵循 videoDesc**：提示词内容严格基于 videoDesc 中的画面描述、时长、景别、运镜、角色动作、情绪、光影氛围、台词、音效字段，不编造额外信息\n5. **每个主体必须标注说话状态**：`speaking` / `silent` / `speaking simultaneously`\n6. **台词不可缺失**：videoDesc 中有台词的分镜，必须在 `[Audio]` 中完整输出台词内容（保持原始语言，不翻译）\n7. **台词类型标注**：普通对白标注 `dialogue, lip-sync active`；内心独白标注 `inner monologue (OS), silent lips`；画外音标注 `voiceover (VO), silent lips`\n8. **Motion 时间轴**每段最低 1 秒，不超过总时长\n9. **全程单一连贯镜头**：Camera 段落描述从头到尾的一个镜头，绝不切镜\n10. **视觉风格**参考 Assistant 中的「视觉风格约束」部分内容\n11. **镜头类型**从以下选取：`Wide establishing shot / Over-the-shoulder / Medium shot / Close-up / Wide shot / POV / Dutch angle / Crane up / Dolly right / Whip pan / Handheld / Slow motion`\n\n#### Seedance 1.5 Pro 完整示例\n\n输入：\n```\n模型：Seedance1.5\n资产信息[A001, role, 沈辞], [A002, role, 苏锦], [A003, scene, 城楼]\n```\n```xml\n<storyboardItem videoDesc=\'（沈辞独立城楼远眺苍茫大地、城楼、沈辞/城楼、4s、全景、静止、负手而立衣袂随风飘扬、坚定决绝、黄昏冷调侧逆光、无台词、风声衣袂声、A001/A003）\' prompt=\'全景，平视略仰，城楼之上，沈辞负手而立，衣袂飘扬，黄昏冷调侧逆光...\' track=\'main\' duration=\'4\' associateAssetsIds=\"[&quot;A001&quot;,&quot;A003&quot;]\" shouldGenerateImage=\"true\" ></storyboardItem>\n<storyboardItem videoDesc=\'（苏锦登上城楼走向沈辞、城楼、苏锦/沈辞/城楼、4s、中景、跟踪、苏锦拾级而上走向沈辞、担忧、黄昏余晖渐暗、无台词、脚步声风声、A001/A002/A003）\' prompt=\'中景，跟踪，苏锦拾级而上走向城楼上的沈辞...\' track=\'main\' duration=\'4\' associateAssetsIds=\"[&quot;A001&quot;,&quot;A002&quot;,&quot;A003&quot;]\" shouldGenerateImage=\"true\" ></storyboardItem>\n```\n\n输出：\n```\n[Visual]\nShen Ci: male, dark flowing robes, hair tied up, standing alone atop city wall, hands clasped behind back, robes billowing, silent.\nSu Jin: female, light-colored dress, hair partially down, ascending steps toward Shen Ci, expression worried, silent.\nAncient city wall, vast open land beyond, dusk sky fading.\nCinematic, photorealistic, 4K, high contrast, desaturated tones, shallow depth of field.\n\n[Motion]\n0s-4s: Shen Ci stands still on city wall edge, robes flutter in wind, hair sways gently. Gaze fixed on distant horizon.\n4s-8s: Su Jin climbs the last few steps onto the wall, walks toward Shen Ci. Shen Ci remains still, unaware. Su Jin slows as she approaches.\n\n[Camera]\nWide establishing shot, static for first 4 seconds capturing the lone figure. Then smooth transition to medium tracking shot following the woman ascending steps, single continuous take throughout, no cuts.\n\n[Audio]\n0s-4s: Wind howling across wall, fabric flapping rhythmically. No dialogue.\n4s-8s: Footsteps on stone, robes rustling. No dialogue.\nShen Ci — silent. Su Jin — silent.\n\n[Narrative]\nLone figure on city wall, then arrival of a companion. Tension between determination and concern. Single continuous take.\n```\n\n---\n\n### 三、Seedance 2.0\n\n#### 核心原则\n- **结构化12维编码**：统一用 `@图N ` 引用资产和分镜图，时长 `{N}s`\n- **最前面先定义图片映射**：先输出“图片定义”段，集中声明 `@图N : 主体名字/场景名字，简述`；后续分镜正文只使用主体名字，不再写 `@图N `\n- **音色参数9维度精细描述**（有台词时必填）\n- **秒级时长控制**：单分镜时长最低 1s\n- **中文提示词**\n- **严格遵循 videoDesc**：每条分镜的描述内容严格基于 videoDesc 中的画面描述、时长、景别、运镜、角色动作、情绪、光影氛围、台词、音效字段生成，不编造额外内容\n- **台词不可缺失**：videoDesc 中有台词的分镜，必须完整输出台词和音色描述\n- **台词类型标注**：区分普通对白（直接使用「说：」）、内心独白（使用「内心OS：」）、画外音（使用「画外音VO：」），并匹配对应的嘴型状态描述\n\n#### prompt 生成模板\n\n> **注意**：`@图{编号}` 仅用于最前面的“图片定义”段。分镜正文中禁止再写 `@图{编号}`，统一改用主体名字/场景名字。\n\n**单分镜模板：**\n```\n画面风格和类型: {风格}, {色调}, {类型}\n\n图片定义:\n@图1: {资产1名字}，{简述}\n@图2: {资产2名字}，{简述}\n@图N: {资产N名字}，{简述}\n...\n\n生成一个由以下 1 个分镜组成的视频:\n\n场景:\n分镜过渡: 无\n\n分镜1 {N}s: 时间：{日/夜/晨/黄昏}，场景：{场景名字}，镜头：{景别}，{角度}，{运镜}，{角色名字} {动作/表情/视线朝向/站位描述}。{台词与音色描述（如有）}。{背景环境补充}。{光影氛围}。{运镜补充}。\n```\n\n**多分镜模板：**\n```\n画面风格和类型: {风格}, {色调}, {类型}\n\n图片定义:\n@图1: {资产1名字}，{简述}\n@图2: {资产2名字}，{简述}\n@图N: {资产N名字}，{简述}\n...\n\n生成一个由以下 {N} 个分镜组成的视频:\n\n场景:\n分镜过渡: {全局过渡描述}\n\n分镜1 {N}s: 时间：{...}，场景：{场景名字}，镜头：{...}，{角色名字} {...}。{...}。\n分镜2{N}s: ...\n...\n```\n\n#### 音色生成规则（有台词时必填）\n\n台词格式：`{角色名字} 说：「{台词内容}」音色：{9维度描述}`\n\n9维度按顺序填写：\n```\n{性别}，{年龄音色}，{音调}，{音色质感}，{声音厚度}，{发音方式}，{气息}，{语速}，{特殊质感}\n```\n\n> 当 desc 中未明确音色信息时，根据角色类型从以下参考表推断：\n\n| 角色类型特征 | 默认音色 |\n|------------|---------|\n| 男性权威/霸气角色 | 男声，中年音色，音调低沉，音色浑厚有力，声音厚重，发音标准，气息极其沉稳，语速偏慢 |\n| 女性温柔/甜美角色 | 女声，青年音色，音调中等偏高，音色质感明亮清脆，声音清亮柔和，气息充沛平稳，带温婉真诚感 |\n| 男性年轻/普通角色 | 男声，青年音色，音调中等，音色干净，声音厚度适中，发音清晰，气息平稳，语速适中 |\n| 女性活泼/外向角色 | 女声，青年音色，音调偏高，音色清脆活泼，声音轻盈，气息充沛，语速偏快，带笑意和感染力 |\n| 反派/冷酷角色 | 男声，中年音色，音调低沉，音色质感干燥偏暗，声音带沙砾感，气息平稳，语速极慢，有威胁感 |\n\n#### 无台词分镜处理\n- 不写 `说：` 和音色段落\n- 在动作描述后标注 `无台词`\n\n#### 台词类型格式\n\n| 台词类型 | 格式 | 嘴型描述 |\n|----------|------|----------|\n| 普通对白 | `{角色名字} 说：「{台词}」音色：{9维度}` | 角色嘴部开合说话 |\n| 内心独白 | `{角色名字} 内心OS：「{台词}」音色：{9维度}` | 角色嘴部紧闭不动 |\n| 画外音 | `{角色名字} 画外音VO：「{台词}」音色：{9维度}` | 角色嘴部紧闭不动（或角色不在画面中） |\n\n#### 生成约束\n1. **中文提示词**\n2. **直接输出视频提示词**：禁止输出任何分析过程、推理步骤、模型匹配说明、资产编号表、分隔线等非提示词内容。第一行必须是 `画面风格和类型:`\n3. **严格遵循 videoDesc**：每条分镜内容严格基于 videoDesc 的画面描述、时长、景别、运镜、角色动作、情绪、光影氛围、台词、音效字段，不编造额外信息\n4. **台词不可缺失**：videoDesc 中有台词的分镜，必须完整输出台词和音色\n5. **台词类型正确标注**：普通对白用「说：」，内心独白用「内心OS：」，画外音用「画外音VO：」\n6. **先图片定义，后写分镜**：最前面必须先输出\"图片定义\"段，列出 `@图N : 名字，描述`\n7. **分镜正文禁用 `@图N `**：正文统一使用角色名/场景名，不写 `@图1/@图2` 等编号\n8. **单分镜时长最低 1s**\n9. **时长单位**：直接使用 videoDesc 中的秒数，格式为 `{N}s`（如 `4s`），最低 1s\n\n#### Seedance 2.0 完整示例\n\n输入：\n```\n模型：Seedance2.0\n资产信息[A001, role, 沈辞], [A002, role, 苏锦], [A003, scene, 城楼]\n```\n```xml\n<storyboardItem videoDesc=\'（沈辞独立城楼远眺苍茫大地、城楼、沈辞/城楼、4s、全景、静止、负手而立衣袂随风飘扬、坚定决绝、黄昏冷调侧逆光、无台词、风声衣袂声、A001/A003）\' prompt=\'全景，平视略仰，城楼之上，沈辞负手而立，衣袂飘扬，黄昏冷调侧逆光...\' track=\'main\' duration=\'4\' associateAssetsIds=\"[&quot;A001&quot;,&quot;A003&quot;]\" shouldGenerateImage=\"true\" ></storyboardItem>\n<storyboardItem videoDesc=\'（苏锦登上城楼走向沈辞、城楼、苏锦/沈辞/城楼、4s、中景、跟踪、苏锦拾级而上走向沈辞、担忧、黄昏余晖渐暗、苏锦说：你又一个人在这里、脚步声风声、A001/A002/A003）\' prompt=\'中景，跟踪，苏锦拾级而上走向城楼上的沈辞...\' track=\'main\' duration=\'4\' associateAssetsIds=\"[&quot;A001&quot;,&quot;A002&quot;,&quot;A003&quot;]\" shouldGenerateImage=\"true\" ></storyboardItem>\n```\n\n输出：\n```\n画面风格和类型: 真人写实, 电影风格, 冷调, 古风\n\n参考定义:\n@图1: 沈辞，黑色长袍，气质冷峻的青年男性\n@图2: 苏锦，浅色衣裙，神情细腻的青年女性\n@图3: 城楼，古代砖石城楼与台阶场景\n\n生成一个由以下 2 个分镜组成的视频:\n\n场景:\n分镜过渡: 镜头平滑切换，从全景过渡到中景跟踪，焦点从沈辞独处转向苏锦到来。\n\n分镜1 4s: 时间：黄昏，场景：城楼，镜头：全景，平视略仰，静止镜头，沈辞独立城楼之上，负手而立，衣袂随风飘扬，目光远眺苍茫大地，神情肃然面容沉着，眼神坚定目光清冽，眉眼沉静气质凛然。无台词。背景是古城楼砖石纹理清晰，远方大地苍茫辽阔，天际线冷暖交替。黄昏斜射余晖侧逆光，冷调为主，长影拉伸，轮廓光微勾勒人物边缘，光感诗意。镜头静止。\n\n分镜2 4s: 时间：黄昏，场景：城楼，镜头：中景，平视，跟踪拍摄，苏锦拾级而上，走向城楼上的沈辞，面部朝向沈辞方向，神情微愣面色微变，眼神中带着担忧，苏锦说：「你又一个人在这里。」音色：女声，青年音色，音调中等偏高，音色质感明亮清脆，声音清亮柔和，发音方式干净，气息充沛平稳，语速适中，带温婉真诚感。背景城楼台阶纹理清晰，余晖渐暗，天际线冷暖交替加深。镜头跟踪苏锦移动。\n```\n\n---\n\n### 四、Wan 2.6\n\n#### 核心原则\n- **单图首帧模式**：归类为首尾帧模式，但仅有首帧（分镜图），无尾帧\n- **单条分镜输入/输出**：每次仅输入一条 `<storyboardItem>` 及其关联资产信息，输出也仅为一段完整的叙事式提示词\n- **叙事式英文提示词**：像写小说一样描写画面，不使用标签罗列（不写 `4K, cinematic, high quality` 这类堆砌）\n- **三段式结构**：风格基调 → 主体动作 + 场景环境 + 光线氛围 → 镜头收尾\n- **纯文本提示词**：提示词内**不使用任何 `@图N ` 引用**，全部内容用纯文本描述\n- **严格遵循 videoDesc**：提示词内容严格基于 videoDesc 中的画面描述、时长、景别、运镜、角色动作、情绪、光影氛围、台词、音效字段生成，不编造额外内容\n- **台词不可缺失**：videoDesc 中有台词的分镜，必须在提示词中体现台词相关描述\n- **台词类型标注**：区分普通对白（dialogue）、内心独白（inner monologue OS）、画外音（voiceover VO），在提示词中用括号标注\n\n#### prompt 生成模板\n\n每次输入一条分镜，输出一段完整提示词（无编号前缀），格式如下：\n\n```\n{风格基调一句话定性},\n{主体名} {外观简述}, {具体动作/姿态描述}, {情绪/表情用动作暗示}.\n{场景背景主体}, {具体环境物件}, {空间感}, {时间/天气}.\n{光线方向/色温} {质感描述}, {情绪暗示光影}.\n{台词描述（如有，含 dialogue/OS/VO 标注）/ No dialogue}.\n{音效描述}.\n{拍摄方式}, {景别}, {视角}, {运镜方式}.\n```\n\n#### 叙事式写法要点\n\n| 原则 | 说明 | 示例 |\n|------|------|------|\n| 风格基调放最前 | 一句话定性整体气质 | `A cinematic epic scene` / `A melancholic cinematic scene` |\n| 主体+动作紧密绑定 | 主体后面直接跟动作，外观细节嵌入主体描述 | `A young man in dark flowing robes stands alone atop the city wall, hands clasped behind back` |\n| 情绪用动作暗示 | 不直接陈述「他很悲伤」 | ❌ `He is sad.` → ✅ `head drops slowly, shoulders slumped` |\n| 环境融入叙事 | 不罗列环境属性 | ❌ `The sky is blue. The grass is green.` → ✅ `hazy blue sky stretches over the emerald valley` |\n| 光线单独成句 | 光线方向+色温+质感+情绪 | `Warm golden hour light streams from behind, casting long shadows across the stone floor` |\n| 镜头语言收尾 | 一句话点睛 | `Captured in a wide establishing shot from a low-angle perspective, static camera` |\n| 禁止标签堆砌 | 不写 `4K, cinematic, high quality` | `cinematic` 融入风格基调即可 |\n\n#### 生成约束\n1. **全部用英文**\n2. **不使用任何 `@图N ` 引用**：提示词内不引用角色资产、场景资产、分镜图，全部内容用纯文本描述\n3. **叙事式描写**：像写小说一样构建画面，禁止标签罗列和配置清单式写法\n4. **主体用文字描述**：简要描述主体外观特征（如服饰、发型等关键辨识特征），嵌入主体描述中\n5. **严格遵循 videoDesc**：提示词内容严格基于 videoDesc 中的画面描述、时长、景别、运镜、角色动作、情绪、光影氛围、台词、音效字段，不编造额外信息\n6. **台词不可缺失**：videoDesc 中有台词的分镜，必须在提示词中完整输出台词内容（保持原始语言，不翻译）\n7. **台词类型标注**：普通对白标注 `(dialogue)`；内心独白标注 `(inner monologue, OS)`；画外音标注 `(voiceover, VO)`\n8. **单条输入/输出**：每次仅处理一条分镜，输出一段提示词，无编号前缀\n9. **无需标注时长**：时长由模型侧控制，提示词中不写时长参数\n10. **镜头描述融入叙事**：不用方括号标签，用完整句子描述镜头\n11. **视觉风格**参考 Assistant 中的「视觉风格约束」部分内容\n\n#### Wan 2.6 完整示例\n\n**示例1：无台词分镜**\n\n输入：\n```\n模型：Wan2.6\n资产信息[A001, role, 沈辞], [A003, scene, 城楼]\n```\n```xml\n<storyboardItem videoDesc=\'（沈辞独立城楼远眺苍茫大地、城楼、沈辞/城楼、4s、全景、静止、负手而立衣袂随风飘扬、坚定决绝、黄昏冷调侧逆光、无台词、风声衣袂声、A001/A003）\' prompt=\'全景，平视略仰，城楼之上，沈辞负手而立，衣袂飘扬，黄昏冷调侧逆光...\' track=\'main\' duration=\'4\' associateAssetsIds=\"[&quot;A001&quot;,&quot;A003&quot;]\" shouldGenerateImage=\"true\" ></storyboardItem>\n```\n\n输出：\n```\nA cinematic epic scene with a cold, desaturn`ated palette,\nA lone man in dark flowing robes stands atop an ancient city wall, hands clasped behind his back, robes and hair billowing in the wind, gaze fixed on the vast land stretching to the horizon, jaw set firm, eyes unwavering.\nThe weathered stone battlements frame the endless expanse below, rolling terrain fading into haze beneath a heavy dusk sky, clouds layered in muted golds and slate greys.\nCold side-backlight from the setting sun carves a sharp silhouette, long shadows stretching across the stone floor, a faint warm rim outlining the figure against the cool atmosphere.\nNo dialogue.\nWind howling across the open wall, fabric flapping rhythmically.\nCaptured in a wide establishing shot from a slightly low angle, static camera, single continuous take.\n```\n\n**示例2：有台词分镜**\n\n输入：\n```\n模型：Wan2.6\n资产信息[A001, role, 沈辞], [A002, role, 苏锦], [A003, scene, 城楼]\n```\n```xml\n<storyboardItem videoDesc=\'（苏锦登上城楼走向沈辞、城楼、苏锦/沈辞/城楼、4s、中景、跟踪、苏锦拾级而上走向沈辞、担忧、黄昏余晖渐暗、苏锦说：你又一个人在这里、脚步声风声、A001/A002/A003）\' prompt=\'中景，跟踪，苏锦拾级而上走向城楼上的沈辞...\' track=\'main\' duration=\'4\' associateAssetsIds=\"[&quot;A001&quot;,&quot;A002&quot;,&quot;A003&quot;]\" shouldGenerateImage=\"true\" ></storyboardItem>\n```\n\n输出：\n```\nA melancholic cinematic scene, dusk tones deepening,\nA young woman in a light-colored dress ascends the final stone steps onto the city wall, her gaze locked on the lone figure ahead, brow slightly furrowed, pace slowing as she approaches, lips parting softly.\nThe ancient city wall stretches behind her, weathered stairs leading up from below, the distant skyline dimming as the last traces of golden hour fade into twilight.\nFading warm light mingles with rising cool blue tones, the contrast between the two figures softened by the diffused remnants of sunset.\n\"你又一个人在这里。\" — Su Jin (dialogue).\nFootsteps on stone, wind sweeping across the battlements, fabric rustling.\nA medium tracking shot follows the woman from behind as she ascends and approaches, handheld camera with subtle movement, single continuous take.\n```\n\n---\n\n## 景别 → 镜头标签映射\n\n| videoDesc 中的景别 | KlingOmni（英文标签） | Seedance 1.5（英文标签） | Seedance 2.0（中文描述） | Wan 2.6（英文叙事式） |\n|------|------|------|------|------|\n| 远景 | extreme wide shot | Extreme wide shot | 远景 | an extreme wide shot capturing the vast expanse |\n| 全景 | wide shot | Wide establishing shot | 全景 | a wide establishing shot |\n| 中景 | medium shot | Medium shot | 中景 | a medium shot |\n| 近景 | close-up | Close-up | 近景 | a close-up shot |\n| 特写 | close-up | Close-up | 特写 | a close-up capturing fine detail |\n| 大特写 | extreme close-up | Extreme close-up | 大特写 | an extreme close-up |\n\n## 运镜 → 镜头标签映射\n\n| videoDesc 中的运镜 | KlingOmni（英文标签） | Seedance 1.5（英文标签） | Seedance 2.0（中文描述） | Wan 2.6（英文叙事式） |\n|------|------|------|------|------|\n| 静止 | static camera | Static, no camera movement | 镜头静止 | static camera, locked off |\n| 推进 | dolly in / push in | Slow dolly forward | 镜头缓慢向前推进 | camera slowly pushing in |\n| 拉远 | dolly out / pull back | Slow dolly backward pull | 镜头缓慢向后拉远 | camera gently pulling back |\n| 跟踪 | tracking shot | Tracking shot, handheld | 跟踪拍摄 | tracking shot following the subject |\n| 摇镜 | pan left/right | Slow pan | 镜头缓慢摇移 | smooth pan across the scene |\n| 甩镜 | whip pan | Whip pan | 快速甩镜 | whip pan |\n| 升降 | crane up/down | Crane up/down | 镜头升降 | crane rising / descending |\n| 环绕 | surround shooting | Orbiting shot | 环绕拍摄 | orbiting around the subject |\n\n---\n\n## 执行流程\n\n1. **解析输入**：提取模型名和多参标志，按路由规则匹配模式；提取资产列表\n2. **构建 @图N 编号表**：资产按输入顺序从 `@图1 ` 起编号，分镜图接续编号；`shouldGenerateImage=\"false\"` 的分镜不分配分镜图编号\n3. **逐条解析 `<storyboardItem>`**：按 videoDesc 解析规则提取12个字段，结合 `duration`、`associateAssetsIds` 建立标签映射\n4. **整合为一个完整的视频提示词**：按目标模型格式编排全部分镜\n5. **输出视频提示词**\n\n---\n\n## 约束\n\n- **仅输出视频提示词**：不附加任何解释、注释、分析过程、推理步骤、模型匹配说明、资产编号表、分隔线（`---`）或额外说明，只输出视频提示词文本。禁止在提示词前后输出任何非提示词内容\n- **严格遵循 videoDesc**（全模式通用）：提示词内容严格基于 videoDesc 中的画面描述、时长、景别、运镜、角色动作、情绪、光影氛围、台词、音效字段生成，不编造额外内容\n- **台词不可缺失**（全模式通用）：videoDesc 中有台词的分镜，必须在提示词中完整体现台词内容，不得遗漏\n- **台词保持原始输入**（全模式通用）：台词内容严禁翻译，必须保持 videoDesc 中的原始语言原样输出\n- **台词类型标注**（全模式通用）：必须区分普通对白（dialogue / 说）、内心独白（OS / 内心OS）、画外音（VO / 画外音VO），并在提示词中正确标注\n- **时间跨度最低 1 秒**（全模式通用）：所有模式中涉及时间分段（Motion 时间轴 / Seedance 2.0 分镜时长 {N}s）的最小粒度为 1 秒（1s），禁止出现 0.5 秒等低于 1 秒的间隔\n- **视觉风格**：风格相关描述参考 Assistant 中的「视觉风格约束」部分内容，不在本 Skill 内自行定义风格\n- **严格按匹配到的模式格式**，不混用不同模式的格式\n- **不修改原始输入**：不改写 `<storyboardItem>` 的任何字段；`prompt` 已有的分镜图提示词仅作画面参考\n- **不编造资产或台词**：只使用输入中的资产信息；无台词则标注「无台词」/ `No dialogue`\n- **时长单位**：Seedance 2.0 的分镜时长直接使用秒，格式为 `{N}s`（如 `4s`），最低 1s\n', NULL),
(4, '音色绑定', 'audioBindPrompt', '你是一个音色匹配助手。\n你的任务是：根据给定角色资产的名称与描述，从候选音频列表中选出最合适的音色。\n匹配规则：\n1. 优先根据角色性别、年龄、性格等特征与音色描述进行语义匹配；\n2. 同一角色仅可匹配一个音色；\n3. 若候选列表中没有合适的音色，则无需返回 audioId；', NULL);
INSERT INTO `o_script` (`id`, `name`, `content`, `projectId`, `extractState`, `createTime`, `errorReason`) VALUES
(1, '惊蛰 EP01：烛照梁', '# 惊蛰 EP01：烛照梁\n# 目标时长：4分钟 ≈ 600字台词\n# 平台：横屏16:9 | 风格：3D国风赛博 | 节拍：驱虫仪式→窑火已熄→被拒门外→虚空拉坯→墙头羞辱→院外叩门\n\n---\n\n## 剧情梗概\n\n二月二，龙抬头。暮色里，泥瓶巷孤苦少年陈平安依照祖辈习俗，手持蜡烛桃枝在破败老宅中驱虫祈福。他十四岁，爹娘早逝，烧瓷手艺随官窑关闭而废弛，师傅姚老头也在去年秋天死在窑头前。曾去铁匠铺求一口饭吃，被阮铁匠斜瞥一眼拒之门外。但他从未放下拉坯的手艺——夜深人静时闭眼站立院中，双手在虚空模拟拉坯，十指青筋暴起，以OS吐出压抑已久的求生意志：\"老天不给路——我就用这双手，自己踩出一条。\"邻居宋集薪蹲墙头以\"寒门无贵子\"将他踩到最底。话音未落，院门外传来陌生锦衣少年的声音：\"你这婢女——卖不卖？\"陈平安猛然回头——命运的齿轮在龙抬头之夜悄然转动。\n\n---\n\n## 剧本正文\n\n1-1 老宅屋内 暮色/内\n\n人物：陈平安\n\n△暮色如凝固的血，从破败窗棂渗入。黄土夯成的老宅四壁空空——一张硬木板床，墙角堆着落满灰的轱辘车残骸。墙上依稀可见褪色的釉线纹路，那是小镇官窑鼎盛时家家户户墙上都有的发光符纹，如今早已熄灭，只剩一道道暗沉的凹槽。\n\n△陈平安——十四五岁，身形清瘦，粗布衣衫打着三四处补丁但浆洗得干净——一手持蜡烛，一手持新折的桃枝。烛火摇曳，在土墙上投下他单薄的影子。影子随着烛光晃动，像一棵被风吹弯的细竹。\n\n△他举起蜡烛照向房梁角落。烛光扫过蛛网。桃枝在梁柱上敲打——\"笃、笃、笃\"——动作虔诚而熟练。这是他父母还在时就学会的仪式。\n\n陈平安（低声念叨）：\n二月二，烛照梁，桃打墙，人间蛇虫无处藏。\n\n△他走向墙角，弯腰。桃枝在阴暗处反复扫过，驱赶看不见的蛇蝎蜈蚣。一滴烛泪滚落，落在他虎口的旧茧上。他没有缩手。他直起腰，环顾空荡荡的屋子——除了他自己的影子，什么都没有。\n\n---\n\n1-2 院中 暮色转夜/外\n\n人物：陈平安\n\n△院中。新折的桃枝搁在石阶旁，断口还渗着树汁。陈平安吹灭蜡烛——一缕青烟在暮色里散尽。他在台阶上坐下，双手搁在膝上，仰头。\n\n△空镜。远处，数十座龙窑沿山脊连绵起伏，形若卧龙。窑口被官府铁条封死，窑体上的铜铁联动装置锈迹斑斑——那是当年朝廷督造时安装的窑温监测机关，如今像龙的肋骨裸露在外。没有一丝火光。这座小镇的窑火，已经死了三年了。\n\n△切回陈平安。少年面孔被初现的星光映亮。他的眼睛很安静，但不是空洞——像一潭深水，水面无波，底下有暗流。\n\n陈平安（OS，平静得近乎冷漠）：\n窑火熄了三年。师傅姓姚——去年暮秋，一个人坐在窑头前，闭了眼。没人知道他在那儿坐了多久。\n\n△闪回画面，仅三秒：一个瘦削老人坐在小竹椅上，面对熄灭的窑炉。晨光勾勒出他侧脸的轮廓，嘴角似乎还挂着一丝笑。画面消散，像被风吹散的窑灰。\n\n陈平安（OS）：\n师傅嫌我没悟性。榆木疙瘩，不开窍。我认。\n\n△他低头看着自己摊开的双手。虎口和指腹布满老茧，十指微微蜷曲——那是经年累月拉坯留下的形状，像一副摘不下来的手套。\n\n陈平安（OS）：\n可我这双手——从来没放下过。\n\n---\n\n1-3 骑龙巷铁匠铺 日/外（闪回）\n\n人物：陈平安 阮铁匠 众少年若干\n\n△闪回。正午日光刺眼。骑龙巷口，临时搭起的铁匠铺子前围了七八个少年。铺内火星四溅，叮当锤声刺耳，炉膛中火光带着一丝诡异的幽蓝——这年头，连打铁的都在炉炭里掺了些不知名的矿石粉末。\n\n△陈平安站在人群最前面，胸膛微微起伏——他是一路跑来的，额头上还挂着汗。\n\n△阮铁匠——膀大腰圆的中年汉子，肩搭汗巾——从铺内走出。他的目光扫过少年们，在陈平安身上停了一瞬。不是审视，是打量一件不合用的工具。\n\n阮铁匠（朝陈平安身后一指）：\n下一个。\n\n陈平安（上前一步）：\n我——\n\n阮铁匠（头也不抬，转身回铺）：\n不收。\n\n△陈平安僵在原地。身后的少年鱼贯而入，有人擦过他肩膀时还推了一把。风箱拉动，炉火猛然蹿高。铁匠铺内一片通红。陈平安瘦削的轮廓被火光勾勒出来——站在门外，与门内的世界隔着一道光做的墙。\n\n△闪回结束。\n\n---\n\n1-4 院中 夜/外\n\n人物：陈平安\n\n△夜色如墨。月光清冷，洒在黄土院墙上，墙上那些褪色的釉线在月光下泛出极微弱的暗纹——像大地干裂的血管。\n\n△陈平安站在院中央，闭眼。他缓缓抬起双臂，双手在虚空中张开——那是一个拉坯匠人最熟悉的起手式：左手虚托泥坯底部，右手四指轻按泥壁。\n\n△他动了。十指在虚空中模拟拉坯。手腕微颤，指节用力。动作起初生涩——像锈住的齿轮——渐渐流畅。汗水从他额角滑落，沿着脸颊滴入衣领。\n\n△特写：他紧闭的双眼。眉头深锁。嘴唇紧抿成一条线。\n\n陈平安（OS，低沉而缓慢，像从牙缝里挤出来）：\n爹说过——手艺人，饿不死。\n\n△他的手猛然加速，像在与某种看不见的力量较劲。十指青筋暴起，双臂肌肉绷紧。他的呼吸变得粗重。\n\n△中景：月光下，少年站在破败院中，双手在虚空里与命运角力。墙上他的影子扭曲、膨胀、收缩——像一个正在挣脱枷锁的魂。\n\n陈平安（OS，压抑中带着狠劲）：\n老天不给路——\n\n△大特写：双手在虚空中猛然一收。十指如钳。指节发白。那一瞬间，虚空中仿佛真有一个泥坯在他掌间成形——虽然什么都没有，但每一根手指都在与不存在的黏土对话。\n\n陈平安（OS，一字一顿）：\n——我就用这双手，自己踩出一条。\n\n△他睁眼。眼中不是绝望。是一种沉默而顽固的光——像埋在灰烬里的火种，不烈，但不灭。\n\n△他慢慢放下双手，熟练地抖了抖手腕。这个动作他重复了千百遍——没有师傅教，是他自己瞎琢磨出来的门道。他走到石阶旁，拿起桃枝，在手中转了一圈。\n\n---\n\n1-5 院中/墙头 夜/外\n\n人物：陈平安 宋集薪 稚圭\n\n△一声刺耳的讥笑划破寂静。陈平安停下脚步，但没有转头——他听得出这个声音。\n\n△宋集薪——与陈平安年龄相仿的锦衣少年，衣衫虽旧但质地考究，袖口隐隐有暗纹流转——蹲在隔壁低矮的黄土墙头上。月光下，他蹲墙头的姿势活像一只在枝头嘲笑猎物的乌鸦。泥瓶巷的院墙矮得可怜，他根本不用踮脚就能看到这边的一切，偏偏每次都要蹲上墙头。\n\n△墙的另一边，婢女稚圭站在院中。她约莫十三四岁，一双杏眼怯怯地望着这边。她扯了扯自己的袖角，像一只察觉到危险的小兽。\n\n宋集薪（咧嘴）：\n陈平安，你刚才在干什么？手在空中瞎比划——跟庙会耍把式的似的。\n\n△陈平安不答，继续抖手腕。动作不紧不慢。\n\n宋集薪（从墙头探出身子，语气夸张）：\n哦——我忘了。拉坯，是吧？你那点手艺——\n\n△他伸出一根手指，在空中画了个圈。\n\n宋集薪：\n——练了三年，抵不过人家刘羡阳半年。窑都关了，师傅也死了，你还练？练给谁看啊？\n\n△沉默。陈平安停下抖手腕的动作。他抬起头，月光落在他的脸上。\n\n陈平安（平静，目光不躲不闪）：\n练给自己看。\n\n△宋集薪一怔。随即仰头大笑，笑声在空巷里回荡。\n\n宋集薪：\n好！好一个\"练给自己看\"！\n\n△笑声戛然而止。他的目光居高临下，像在打量一件窑炉里捡出来的废瓷。\n\n宋集薪（慢悠悠，每一个字都像在剥陈平安的皮）：\n你知道你像什么吗？像窑炉里烧废了的瓷器——釉色花了，胎骨裂了，偏偏不肯碎。还搁在架子上，自己骗自己，说——我还有用。\n\n△陈平安沉默。他的手微微攥紧桃枝，指节泛白。但他的脊梁没有弯。\n\n宋集薪（压低声音，嘴角仍挂着笑）：\n寒门无贵子——\n\n△他顿了顿，让这句话落在夜风里，像一块石头沉入深井。\n\n宋集薪：\n陈平安——你这辈子、下辈子，都逃不掉。\n\n△寂静。陈平安站在原地。月光将他的影子拉得又细又长，从院中延伸到黄土墙根。他没有低头。但他也没有反驳。他只是站在那里，攥着那根桃枝，指节泛白。\n\n△就在这一刻——\n\n△院门外，夜色如深渊。两个模糊的身影停在那里。锦衣华服被月光勾勒出一线银边。\n\n锦衣少年（OS，轻佻含笑，像在谈论一件有趣的物件）：\n你这婢女——卖不卖？\n\n△陈平安猛然回头。宋集薪脸上的笑容像被冻住。稚圭瞪大杏眼，脸色惨白，下意识后退半步。\n\n△画面定格。院门外，月光只照到锦衣少年的半幅衣摆——面料在月色下泛起微弱的金属光泽，上面的纹路像某种古老的符阵。\n\n△字幕淡入：二月二，龙抬头。', 1779904318831, 1, NULL, NULL),
(2, '惊蛰 EP02：锦衣叩门', '# 惊蛰 EP02：锦衣叩门\n# 目标时长：4分钟 ≈ 600字台词\n# 平台：横屏16:9 | 风格：3D国风赛博 | 节拍：锦衣叩门→婢女买卖→鲤鱼因果→拒赏→四脚蛇疑云\n\n---\n\n## 剧情梗概\n\n锦衣少年踏着月光踏入泥瓶巷，一句\"你这婢女——卖不卖？\"将宋集薪的傲慢炸得粉碎。白银一万两、黄金万两、逗你玩的——三连击碾压之后，锦衣少年转向陈平安，谈起白天那条金色鲤鱼。闪回揭晓因果：陈平安在骑龙巷看中一条鲤鱼，囊中羞涩与鱼贩子讨价还价之际，被锦衣少年以五十文截走。回到此刻，锦衣少年丢出沉甸甸的绣袋作为酬谢。陈平安接住，低头——然后挺直脊梁，将绣袋递还：\"银货两讫。这赏钱——不必了。\"一个穷到骨子里的少年，面对锦衣华服不卑不亢。锦衣少年笑容凝固，老者眯着的眼第一次真正睁开。锦衣少年离去后，宋集薪忽然压低声音提起那条四脚蛇——\"额头隆起来——\"话未说完，被稚圭惊恐扯断。陈平安眼中闪过一丝困惑。春雷隐隐，从远方滚过泥瓶巷的上空。\n\n---\n\n## 剧本正文\n\n2-1 院门口/院中 夜/外\n\n人物：陈平安 宋集薪 稚圭 锦衣少年 吴爷爷\n\n△画面从第1集定格处\"解冻\"。月光如水，漫过泥瓶巷低矮的黄土墙。院门外那两个模糊的轮廓缓缓走进月光——锦衣少年十五六岁，一袭月白长衫，袖口和领缘绣着暗金色云纹，在月色下泛起细微的金属光泽，那些纹路并非寻常刺绣，丝线中嵌着若有若无的光点，像微缩的星辰在面料中缓缓流动。他眉眼含笑，神态闲适，像逛自家后花园。\n\n△身后跟着一位身形高大的老者——吴爷爷。面容白皙，须发灰白但梳得一丝不苟。他的眼睛眯成两条细缝，嘴角挂着和蔼的笑意，目光从陈平安身上轻轻滑过——像溪水流过一块不起眼的石头——却在宋集薪和稚圭身上各自停了一瞬。\n\n锦衣少年（目光越过陈平安，落在他身后院中的稚圭身上，语气漫不经心，像在问一柄扇子的价钱）：\n你这婢女——卖不卖？\n\n△宋集薪从墙头跳下。落地时脚下一滑，扶了一下墙才站稳，但脸上的倨傲一秒都没丢。他挡在稚圭身前，斜眼打量着锦衣少年——衣料上的暗纹流光让他瞳孔微缩，但嘴角立刻勾起一抹冷笑。\n\n宋集薪（双手抱胸）：\n卖！怎么不卖！\n\n锦衣少年（微笑不变）：\n那你说个价。\n\n△宋集薪伸出一根手指，在月光下慢悠悠地晃了晃。稚圭在他身后瞪大了杏眼，嘴唇微张，像一头突然被猎人瞄准的幼鹿。\n\n宋集薪（一字一顿，像在报一个能把对方吓退的数字）：\n白银一万两。\n\n△锦衣少年面不改色，微微颔首。那姿态不像在谈一笔买卖——倒像在确认今天的晚风确实是从东边吹来的。\n\n锦衣少年：\n好。\n\n△宋集薪的笑容冻在脸上。他飞快地扫了锦衣少年一眼——对方身后那老者依旧眯眼微笑，双手拢在袖中，像在看一出排了很久的戏。宋集薪的喉结滚了一下。\n\n宋集薪（声音陡然拔高，指尖发颤）：\n——是黄金万两！\n\n△锦衣少年嘴角翘起。那个笑容不紧不慢地绽放——像在棋盘上落下最后一枚棋子，然后抬眼欣赏对手的表情。\n\n锦衣少年：\n逗你玩的。\n\n△宋集薪脸色铁青。他攥紧拳头，指节发白。稚圭在他身后轻轻扯了扯他的衣角，他深吸一口气，硬生生把怒意咽了下去——他咽得那么用力，下颌骨都绷出了棱角。\n\n△锦衣少年不再理睬宋集薪。他偏转视线，望向陈平安。那目光里不再是戏弄——是一种认真的好奇，像在打量一件第一眼没看明白的物件。\n\n锦衣少年：\n今天多亏了你——\n\n△陈平安微微皱眉。月光勾勒出他清瘦面孔的轮廓线条。他不认识这个人——但对方华服上流转的金属光泽，在这条连窑火都死了三年的泥瓶巷里，像一颗从天外掉进来的陨石。\n\n锦衣少年（语气郑重起来）：\n——我才能买到那条鲤鱼。金灿灿的，越看越欢喜。\n\n△锦衣少年顿了顿，抬起双手，对陈平安行了一个少年人之间不常见的拱手礼——动作不算标准，但诚意不假。\n\n锦衣少年（笑脸灿烂）：\n专程让吴爷爷带我来，当面道一声谢。\n\n△陈平安的瞳孔微微放大。他记起来了——白天的骑龙巷，那条在鱼篓里蹦跳的金色尾巴。\n\n---\n\n2-2 骑龙巷 日/外（闪回）\n\n人物：陈平安 中年人 锦衣少年 吴爷爷\n\n△闪回。正午的骑龙巷。青石板路被日光晒得发白，热气从石缝里蒸腾出来，扭曲了远处的街景。一个穿粗布短褂的中年人拎着鱼篓走过——篓子里一尾巴掌长的金黄鲤鱼正在拼命蹦跳，鳞片在阳光下炸开碎金似的光芒。\n\n△陈平安从巷口拐出。他的目光被那道金色牢牢锁住，脚步不由自主跟了上去。他的眼睛亮了——在这座连窑火都熄了的小镇里，一条金灿灿的活物，比十座龙窑更能让一个少年心跳加速。\n\n陈平安（追上中年人，声音急切）：\n大叔，这鲤鱼——十文钱，卖不卖？\n\n中年人（头也不回，脚步不停）：\n十文？你当我傻？三十文！\n\n△陈平安紧跟在中年人身后，步伐急促。他的手不自觉地摸向腰间——那里只有孤零零的十几枚铜钱，在干瘪的钱袋里发出细微的碰撞声。\n\n陈平安（咬了咬嘴唇）：\n十五文——不，二十文！\n\n△中年人脚步慢了下来。他侧头瞥了陈平安一眼，似乎在掂量这个穷少年的诚意。鱼篓里，金色鲤鱼又蹦了一下，水花溅到陈平安脸上。\n\n△就在这时——街角转出两个人影。走在前面的锦衣少年一眼就锁定了鱼篓中那道金色。他眼睛一亮，大步走上前。\n\n锦衣少年（从腰间摸出一串铜钱，随手抛给中年人，动作轻巧得像丢一颗石子）：\n五十文。连篓子。\n\n△中年人眉开眼笑，一把接过铜钱，将鱼篓塞进锦衣少年手中。整个过程快得像一场早有预谋的交易。\n\n△陈平安站在原地。他看着锦衣少年拎起鱼篓——那条金色鲤鱼在篓子里蹦了一下，尾巴甩出一串细碎的水珠，在日光下闪了闪，然后消失在街角。少年的手还按在腰间那只干瘪的钱袋上。\n\n△闪回结束。\n\n---\n\n2-3 院中 夜/外\n\n人物：陈平安 锦衣少年 吴爷爷 宋集薪 稚圭\n\n△切回。月光重新洒在陈平安脸上。他眨了眨眼，从白天的记忆中回过神。\n\n△锦衣少年从袖中掏出一只沉甸甸的绣袋。袋口的绳结是银丝编成的，在月光下泛着冷光。他随手一抛——绣袋在空中划出一道短促的弧线。\n\n△陈平安下意识接住。低头。绣袋的分量压在掌心，沉甸甸的，比他腰间那只干瘪的钱袋重十倍不止。袋口微敞，露出里面银锭的边角，在月光下泛出柔润的光泽。\n\n锦衣少年（转身欲走，语气轻快得像完成了一件微不足道的小事）：\n这是酬谢——你我就算两清了。\n\n△陈平安低头看着手中的绣袋。他的手指微微收紧。虎口上那些拉坯磨出的老茧，与光滑的绸缎袋面触碰——粗糙与柔滑，在这只十四岁少年的掌心里对峙。\n\n△特写。他的拇指在绣袋上摩挲了一下。然后停住。\n\n△他抬起头。月光落在他脸上——那张清瘦的脸上没有犹豫，没有挣扎之后的释然。那双眼睛里是一种平静——像深潭，投进去一颗石头也溅不起水花，因为水太深了。\n\n陈平安（平静，但字字清晰，像将一枚铜板按在青石板上）：\n我卖鱼，你买鱼。\n\n△他上前一步。将绣袋递还。手很稳——那双刚才在虚空中与命运角力的手，此刻托着一袋沉甸甸的银子，却像托着一片落叶。\n\n陈平安（目光不躲不闪，直视锦衣少年的眼睛）：\n银货两讫。这赏钱——不必了。\n\n△锦衣少年脸上的笑容凝固了——不是愤怒，不是被冒犯，而是一种从未被预演过的意外。他转过身，第一次真正审视面前这个穷少年。从头到脚——破败的院子，打着补丁的衣衫，刚被宋集薪羞辱过的脊梁。但那脊梁此刻挺得笔直，那双眼睛不躲不闪，像两颗钉在夜色里的铁钉。\n\n△宋集薪张着嘴，忘了合上。他看看绣袋，又看看陈平安——那表情像看到一条泥瓶巷里的野狗拒绝了送到嘴边的肉。\n\n△老者原本眯着的眼睛——微微睁开了。那双眼睛里不再是和蔼，而是一种安静的审视。目光从陈平安脸上缓缓移动到他还举着绣袋的手上，再移回他的眼睛。那目光里有惊讶，有思索，还有一丝难以名状的意味——像是认出了某种很久以前见过的东西。\n\n△锦衣少年盯着陈平安看了三秒。三秒里，泥瓶巷静得只剩夜风刮过枯草的声音。然后他忽然笑了——这次的笑不再是轻佻，不再是戏弄，而是一种被勾起兴趣的欣赏。\n\n锦衣少年（伸手接过绣袋，动作干脆利落）：\n有意思。\n\n△他转头看向老者。老者微微点头——幅度极小，但分量不轻。\n\n锦衣少年（收起绣袋，转身）：\n吴爷爷，走吧。\n\n△两人转身。锦衣少年的步伐轻快依旧，但走出三步后，他忽然放慢了脚步——像在回味什么。老者临走前，回头多看了陈平安一眼。那一眼不是打量一件物品，是记住一个人。\n\n△两人的身影渐渐被夜色吞没。锦衣少年袖口的暗金色光点在黑暗中最后闪了一下，然后消失——像两颗流星沉入深海。\n\n[硬切]\n\n---\n\n2-4 院中 夜/外\n\n人物：陈平安 宋集薪 稚圭\n\n△寂静重新降临泥瓶巷。月光冷冷地铺在黄土墙上，那些褪色的釉线暗纹在月色中若隐若现。\n\n△宋集薪站在院中，盯着锦衣少年消失的方向。他的下颌还在发紧。刚才被\"逗你玩的\"四个字扇的那记耳光——没有声音，但比任何真耳光都响。\n\n宋集薪（忽然转头，盯着陈平安，声音里带着一种说不清是嘲讽还是困惑的复杂意味）：\n你知不知道那袋银子——够你把院墙翻新三遍，还能剩一桌酒席钱？\n\n△陈平安不答。他低头看着自己的双手——那双刚才递还绣袋的手，那双在虚空中与命运角力的手。月光洒在虎口的旧茧上。\n\n陈平安（轻声，像在对自己说）：\n我爹说过——手艺人，不靠赏钱吃饭。\n\n△宋集薪语塞。他想说什么，张了张嘴，却发现自己准备好的每一句嘲讽都对不上此刻的气氛。他沉默了片刻，然后忽然想起了什么——眼神变了。不再是嘲讽，是一种带着兴奋和不安的郑重。\n\n宋集薪（压低声音，凑近矮墙）：\n陈平安——\n\n△陈平安抬起头。\n\n宋集薪（声音压得更低，像在分享一个不该说的秘密）：\n你还记得正月里那条四脚蛇吗？\n\n△陈平安点头。他当然记得——正月初一，宋集薪坐在门槛上晒太阳，那条四脚蛇被一次次摔出去，又一次次爬回来。最后被甩过墙头，落在他院中。\n\n宋集薪（眼睛发亮，语速加快，声音里带着一丝连他自己都没察觉的战栗）：\n那条四脚蛇，额头隆起来——\n\n△稚圭猛地扯住宋集薪的袖子。用力之大，把宋集薪整个人拽得踉跄了一步。宋集薪转头——少女的杏眼中满是惊恐，不是害怕锦衣少年时的那种怯弱，而是一种更深层的、近乎本能的恐惧。她拼命摇头，嘴唇哆嗦着，说不出话，但抓着他袖子的手指已经掐进了布料。\n\n△宋集薪硬生生把后半句话咽了回去。喉结滚动。月光下，他的表情变了——从兴奋变成了某种若有所思的沉默。\n\n△夜风穿过泥瓶巷。墙头的枯草瑟瑟作响。远处天际，隐隐有春雷滚过——闷闷的一声，像大地在翻身。\n\n宋集薪（改口，声音恢复了往常的漫不经心，但眼神还没完全收回来）：\n我和稚圭——下个月就要离开这里了。\n\n△陈平安沉默。少年的眼中闪过一丝困惑——不是对\"离开\"，是对那句被掐断的话。额头隆起。然后呢？宋集薪咽回去的后半句像一根鱼刺，卡在夜色里，吞不下也吐不出。\n\n△他没有追问。只是点了点头。但那双眼睛里——第一次——有了一种不同于以往的光。不是绝望，不是沉默的骨气。是一种正在苏醒的警觉。像一头沉睡的动物，听到了远处丛林中树枝折断的声音。\n\n△画面拉远。月光下，三个少年站在泥瓶巷的两座院子里，隔着矮墙。远处的春雷又滚了一声——比刚才更近。\n\n△镜头缓缓升起。泥瓶巷的全景——一排排低矮的黄土墙，连绵起伏的龙窑轮廓在远方山脊上若隐若现。一个清瘦少年独自站在院中，低头看着自己的双手。\n\n△定格。\n\n△字幕淡入：额头隆起，然后呢？', 1779904318831, 1, NULL, NULL),
(3, '惊蛰 EP03：龙抬头', '# 惊蛰 EP03：龙抬头\n# 目标时长：4分钟 ≈ 600字台词\n# 平台：横屏16:9 | 风格：3D国风赛博 | 节拍：四脚蛇回溯→头生角→离开→春雷→推门→龙抬头\n\n---\n\n## 剧情梗概\n\n第2集末宋集薪那句被稚圭掐断的话，在第三集开场被补全——\"额头隆起，如头顶生角。\"闪回三连击完整揭露超自然线索：正月里宋集薪一次次把四脚蛇摔出去，它一次次爬回来，被甩过墙头落入陈平安院中；次日它出现在陈平安床底，额头已隐隐隆起。回到此刻，稚圭惊恐扯断对话，宋集薪咽下后半句，改口透露下个月将携稚圭离开小镇。陈平安独自躺在硬木板床上，闭眼念叨\"碎碎平安\"。春雷在窗外炸响——他猛然睁眼，翻身下床，从床底摸出破旧包袱，推门踏入雷光翻滚的院中。\"平安不是等来的。\"少年清瘦身影立于天地之间，宛如一柄出鞘的刀。画面定格。字幕浮现：二月二，龙抬头。\n\n---\n\n## 剧本正文\n\n3-1 院中/陈平安屋内 夜/外→内（闪回）\n\n人物：陈平安 宋集薪 稚圭\n\n△画面从第2集末\"解冻\"。月光冷冷地铺在泥瓶巷两座毗邻的黄土院墙上——墙上那些褪色的釉线暗纹在月色中泛出极微弱的金属光泽，像某种被遗忘的电路。陈平安仍站在院中，清瘦面孔被月光劈成明暗两半。他的眉头微锁——不是愤怒，是一种正在凝聚的警觉，像一头沉睡的动物听到了远处丛林中树枝折断的声音。\n\n△矮墙另一侧。宋集薪盯着锦衣少年消失的方向——那个方向现在只剩夜雾翻涌。他转回头。月光下，他惯常的嘲讽表情不见了，取而代之的是一种混合了兴奋和不安的郑重——像一个赌徒在揭开骰盅前最后那一瞬的表情。\n\n宋集薪（压低声音，比第2集末更轻、更慢，每一个字都像在薄冰上行走）：\n额头隆起——\n\n△他顿了顿。夜风在这一刻停了。泥瓶巷静得能听见墙头枯草摩擦的声音。\n\n宋集薪（喉结滚动，终于把那句吞了三十天的后半句吐了出来）：\n——如头顶生角。\n\n△陈平安瞳孔骤缩。他的手指猛地收紧——那根桃枝在虎口处被攥得发出细微的咯吱声。画面切至他的眼睛——那双一向沉静如深潭的眼睛，此刻有涟漪在扩散。\n\n△闪回——画面以褪色偏白调性切入，只有琥珀色的暖光残留在画面边缘，像一张正在燃烧的旧纸。正月，阳光冷白如刀。宋集薪坐在门槛上晒太阳，一条灰褐色的四脚蛇从门槛下溜过——动作极快，贴着地面像一道影子——往屋里钻。\n\n△宋集薪一把抓住它。五指粗暴地箍住四脚蛇的躯干，拎起来——那东西在他手中扭动，细小的四肢在空中乱划。宋集薪抡圆了手臂，狠狠摔向院中。四脚蛇砸在黄土院面上，弹了一下，肚皮朝天。尘土飞扬。\n\n△片刻。四脚蛇翻过身。又开始往屋里爬——动作比刚才慢，但方向不变。\n\n宋集薪（闪回中，声音带着恼火和一丝不易察觉的恐惧）：\n又来！你还来？！\n\n△他再次抓起四脚蛇——这次双手并用，像投一颗石子——甩过矮墙。四脚蛇在空中划出一道抛物线，越过黄土墙头，落入陈平安院中。落地时发出一声闷响。那声音很轻，但在寂静的正午，像一颗种子被种进土里。\n\n△闪回画面转场——次日清晨，薄雾如纱。陈平安弯腰，一只手撑着床板，另一只手拨开床底积灰的杂物。他的动作停住。床底角落，那条四脚蛇蜷缩成一团，一动不动——但它活着，腹部微微起伏。它的额头处，隐隐有隆起的弧度，像皮肤下埋着一颗正在生长的石子。\n\n△陈平安（闪回中）直起腰。他没有驱赶它，也没有触碰它。只是站在床边看了它一会儿。然后转身，像往常一样走出屋子。那时候的他，还没学会追问\"为什么\"。\n\n△闪回结束。切回此刻。月光重新洒在院中，但月光似乎比刚才更冷了。陈平安站在原地，嘴唇微微张开。他不由自主地偏头——目光穿过敞开的屋门，落向那张硬木板床，那个床底。\n\n陈平安（声音很轻，轻到像在对自己确认一个刚刚听懂的秘密）：\n……在我床底下。从正月到现在。\n\n△宋集薪点头。他的表情不再是嘲讽，也不是恐惧——是一种复杂的、连他自己都说不清的东西。他张开嘴，似乎还想说什么。\n\n△稚圭猛地扯住宋集薪的袖子——比第2集扯得更用力，指节发白，布料被攥出了深深的褶皱。她整个人都在轻微发抖。杏眼里已不是惊恐——是某种更深层的东西，像一只被猎人的箭瞄准的幼鹿，全身每一块肌肉都绷紧了。\n\n稚圭（声音发颤，语速极快，几乎是尖叫的前一刻）：\n别说了——别再说了！\n\n△宋集薪闭嘴。月光下，三个少年隔着矮墙。沉默像一堵看不见的墙压下来，比泥瓶巷任何一堵黄土墙都更沉重。远处天际，隐隐有春雷滚过——闷闷的一声，像大地在翻身。\n\n[硬切]\n\n---\n\n3-2 院中 夜/外\n\n人物：陈平安 宋集薪 稚圭\n\n△沉默持续了三次呼吸的时间。夜风重新穿过泥瓶巷，墙头枯草瑟瑟作响。远处春雷又滚了一声——比刚才更近，闷闷的，像一头巨兽在云层深处翻身。\n\n△宋集薪深吸一口气。他把刚才的郑重收起来，重新换上了惯常那副漫不经心的表情——但换得不够利落，嘴角的弧度比平时僵硬，眼底还有来不及收走的阴影。\n\n宋集薪（声音恢复了往常的轻快，但眼神没跟上，像一件穿反了的衣裳）：\n我和稚圭——下个月就要离开这里了。\n\n△他顿了顿，看了一眼稚圭。少女低着头，手指还绞着自己的衣角，指节泛白。月光落在她发顶，将她额前碎发的影子投在脸上，像一道细密的栅栏。\n\n宋集薪（忽然笑了一下——那个笑容里有某种陈平安从未见过的东西，不是嘲讽，是一种陌生的、接近真诚的意味）：\n说实话——我也不知道要去哪儿。但总得走。\n\n△陈平安沉默。他看着宋集薪，又看了看稚圭。少女始终没有抬头。他的目光在两人之间来回了一次，然后轻轻叹了口气——那声叹息很短，很轻，像一片枯叶从枝头落下，还没落地就被风吹散了。\n\n陈平安：\n路上小心。\n\n△宋集薪张了张嘴。他似乎想说什么——一句嘲讽、一句玩笑、或者那句被稚圭掐断的话语的真正后半段——但最终什么都没说。他转身，拉着稚圭的袖子，两人一前一后消失在矮墙的另一面。\n\n△空镜。陈平安独自站在院中。月光将他的影子投在黄土院墙上——不再是那个被风吹弯的细竹般的少年，影子里的脊梁是直的。远处，第三声春雷滚过——比前两声更沉，更近。他抬起头，望向天际翻滚的黑云。那双眼睛里——不再是困惑，不再是隐忍，是一种正在被锻造的锋利，像一块铁终于烧到了临界温度。\n\n[叠化]\n\n---\n\n3-3 陈平安屋内 夜/内\n\n人物：陈平安\n\n△屋内。黑暗浓稠如墨。陈平安躺在硬木板床上，闭着眼。呼吸看似平稳——但他攥着被角的手指微微发白。木板床之下，泥土深处，似乎有什么在微微震动——极其细微，像一颗深埋的种子在用尽全力拱开头顶的土。\n\n陈平安（闭眼，嘴唇微动，声音极轻，像在念一道只有自己听得见的咒语）：\n碎碎平，岁岁安。碎碎平安，岁岁平安……\n\n△窗外。一道闪电劈开夜空。电光透过破败窗棂，在土墙上劈出栅栏般的影子——墙上那些早已熄灭的釉线凹槽，在电光中闪过一瞬微弱的反光，像某种被遗忘的电路试图重新通电。然后黑暗重新吞没一切。\n\n△春雷炸响——这次不是远处闷闷的翻滚，是一声撕裂天地的怒吼，就在头顶。整座老宅微微颤抖，墙角的轱辘车残骸发出细碎的震颤声。\n\n△陈平安猛然睁眼。\n\n△他坐起身。月光与残留的电网蓝光从窗棂同时渗入，照亮他清瘦面孔的轮廓线条——颧骨，下颌，绷紧的嘴唇。他的目光在黑暗中闪烁。不再是白天的隐忍、夜晚的困惑。那目光像一块被反复淬炼的铁，终于从炉膛里夹了出来——通体透亮，边缘锋利。\n\n△他翻身下床。赤脚踩在夯土地上。弯腰。从床底摸出一个破旧包袱——动作利落，没有一丝犹豫，像这个动作他已经练习了一千次。包袱很旧，粗布上打着一块补丁，但那块补丁的针脚走得极细密——是他自己缝的。\n\n△他站起身。包袱斜挎在肩上。少年站在黑暗中，环顾这间住了十四年的老宅——空空的四壁，墙角的轱辘车残骸，墙上那些早已熄灭的釉线暗纹。他的目光在那些釉线上停了一瞬。嘴唇微动，无声地念了两个字——也许是\"师傅\"，也许是\"爹娘\"。\n\n△然后他转身。面向那扇破败的木门。门缝里透进一线微光——不是月光，是远方天际正在逼近的雷暴。\n\n[硬切]\n\n---\n\n3-4 院中 夜/外\n\n人物：陈平安\n\n△木门被推开。吱呀一声，像一声悠长的叹息——但推门的手很稳。\n\n△陈平安踏入院中。春雷在他头顶炸响——电光劈开夜空，将整个泥瓶巷照得惨白如昼。他的清瘦面孔在电光中一闪——眼睛是湿的，但嘴角紧抿成一条直线。不是因为软弱。是因为他终于决定：不再等。\n\n△他仰起头。翻滚的黑云压得很低，像一口倒扣的窑炉。第二道闪电劈落——这次更近，劈在远处龙窑的方向。电光沿着山脊蔓延，勾勒出数十座龙窑的轮廓。那些窑炉被封死多年，窑体上的铜铁联动装置锈迹斑斑——但在电光中，锈迹泛起诡异的蓝芒，像一条条骨节嶙峋的卧龙在闪电中短暂复活。\n\n△陈平安深吸一口气。雨水尚未落下，但空气里已经满是暴雨将至的腥甜。他迈出一步——踏入院中央，那个他曾在虚空中与命运角力的地方。破旧包袱在肩上晃动。\n\n陈平安（对着雷光翻滚的天际，声音不高，但每一个字都像钉子钉进木头里——沉稳、笃定、不可动摇）：\n平安不是等来的。\n\n△第三道春雷炸响。狂风卷起院中的枯叶，在他脚边打旋。少年逆着风，又迈出一步。他的背影在电光与暗夜的交替中一明一灭——像一座正在被雷电淬炼的雕像。\n\n△特写：陈平安的眼睛。那双眼里不再有迷茫，不再有隐忍，是一种沉默的锋利——像一柄刚刚从磨刀石上抬起来的刀，刃口还挂着水珠，但已经能劈开风。\n\n△镜头缓缓拉远。泥瓶巷全景——一排排低矮的黄土矮墙，连绵起伏的龙窑在远方山脊上若隐若现。暴雨将至，天际被闪电撕开一道裂缝——一半是墨黑的乌云，一半是银白的电光。那个清瘦的少年站在院中，提着破旧包袱，仰头望向天地之间那道裂缝。他就站在那里——像站在命运的门槛上。一脚在泥瓶巷的黄土里，一脚已经踩进了雷光。\n\n△画面定格。雨水始终没有落下。但少年的眼睛已经湿了——不是因为软弱。是因为一个被世界定义为\"寒门弃子\"的少年，终于挺直了脊梁，自己推开了门。\n\n△字幕缓缓浮现——字体是粗粝的篆刻风格，笔画间有微弱的暗金色光点流动：二月二，龙抬头。\n\n△画面淡出。最后一帧：陈平安的背影，走向院门。门外的世界被电光照亮——看不清具体是什么，只有一片刺目的、正在裂开的光。', 1779904318831, 1, NULL, NULL);
