INSERT INTO `o_storyboard` (`id`, `scriptId`, `prompt`, `filePath`, `duration`, `state`, `trackId`, `reason`, `track`, `videoDesc`, `shouldGenerateImage`, `projectId`, `flowId`, `index`, `createTime`) VALUES
(1, 1, '@图1 为补丁常服角色 @图2 为蜡烛道具 @图3 为桃枝道具 @图4 为老宅屋内场景 @图5 为轱辘车残骸道具,\n\n【画面】@图4，全景构图，黄土夯成的老宅四壁空空，墙上褪色釉线暗纹如干裂血管，墙角堆着@图5落满灰；@图1 身形清瘦站立于画面中央，3/4背面朝右，一手持@图2一手持@图3静立屋中，@图2烛火摇曳在土墙上投下单薄影子，孤寂而立，神情温良沉静。\n\n【风格】3D渲染风格，高精度高模建模，PBR物理材质，3D国风赛博，新中式赛博朋克，东方科幻美学，电影级光影，光线追踪，全局光照，3D国风赛博场景渲染，中式黄土老宅与赛博釉线暗纹有机融合，建筑细节丰富，3D国风赛博渲染，东方科幻美学，新中式赛博朋克内核，中式美学与赛博元素有机融合，古风场景风格统一，PBR物理材质，电影级院线渲染，3D高清渲染，8K超高清，高细节，高精度高模建模，PBR物理材质，画面无字幕、无水印、无标题叠字、无UI界面。\n\n保持 @图1 面部特征、发型、服饰与参考图完全一致。', '/1779904318831/assets/1/a72a0b01-1100-48ff-b866-bc204645540e.jpg', '4', '已完成', 1779913878940, NULL, '1', '镜1·烛照梁：黄土夯成的老宅四壁空空，墙上褪色釉线暗纹如干裂血管，墙角轱辘车残骸落满灰。陈平安一手持蜡烛一手持桃枝静立屋中，3/4背面朝右，烛火摇曳，孤寂温良。全景静止，时长4秒。无台词，蜡芯噼啪微响与窗外远处犬吠。资产：陈平安(补丁常服)、蜡烛、桃枝、老宅屋内、轱辘车残骸', 1, 1779904318831, NULL, 0, 1779913878937),
(2, 1, '@图1 为补丁常服角色 @图2 为蜡烛道具 @图3 为桃枝道具 @图4 为老宅屋内场景,\n\n【画面】@图4，近景构图，@图1 3/4正面朝右微仰头，缓缓举起@图2照向房梁角落，烛光扫过蛛网；@图1 手中@图3在梁柱上有节奏敲打，手腕沉稳虔诚；然后走向墙角弯腰，面朝右微低头，将@图3探入角落处反复扫过；@图2烛泪沿蜡烛滑落，滴在@图1虎口旧茧上，手指微颤但未缩回，神情虔诚坚韧。\n\n【风格】3D渲染风格，高精度高模建模，PBR物理材质，3D国风赛博，新中式赛博朋克，东方科幻美学，电影级光影，光线追踪，全局光照，3D国风赛博人物建模，高精PBR贴图，新中式补丁粗布服饰纹理清晰，发丝细腻物理渲染，皮肤质感真实，3D国风赛博场景渲染，中式黄土老宅与赛博釉线暗纹有机融合，3D国风赛博渲染，东方科幻美学，新中式赛博朋克内核，中式美学与赛博元素有机融合，古风场景风格统一，PBR物理材质，电影级院线渲染，3D高清渲染，8K超高清，高细节，高精度高模建模，PBR物理材质，画面无字幕、无水印、无标题叠字、无UI界面。\n\n保持 @图1 面部特征、发型、服饰与参考图完全一致。', '/1779904318831/assets/1/0d26217a-ade2-43aa-b7cd-77700df34b1a.jpg', '10', '已完成', 1779913886440, NULL, '2', '镜2·桃打墙：陈平安缓缓举起蜡烛照向房梁角落，扫过蛛网；桃枝在梁柱上有节奏敲打笃笃笃，动作虔诚熟练；然后走向墙角弯腰，桃枝在角落处反复扫过；一滴烛泪滚落，落在虎口旧茧上，手指微颤但未缩回。近景缓慢上摇，时长10秒。台词：二月二，烛照梁，桃打墙，人间蛇虫无处藏。音效：桃枝敲梁笃笃笃、蜡芯噼啪、桃枝扫墙角沙沙声、烛泪滴落声。资产：陈平安、蜡烛、桃枝、老宅屋内', 1, 1779904318831, NULL, 1, 1779913886437),
(3, 1, '@图1 为补丁常服角色 @图2 为老宅屋内场景,\n\n【画面】@图2，中景构图，@图1 面朝左缓缓直起腰，转头环顾空荡荡的屋子四壁，目光最终落回自己脚下，黄土夯墙上褪色釉线暗纹如干裂血管。孤寂空落的氛围中，@图1 身形清瘦立于空屋中央，神情空落。\n\n【风格】3D渲染风格，高精度高模建模，PBR物理材质，3D国风赛博，新中式赛博朋克，东方科幻美学，电影级光影，光线追踪，全局光照，3D国风赛博人物建模，高精PBR贴图，新中式补丁粗布服饰纹理清晰，发丝细腻物理渲染，皮肤质感真实，3D国风赛博场景渲染，中式黄土老宅与赛博釉线暗纹有机融合，3D国风赛博渲染，东方科幻美学，新中式赛博朋克内核，中式美学与赛博元素有机融合，古风场景风格统一，PBR物理材质，电影级院线渲染，3D高清渲染，8K超高清，高细节，高精度高模建模，PBR物理材质，画面无字幕、无水印、无标题叠字、无UI界面。\n\n保持 @图1 面部特征、发型、服饰与参考图完全一致。', '/1779904318831/assets/1/fe4591cf-59f6-48a0-a6bd-1afd178f7bef.jpg', '4', '已完成', 1779913892294, NULL, '3', '镜3·空屋环顾：陈平安缓缓直起腰，转头环顾空荡荡的屋子——四壁空空，除了自己的影子什么都没有。中景缓慢拉远，时长4秒。无台词，寂静中远处一声犬吠。资产：陈平安、老宅屋内', 1, 1779904318831, NULL, 2, 1779913892292),
(4, 1, '@图1 为补丁常服角色 @图2 为桃枝道具 @图3 为蜡烛道具 @图4 为院中场景,\n\n【画面】@图4，中景构图，@图2搁在石阶旁断口渗着树汁；@图1 3/4正面朝右走到石阶旁放下@图2，随即吹灭@图3，一缕青烟从烛芯升起散尽，身形清瘦立于破败院中，神情沉静落寞。\n\n【风格】3D渲染风格，高精度高模建模，PBR物理材质，3D国风赛博，新中式赛博朋克，东方科幻美学，电影级光影，光线追踪，全局光照，3D国风赛博人物建模，高精PBR贴图，新中式补丁粗布服饰纹理清晰，3D国风赛博场景渲染，黄土院墙釉线暗纹赛博质感，3D国风赛博渲染，东方科幻美学，新中式赛博朋克内核，中式美学与赛博元素有机融合，古风场景风格统一，PBR物理材质，电影级院线渲染，3D高清渲染，8K超高清，高细节，高精度高模建模，PBR物理材质，画面无字幕、无水印、无标题叠字、无UI界面。\n\n保持 @图1 面部特征、发型、服饰与参考图完全一致。', '/1779904318831/assets/1/ffa1d8f6-f2e9-456b-92f8-9610357cde95.jpg', '4', '已完成', 1779913897837, NULL, '4', '镜4·吹灭蜡烛：院中，桃枝搁在石阶旁，断口渗着树汁。陈平安走到石阶旁放下桃枝，吹灭蜡烛，一缕青烟从烛芯升起散尽。中景静止，时长4秒。无台词，吹灭蜡烛的气声与夜风穿过破院墙的呜咽声。资产：陈平安、桃枝、蜡烛、院中', 1, 1779904318831, NULL, 3, 1779913897834),
(5, 1, '@图1 为补丁常服角色 @图2 为院中场景,\n\n【画面】@图2，近景构图，@图1 3/4正面朝左微仰头，转身在石阶坐下，双手搁膝，缓缓仰头望向远方，神情沉静内敛，眼中如深潭无波。\n\n【风格】3D渲染风格，高精度高模建模，PBR物理材质，3D国风赛博，新中式赛博朋克，东方科幻美学，电影级光影，光线追踪，全局光照，3D国风赛博人物建模，高精PBR贴图，新中式补丁粗布服饰纹理清晰，3D国风赛博场景渲染，黄土院墙赛博釉线暗纹，3D国风赛博渲染，东方科幻美学，新中式赛博朋克内核，中式美学与赛博元素有机融合，古风场景风格统一，PBR物理材质，电影级院线渲染，3D高清渲染，8K超高清，高细节，高精度高模建模，PBR物理材质，画面无字幕、无水印、无标题叠字、无UI界面。\n\n保持 @图1 面部特征、发型、服饰与参考图完全一致。', '/1779904318831/assets/1/1027cca9-92a6-42fb-9724-5a37ca55e37f.jpg', '3', '已完成', 1779913902361, NULL, '5', '镜5·独坐院中：陈平安转身在石阶坐下，双手搁膝，缓缓仰头望向远方。近景静止，时长3秒。无台词，夜风呜咽声持续。资产：陈平安、院中', 1, 1779904318831, NULL, 4, 1779913902358),
(6, 1, '@图1 为院中场景,\n\n【画面】@图1，大远景构图，镜头从画面左端缓慢横摇至右端，远处数十座龙窑沿山脊连绵起伏形若卧龙；窑口被铁条封死，铜铁联动装置锈迹斑斑如龙骨裸露在外。苍凉死寂，无一丝火光。\n\n【风格】3D渲染风格，高精度高模建模，PBR物理材质，3D国风赛博，新中式赛博朋克，东方科幻美学，电影级光影，光线追踪，全局光照，3D国风赛博场景渲染，龙窑群中式古窑与赛博机械结构有机融合，锈蚀金属质感真实，山脊轮廓纵深，3D国风赛博渲染，东方科幻美学，新中式赛博朋克内核，中式美学与赛博元素有机融合，古风场景风格统一，PBR物理材质，电影级院线渲染，3D高清渲染，8K超高清，高细节，高精度高模建模，PBR物理材质，画面无字幕、无水印、无标题叠字、无UI界面。', '/1779904318831/assets/1/d5c917ff-c2f0-4395-be3f-3bcd10c49d70.jpg', '5', '已完成', 1779913907493, NULL, '6', '镜6·龙窑死寂：空镜——远处数十座龙窑沿山脊连绵起伏形若卧龙。窑口被铁条封死，铜铁联动装置锈迹斑斑如龙骨裸露。大远景缓慢横摇，时长5秒。苍凉死寂，无台词。远处龙窑铁件在风中轻撞的金属声。资产：院中', 1, 1779904318831, NULL, 5, 1779913907492),
(7, 1, '@图1 为补丁常服角色 @图2 为院中场景,\n\n【画面】@图2，近景构图，@图1 3/4正面朝左微仰头，保持仰头姿势，面孔安静；眼睑微动，眼睛很深如深潭，水面无波而底下有暗流，瞳孔深处有暗流般的微光。面容沉郁内敛，神情淡淡目光悠远。\n\n【风格】3D渲染风格，高精度高模建模，PBR物理材质，3D国风赛博，新中式赛博朋克，东方科幻美学，电影级光影，光线追踪，全局光照，3D国风赛博人物建模，高精PBR贴图，新中式补丁粗布服饰纹理清晰，发丝细腻物理渲染，皮肤质感真实，3D国风赛博场景渲染，黄土院墙赛博釉线暗纹，3D国风赛博渲染，东方科幻美学，新中式赛博朋克内核，中式美学与赛博元素有机融合，古风场景风格统一，PBR物理材质，电影级院线渲染，3D高清渲染，8K超高清，高细节，高精度高模建模，PBR物理材质，画面无字幕、无水印、无标题叠字、无UI界面。\n\n保持 @图1 面部特征、发型、服饰与参考图完全一致。', '/1779904318831/assets/1/c206d52f-a657-45e6-ad95-752fc65c5335.jpg', '4', '已完成', 1779913912780, NULL, '7', '镜7·深潭暗流：陈平安保持仰头姿势，面孔安静——眼睛很深，像深潭，水面无波，底下有暗流。眼睑微动，瞳孔深处有暗流般的微光。近景静止，时长4秒。台词OS：窑火熄了三年。音效：夜风呜咽渐弱。资产：陈平安、院中', 1, 1779904318831, NULL, 6, 1779913912776),
(8, 1, '@图1 为院中场景,\n\n【画面】@图1，中景构图，闪回画面，瘦削老人坐在小竹椅上面对熄灭的窑炉，身体纹丝不动，侧脸轮廓被微光勾勒，嘴角似乎挂着一丝笑；画面从边缘开始如被风吹散的窑灰般飘散消逝。悲凉而静谧。\n\n【风格】3D渲染风格，高精度高模建模，PBR物理材质，3D国风赛博，新中式赛博朋克，东方科幻美学，电影级光影，光线追踪，全局光照，3D国风赛博场景渲染，窑炉中式古窑与赛博机械结构融合，3D国风赛博渲染，东方科幻美学，新中式赛博朋克内核，中式美学与赛博元素有机融合，古风场景风格统一，PBR物理材质，电影级院线渲染，3D高清渲染，8K超高清，高细节，高精度高模建模，PBR物理材质，画面无字幕、无水印、无标题叠字、无UI界面。', '/1779904318831/assets/1/8bbf7089-aff1-4822-a368-eda89a6598e9.jpg', '3', '已完成', 1779913917409, NULL, '8', '镜8·师傅闪回：闪回——瘦削老人坐在小竹椅上，面对熄灭的窑炉。侧脸轮廓，嘴角似乎挂着一丝笑。画面如被风吹散的窑灰从边缘开始消散。中景静止，时长3秒。悲凉静谧，无台词。细微的风吹窑灰沙沙声。资产：院中', 1, 1779904318831, NULL, 7, 1779913917406),
(9, 1, '@图1 为补丁常服角色 @图2 为院中场景,\n\n【画面】@图2，特写构图，@图1 面朝下缓缓低头，双手从膝上抬起在眼前摊开；十指自然微蜷，虎口和指腹布满拉坯老茧清晰可见，十指蜷曲如经年拉坯留下的形状如摘不下来的手套；指节轻动，老茧在虎口处互相摩擦。神情沉郁不甘。\n\n【风格】3D渲染风格，高精度高模建模，PBR物理材质，3D国风赛博，新中式赛博朋克，东方科幻美学，电影级光影，光线追踪，全局光照，3D国风赛博人物建模，高精PBR贴图，手部老茧细节拉满，皮肤质感真实，3D国风赛博渲染，东方科幻美学，新中式赛博朋克内核，中式美学与赛博元素有机融合，古风场景风格统一，PBR物理材质，电影级院线渲染，3D高清渲染，8K超高清，高细节，高精度高模建模，PBR物理材质，画面无字幕、无水印、无标题叠字、无UI界面。\n\n保持 @图1 面部特征、发型、服饰与参考图完全一致。', '1779904318831/assets/1/b4da88f6-8b93-4951-832d-21a6ed4e5278.jpg', '12', '已完成', 1779913923429, NULL, '9', '镜9·双手老茧：陈平安缓缓低头，双手从膝上抬起在眼前摊开——虎口和指腹布满老茧，十指微微蜷曲如经年拉坯留下的形状，像摘不下来的手套。指节轻动，老茧互相摩擦。特写静止，时长12秒。台词OS：师傅姓姚——去年暮秋，一个人坐在窑头前，闭了眼。没人知道他在那儿坐了多久。音效：衣料摩擦微响、老茧摩擦细微沙响。资产：陈平安、院中', 1, 1779904318831, 1, 8, 1779913923425),
(10, 1, '@图1 为补丁常服角色 @图2 为院中场景,\n\n【画面】@图2，近景构图，@图1 正面微低头缓缓抬起头，嘴唇微抿成线，眉头轻皱，片刻后眉头松开，眼神恢复平静，神情隐忍认命。唇线平直，神态淡淡目光悠远。\n\n【风格】3D渲染风格，高精度高模建模，PBR物理材质，3D国风赛博，新中式赛博朋克，东方科幻美学，电影级光影，光线追踪，全局光照，3D国风赛博人物建模，高精PBR贴图，新中式补丁粗布服饰纹理清晰，发丝细腻物理渲染，皮肤质感真实，3D国风赛博渲染，东方科幻美学，新中式赛博朋克内核，中式美学与赛博元素有机融合，古风场景风格统一，PBR物理材质，电影级院线渲染，3D高清渲染，8K超高清，高细节，高精度高模建模，PBR物理材质，画面无字幕、无水印、无标题叠字、无UI界面。\n\n保持 @图1 面部特征、发型、服饰与参考图完全一致。', '/1779904318831/assets/1/ccb5a506-5d24-4d9d-a04a-1cb9c821fc3e.jpg', '7', '已完成', 1779913928212, NULL, '10', '镜10·认命：陈平安缓缓抬起头，嘴唇微抿，眉头轻皱，片刻后眉头松开，眼神恢复平静。近景静止，时长7秒。台词OS：师傅嫌我没悟性。榆木疙瘩，不开窍。我认。音效：夜虫唧唧渐起。资产：陈平安、院中', 1, 1779904318831, NULL, 9, 1779913928208),
(11, 1, '@图1 为补丁常服角色 @图2 为院中场景,\n\n【画面】@图2，中景构图，@图1 背面朝向镜头，双手撑膝缓缓站起，走入院中央站定；脊梁挺直，双手垂在身侧，十指仍微微蜷着呈拉坯手形，背影清瘦而挺拔，沉静蓄力。\n\n【风格】3D渲染风格，高精度高模建模，PBR物理材质，3D国风赛博，新中式赛博朋克，东方科幻美学，电影级光影，光线追踪，全局光照，3D国风赛博人物建模，高精PBR贴图，新中式补丁粗布服饰纹理清晰，3D国风赛博场景渲染，黄土院墙釉线暗纹赛博质感，3D国风赛博渲染，东方科幻美学，新中式赛博朋克内核，中式美学与赛博元素有机融合，古风场景风格统一，PBR物理材质，电影级院线渲染，3D高清渲染，8K超高清，高细节，高精度高模建模，PBR物理材质，画面无字幕、无水印、无标题叠字、无UI界面。\n\n保持 @图1 面部特征、发型、服饰与参考图完全一致。', '/1779904318831/assets/1/9730e854-0692-4d20-87dc-826569ca7132.jpg', '5', '已完成', 1779913933280, NULL, '11', '镜11·起身入院：陈平安双手撑膝缓缓站起，走入院中央站定，脊梁挺直，双手自然垂在身侧，十指仍微微蜷着。中景静止，时长5秒。台词OS：可我这双手——从来没放下过。音效：脚步声、夜虫唧唧。资产：陈平安、院中', 1, 1779904318831, NULL, 10, 1779913933276),
(12, 1, '@图1 为骑龙巷铁匠铺场景,\n\n【画面】@图1，全景构图，铁匠铺内锤打正酣，火星四溅飞舞，风箱被拉动，炉膛中火光带着一丝诡异的幽蓝。灼热喧嚣，铺内一片通红忙碌。\n\n【风格】3D渲染风格，高精度高模建模，PBR物理材质，3D国风赛博，新中式赛博朋克，东方科幻美学，电影级光影，光线追踪，全局光照，3D国风赛博场景渲染，中式铁匠铺与赛博矿石幽蓝炉火有机融合，金属工具质感真实，3D国风赛博渲染，东方科幻美学，新中式赛博朋克内核，中式美学与赛博元素有机融合，古风场景风格统一，PBR物理材质，电影级院线渲染，3D高清渲染，8K超高清，高细节，高精度高模建模，PBR物理材质，画面无字幕、无水印、无标题叠字、无UI界面。', '/1779904318831/assets/1/4db2b077-0d82-4635-9ec0-bbb2ec5513aa.jpg', '3', '已完成', 1779913937899, NULL, '12', '镜12·铁匠铺：空镜——铁匠铺内火星四溅，叮当锤声刺耳，风箱拉动，炉膛中火光带着一丝诡异的幽蓝。全景静止，时长3秒。灼热喧嚣，无台词。音效：叮当锤声刺耳、风箱拉动呼哧声、炉膛火焰低吼。资产：骑龙巷铁匠铺', 1, 1779904318831, NULL, 11, 1779913937897),
(13, 1, '@图1 为补丁常服角色 @图2 为骑龙巷铁匠铺场景,\n\n【画面】@图2，中景构图，@图1 3/4背面朝左站在人群最前面，刚从人群后方挤到最前，胸膛起伏喘气，额头挂着未干的汗珠，急切期待。\n\n【风格】3D渲染风格，高精度高模建模，PBR物理材质，3D国风赛博，新中式赛博朋克，东方科幻美学，电影级光影，光线追踪，全局光照，3D国风赛博人物建模，高精PBR贴图，新中式补丁粗布服饰纹理清晰，发丝细腻物理渲染，皮肤质感真实，3D国风赛博场景渲染，中式铁匠铺与赛博矿石幽蓝炉火有机融合，3D国风赛博渲染，东方科幻美学，新中式赛博朋克内核，中式美学与赛博元素有机融合，古风场景风格统一，PBR物理材质，电影级院线渲染，3D高清渲染，8K超高清，高细节，高精度高模建模，PBR物理材质，画面无字幕、无水印、无标题叠字、无UI界面。\n\n保持 @图1 面部特征、发型、服饰与参考图完全一致。', '/1779904318831/assets/1/2226be0f-9196-4076-abd9-1d73db4ce1e1.jpg', '2', '已完成', 1779913942929, NULL, '13', '镜13·跑来求工：陈平安从人群后方挤到最前面，胸膛微微起伏喘着气，额头汗珠未干——一路跑来的。中景静止，时长2秒。急切期待，无台词。少年们嘈杂脚步声。资产：陈平安、骑龙巷铁匠铺', 1, 1779904318831, NULL, 12, 1779913942924),
(14, 1, '@图1 为阮铁匠角色 @图2 为补丁常服角色 @图3 为骑龙巷铁匠铺场景,\n\n【画面】@图3，近景构图，@图1 肩搭汗巾从铺内走出，3/4正面朝左，目光从左扫到右扫过少年们，在@图2身上停了一瞬——打量一件不合用的工具——随即移开。@图2 3/4背面朝左站在画面中前景，急切而隐忍。@图1神情冷漠审视，面无波澜。\n\n【风格】3D渲染风格，高精度高模建模，PBR物理材质，3D国风赛博，新中式赛博朋克，东方科幻美学，电影级光影，光线追踪，全局光照，3D国风赛博人物建模，高精PBR贴图，新中式补丁粗布服饰与铁匠汗巾纹理清晰，发丝细腻物理渲染，皮肤质感真实，3D国风赛博场景渲染，中式铁匠铺与赛博矿石幽蓝炉火有机融合，3D国风赛博渲染，东方科幻美学，新中式赛博朋克内核，中式美学与赛博元素有机融合，古风场景风格统一，PBR物理材质，电影级院线渲染，3D高清渲染，8K超高清，高细节，高精度高模建模，PBR物理材质，画面无字幕、无水印、无标题叠字、无UI界面。\n\n保持 @图1 @图2 面部特征、发型、服饰与参考图完全一致。', '/1779904318831/assets/1/8f7e7a29-3106-45d4-adc3-b57368432428.jpg', '2', '已完成', 1779913949580, NULL, '14', '镜14·阮铁匠审视：阮铁匠肩搭汗巾从铺内走出，目光从左扫到右扫过少年们，在陈平安身上停了一瞬——打量一件不合用的工具——随即移开。近景静止，时长2秒。冷漠审视，无台词。锤声暂歇、风箱一声低喘。资产：阮铁匠、陈平安、骑龙巷铁匠铺', 1, 1779904318831, NULL, 13, 1779913949574),
(15, 1, '@图1 为阮铁匠角色 @图2 为补丁常服角色 @图3 为骑龙巷铁匠铺场景,\n\n【画面】@图3，中景构图，@图1 3/4背面朝右抬起右手朝@图2身后一指；@图2 3/4正面朝右急上前一步，胸膛微倾；@图1已头也不抬转身回铺，背影消失在铺内幽蓝炉火光中。@图2僵立原地，屈辱刺痛的神情凝固在脸上。\n\n【风格】3D渲染风格，高精度高模建模，PBR物理材质，3D国风赛博，新中式赛博朋克，东方科幻美学，电影级光影，光线追踪，全局光照，3D国风赛博人物建模，高精PBR贴图，新中式补丁粗布服饰与铁匠汗巾纹理清晰，发丝细腻物理渲染，皮肤质感真实，3D国风赛博场景渲染，中式铁匠铺与赛博矿石幽蓝炉火有机融合，3D国风赛博渲染，东方科幻美学，新中式赛博朋克内核，中式美学与赛博元素有机融合，古风场景风格统一，PBR物理材质，电影级院线渲染，3D高清渲染，8K超高清，高细节，高精度高模建模，PBR物理材质，画面无字幕、无水印、无标题叠字、无UI界面。\n\n保持 @图1 @图2 面部特征、发型、服饰与参考图完全一致。', '/1779904318831/assets/1/19ec8c25-4352-443d-ad29-8a82f01f2359.jpg', '5', '已完成', 1779913955401, NULL, '15', '镜15·不收：阮铁匠抬起右手朝陈平安身后一指——下一个。陈平安急上前一步——我——。阮铁匠头也不抬转身回铺——不收——背影消失在铺内。中景静止，时长5秒。屈辱刺痛。音效：阮铁匠转身沉重脚步声、风箱低喘。资产：阮铁匠、陈平安、骑龙巷铁匠铺', 1, 1779904318831, NULL, 14, 1779913955398),
(16, 1, '@图1 为补丁常服角色 @图2 为骑龙巷铁匠铺场景,\n\n【画面】@图2，中景构图，@图1 3/4背面朝左如被钉在原地一动不动；身后少年们鱼贯挤过他身侧涌入铺内，一人擦肩时伸手推了他一把；@图1身体微微一晃仍站在原地，屈辱孤立，脊梁却未弯。\n\n【风格】3D渲染风格，高精度高模建模，PBR物理材质，3D国风赛博，新中式赛博朋克，东方科幻美学，电影级光影，光线追踪，全局光照，3D国风赛博人物建模，高精PBR贴图，新中式补丁粗布服饰纹理清晰，3D国风赛博场景渲染，中式铁匠铺门框赛博质感，3D国风赛博渲染，东方科幻美学，新中式赛博朋克内核，中式美学与赛博元素有机融合，古风场景风格统一，PBR物理材质，电影级院线渲染，3D高清渲染，8K超高清，高细节，高精度高模建模，PBR物理材质，画面无字幕、无水印、无标题叠字、无UI界面。\n\n保持 @图1 面部特征、发型、服饰与参考图完全一致。', '/1779904318831/assets/1/398bc7cf-403c-4ecf-bb0b-b4672ab9b082.jpg', '3', '已完成', 1779913960569, NULL, '16', '镜16·僵住门外：陈平安如被钉在原地一动不动——身后少年们鱼贯挤过他身侧涌入铺内，一人擦肩时推了他一把，陈平安身体微微一晃仍站在原地。中景静止，时长3秒。屈辱孤立，无台词。少年们涌入的杂乱脚步声。资产：陈平安、骑龙巷铁匠铺', 1, 1779904318831, NULL, 15, 1779913960566),
(17, 1, '@图1 为补丁常服角色 @图2 为骑龙巷铁匠铺场景,\n\n【画面】@图2，全景构图，风箱拉动炉火猛然蹿高，铺内一片通红；@图1 3/4背面朝左独自站在门外，瘦削轮廓被炉火勾勒，与门内忙碌的世界隔着一道光做的墙。屈辱而孤立，身形静止如雕像。\n\n【风格】3D渲染风格，高精度高模建模，PBR物理材质，3D国风赛博，新中式赛博朋克，东方科幻美学，电影级光影，光线追踪，全局光照，3D国风赛博人物建模，高精PBR贴图，新中式补丁粗布服饰纹理清晰，3D国风赛博场景渲染，中式铁匠铺门框内外赛博冷暖光墙有机融合，3D国风赛博渲染，东方科幻美学，新中式赛博朋克内核，中式美学与赛博元素有机融合，古风场景风格统一，PBR物理材质，电影级院线渲染，3D高清渲染，8K超高清，高细节，高精度高模建模，PBR物理材质，画面无字幕、无水印、无标题叠字、无UI界面。\n\n保持 @图1 面部特征、发型、服饰与参考图完全一致。', '/1779904318831/assets/1/c0d04d6f-def7-476d-aacb-67fa27c99784.jpg', '3', '已完成', 1779913966188, NULL, '17', '镜17·门墙之隔：风箱拉动炉火蹿高——陈平安独自站在门外，与门内忙碌的世界隔着一道光做的墙。全景静止，时长3秒。屈辱孤立，无台词。风箱低喘、炉火低吼。资产：陈平安、骑龙巷铁匠铺', 1, 1779904318831, NULL, 16, 1779913966185),
(18, 1, '@图1 为补丁常服角色 @图2 为院中场景,\n\n【画面】@图2，全景构图，黄土院墙上釉线暗纹隐约可辨；@图1 正面朝向镜头，脊梁挺直双臂垂在身侧立于院中央，双眼闭合，姿势与铁匠铺门外僵立时相同。孤绝沉静，身形清瘦而挺拔。\n\n【风格】3D渲染风格，高精度高模建模，PBR物理材质，3D国风赛博，新中式赛博朋克，东方科幻美学，电影级光影，光线追踪，全局光照，3D国风赛博人物建模，高精PBR贴图，新中式补丁粗布服饰纹理清晰，3D国风赛博场景渲染，黄土院墙釉线暗纹赛博质感，3D国风赛博渲染，东方科幻美学，新中式赛博朋克内核，中式美学与赛博元素有机融合，古风场景风格统一，PBR物理材质，电影级院线渲染，3D高清渲染，8K超高清，高细节，高精度高模建模，PBR物理材质，画面无字幕、无水印、无标题叠字、无UI界面。\n\n保持 @图1 面部特征、发型、服饰与参考图完全一致。', '/1779904318831/assets/1/c3e2c57c-c047-427b-80ef-0c4868d4654b.jpg', '4', '已完成', 1779913971019, NULL, '18', '镜18·院中站立：黄土院墙上釉线暗纹隐约可辨。陈平安与镜17相同站姿——脊梁挺直、双臂垂在身侧——立于院中央，双眼闭合。全景静止，时长4秒。孤绝沉静，无台词。夜虫唧唧。资产：陈平安、院中', 1, 1779904318831, NULL, 17, 1779913971013),
(19, 1, '@图1 为补丁常服角色 @图2 为院中场景,\n\n【画面】@图2，中景构图，@图1 正面朝向镜头，双臂从身侧缓缓抬起；左手掌心向上虚托泥坯底部，右手四指微曲轻按泥壁，双臂在胸前形成拉坯的圆弧起手式。神情专注虔诚，目光凝聚于虚空中的泥坯。\n\n【风格】3D渲染风格，高精度高模建模，PBR物理材质，3D国风赛博，新中式赛博朋克，东方科幻美学，电影级光影，光线追踪，全局光照，3D国风赛博人物建模，高精PBR贴图，新中式补丁粗布服饰纹理清晰，发丝细腻物理渲染，皮肤质感真实，手部拉坯起手式细节拉满，3D国风赛博场景渲染，黄土院墙釉线暗纹赛博质感，3D国风赛博渲染，东方科幻美学，新中式赛博朋克内核，中式美学与赛博元素有机融合，古风场景风格统一，PBR物理材质，电影级院线渲染，3D高清渲染，8K超高清，高细节，高精度高模建模，PBR物理材质，画面无字幕、无水印、无标题叠字、无UI界面。\n\n保持 @图1 面部特征、发型、服饰与参考图完全一致。', '/1779904318831/assets/1/0cbcdcae-9121-4117-a4e1-090dc0a9f936.jpg', '4', '已完成', 1779913976496, NULL, '19', '镜19·拉坯起手：陈平安双臂从身侧缓缓抬起——左手掌心向上虚托泥坯底部，右手四指微曲轻按泥壁——双臂在胸前形成拉坯的圆弧。拉坯起手式。中景缓慢推近，时长4秒。专注虔诚，无台词。衣料摩擦声、夜虫唧唧。资产：陈平安、院中', 1, 1779904318831, NULL, 18, 1779913976490),
(20, 1, '@图1 为补丁常服角色 @图2 为院中场景,\n\n【画面】@图2，近景构图，@图1 3/4正面朝右微低头，十指在虚空中开始推拉揉捏模拟拉坯；起初手腕生涩微颤如锈住齿轮，三四次循环后动作渐趋流畅；额角汗珠滑落沿脸颊滴入衣领。神情挣扎而专注，唇线紧抿。\n\n【风格】3D渲染风格，高精度高模建模，PBR物理材质，3D国风赛博，新中式赛博朋克，东方科幻美学，电影级光影，光线追踪，全局光照，3D国风赛博人物建模，高精PBR贴图，新中式补丁粗布服饰纹理清晰，发丝细腻物理渲染，皮肤质感真实，手部虚空拉坯动态细节拉满，3D国风赛博场景渲染，黄土院墙釉线暗纹赛博质感，3D国风赛博渲染，东方科幻美学，新中式赛博朋克内核，中式美学与赛博元素有机融合，古风场景风格统一，PBR物理材质，电影级院线渲染，3D高清渲染，8K超高清，高细节，高精度高模建模，PBR物理材质，画面无字幕、无水印、无标题叠字、无UI界面。\n\n保持 @图1 面部特征、发型、服饰与参考图完全一致。', '/1779904318831/assets/1/09f14d00-066b-4470-98b1-0b0256cb1bcb.jpg', '5', '已完成', 1779913981956, NULL, '20', '镜20·虚空拉坯：陈平安十指开始在虚空中推拉揉捏——起初手腕生涩微颤如锈住齿轮，三四次循环后动作渐趋流畅。汗水从额角滑落沿脸颊滴入衣领。近景缓慢推近，时长5秒。挣扎专注，无台词。双手破空微响、汗水滴落声。资产：陈平安、院中', 1, 1779904318831, NULL, 19, 1779913981949),
