INSERT INTO `o_videoTrack` (`id`, `videoId`, `projectId`, `scriptId`, `state`, `reason`, `prompt`, `selectVideoId`, `duration`) VALUES
(1779913878940, NULL, 1779904318831, 1, NULL, NULL, '画面风格和类型: 国风3D渲染，PBR材质，体积光，东方美学，典雅大气，电影风格，国风赛博朋克，新中式未来科技，霓虹全息中式元素，赛博化传统中式建筑，雨幕反光路面，霓虹氛围光效，高对比动态光影，东方古韵与未来科技深度融合，赛博国风场景，超写实3D质感\n\n参考定义:\n@参考1: 陈平安，补丁常服，气质温良淳朴的青年男性\n@参考2: 蜡烛，燃烧的半截白蜡\n@参考3: 桃枝，干燥的桃树枝\n@参考4: 老宅屋内，黄土夯成的破旧老宅内部，四壁空空\n@参考5: 轱辘车残骸，墙角废弃的轱辘车残骸，落满灰尘\n\n生成一个由以下 1 个分镜组成的视频:\n\n场景:\n分镜过渡: 无\n\n分镜1 4s: 时间：夜晚，场景：老宅屋内，镜头：全景，平视，静止镜头，陈平安以3/4背面角度朝右静立屋中，左手持蜡烛，右手持桃枝，烛火微微摇曳映照出人物轮廓与斑驳土墙。无台词。黄土夯成的四壁空空，墙上褪色釉线暗纹如干裂血管，墙角轱辘车残骸落满灰，整体氛围孤寂静默。烛光作为唯一暖调光源，在土墙上投射出摇曳的暖色光晕，人物身体边缘被微弱勾勒，暗部笼罩在清冷阴影中，暖色烛光与冷色暗部形成低调对比。镜头静止，蜡芯噼啪微响，窗外远处传来隐约犬吠。', NULL, 4),
(1779913886440, NULL, 1779904318831, 1, NULL, NULL, '画面风格和类型: 国风3D渲染，PBR材质，体积光，东方美学，典雅大气，电影风格，国风赛博朋克，新中式未来科技，霓虹全息中式元素，赛博化传统中式建筑，雨幕反光路面，霓虹氛围光效，高对比动态光影，东方古韵与未来科技深度融合，赛博国风场景，超写实3D质感\n\n参考定义:\n@参考1: 陈平安，青年男性，气质沉稳内敛，身着简朴布衣\n\n生成一个由以下 1 个分镜组成的视频:\n\n场景:\n分镜过渡: 无\n\n分镜1 10s: 时间：夜，场景：老宅屋内，镜头：近景，平视，缓慢上摇，陈平安缓缓举起蜡烛，暖黄烛光照亮房梁角落，蛛网在光影中飘动。他手持桃枝，在梁柱上有节奏地敲打，动作虔诚而熟练，发出笃笃笃的声响。随后他走向墙角，缓缓弯腰，桃枝在角落处反复扫过，带起细微尘埃，发出沙沙声。一滴烛泪滚落，落在虎口旧茧上，皮肤微微泛红，手指微颤但未缩回。陈平安念诵：「二月二，烛照梁，桃打墙，人间蛇虫无处藏。」，嘴部轻微开合，音色：男声，青年音色，音调中等偏低，音色沉稳略带沙哑，声音厚度适中，发音清晰略带乡音，气息深沉平稳，语速平缓，带虔诚庄重之意。背景是老宅木质梁柱结构，光影在墙面摇曳，角落阴影浓重，尘埃在光柱中飞舞。暖黄烛光为主要光源，侧逆光勾勒人物轮廓，局部高光与深沉阴影形成强烈对比，整体氛围古朴神秘。镜头缓慢上摇，跟随蜡烛光源移动，节奏沉稳。', NULL, 10),
(1779913892294, NULL, 1779904318831, 1, NULL, NULL, '画面风格和类型: 国风3D渲染，PBR材质，体积光，东方美学，典雅大气，电影风格，国风赛博朋克，新中式未来科技，霓虹全息中式元素，赛博化传统中式建筑，雨幕反光路面，霓虹氛围光效，高对比动态光影，东方古韵与未来科技深度融合，赛博国风场景，超写实3D质感\n\n参考定义:\n@参考1: 陈平安，衣着朴素的青年男性，气质沉静内敛\n@参考2: 老宅屋内，四壁空空的老旧中式房屋内部场景\n\n生成一个由以下 1 个分镜组成的视频:\n\n场景:\n分镜过渡: 无\n\n分镜1 4s: 时间：傍晚，场景：老宅屋内，镜头：中景，平视，镜头缓慢拉远，陈平安缓缓直起腰，转头环顾空荡荡的屋子，神情落寞而平静，目光缓缓扫过四壁。无台词。屋内除了他之外空无一物，连影子都显得格外孤单，墙壁斑驳的纹理清晰可见，光线昏暗，尘埃在空气中浮动。日落余晖透过破旧窗棂洒入，冷调侧逆光，长影拉伸，光影对比强烈，氛围孤寂清冷。远处传来一声犬吠。镜头缓慢拉远，人物在空屋中逐渐显得渺小。', NULL, 4),
(1779913897837, NULL, 1779904318831, 1, NULL, NULL, '画面风格和类型: 国风3D渲染，PBR材质，体积光，东方美学，典雅大气，电影风格，国风赛博朋克，新中式未来科技，霓虹全息中式元素，赛博化传统中式建筑，雨幕反光路面，霓虹氛围光效，高对比动态光影，东方古韵与未来科技深度融合，赛博国风场景，超写实3D质感\n\n参考定义:\n@参考1: 陈平安，年轻男性，布衣装束，气质沉稳\n@参考2: 桃枝，折断的桃树枝，断口渗着树汁\n@参考3: 蜡烛，白色蜡烛\n@参考4: 院中，破旧庭院，石阶\n\n生成一个由以下 1 个分镜组成的视频:\n\n场景:\n分镜过渡: 无\n\n分镜1 4s: 时间：夜晚，场景：院中，镜头：中景，平视，静止镜头，陈平安走到石阶旁，弯腰放下桃枝，随后吹灭蜡烛，烛焰摇曳后熄灭，一缕青烟从烛芯袅袅升起散尽，面部表情平静，眼神沉静。无台词。背景是破旧庭院，石阶纹理斑驳，桃枝断口处树汁微渗，夜风穿过破院墙的呜咽声在空气中低回。微弱的烛光作为唯一光源，照出人物的轮廓和石阶的质感，光线柔和偏暖，随着蜡烛熄灭，画面渐暗，青烟在月光或残留的微光中飘散，氛围静谧寂寥。镜头静止。', NULL, 4),
(1779913902361, NULL, 1779904318831, 1, NULL, NULL, '画面风格和类型: 写实电影，沉稳冷调，国风古韵\n\n参考定义:\n@参考1: 陈平安，身着素净布衣，气质坚毅的青年男性\n@参考2: 院中，古朴院落一隅，石阶，夜景\n\n生成一个由以下 1 个分镜组成的视频:\n\n场景:\n分镜过渡: 无\n\n分镜1 3s: 时间：深夜，场景：院中，镜头：近景，平视略仰，静止镜头，陈平安转身，缓缓在石阶上坐下，双手搁在膝上，脊背微弓，他缓缓仰起头，目光望向远方，沉静的身影在夜色中透出孤寂，无台词。背景是古朴的石阶与院墙，深夜静谧，夜风呜咽，院中树叶微动。冷月清辉，以低调侧逆光勾勒出人物轮廓，整体影调深沉厚重，营造孤寂氛围。', NULL, 3),
(1779913907493, NULL, 1779904318831, 1, NULL, NULL, '画面风格和类型: 国风3D渲染，PBR材质，体积光，东方美学，典雅大气，电影风格，国风赛博朋克，新中式未来科技，霓虹全息中式元素，赛博化传统中式建筑，雨幕反光路面，霓虹氛围光效，高对比动态光影，东方古韵与未来科技深度融合，赛博国风场景，超写实3D质感\n\n参考定义:\n@参考1: 院中，荒废破败的龙窑群场景\n\n生成一个由以下 1 个分镜组成的视频:\n\n场景:\n分镜过渡: 无\n\n分镜1 5s: 时间：黄昏或阴天，场景：院中，镜头：大远景，平视或微俯，缓慢横摇，展现远处数十座龙窑沿山脊连绵起伏，形若卧龙。窑口被锈迹斑斑的铁条封死，铜铁联动装置锈蚀裸露，如同龙骨。无台词。环境荒芜，杂草丛生，气氛苍凉死寂。阴天或黄昏的散射光，光线暗淡，色调冷峻压抑。远处龙窑的铁件在风中轻撞，发出零星而空洞的金属声。镜头以极其缓慢的速度横摇，强化空间的广袤与死寂感。', NULL, 5),
(1779913912780, NULL, 1779904318831, 1, NULL, NULL, '画面风格和类型: 真人写实, 电影风格, 暗调, 古风\n\n参考定义:\n@参考1: 陈平安，面容安静、眼神深邃的青年男性角色\n@参考2: 院中，深夜庭院场景\n\n生成一个由以下 1 个分镜组成的视频:\n\n场景:\n分镜过渡: 无\n\n分镜1 4s: 时间：深夜，场景：院中，镜头：近景，平视，静止镜头，陈平安保持仰头姿势，面孔安静，眼睑微动，眼睛极深如深潭，水面无波而瞳孔深处有暗流般的微光流转。陈平安内心OS：「窑火熄了三年。」音色：男声，青年音色，音调中等偏低，音色质感沉稳略带沙哑，声音厚度中等，发音清晰，气息控制均匀，语速缓慢，带沉静而克制的情绪质感。背景院中昏暗，夜风呜咽声渐弱，环境冷寂。', NULL, 4),
(1779913917409, NULL, 1779904318831, 1, NULL, NULL, '画面风格和类型: 国风3D渲染，PBR材质，体积光，东方美学，典雅大气，电影风格，国风赛博朋克，新中式未来科技，霓虹全息中式元素，赛博化传统中式建筑，雨幕反光路面，霓虹氛围光效，高对比动态光影，东方古韵与未来科技深度融合，赛博国风场景，超写实3D质感\n\n参考定义:\n@参考1: 院中，古朴安静的窑炉院落场景\n\n生成一个由以下 1 个分镜组成的视频:\n\n场景:\n分镜过渡: 无\n\n分镜1 3s: 时间：阴天或黄昏，场景：院中，窑炉前，镜头：中景，平视，静止镜头，一位瘦削老人坐在小竹椅上，背对或侧身面向熄灭的窑炉，他的侧脸轮廓被微光勾勒，嘴角似乎挂着一丝若有若无的笑。无台词。背景是熄火冷却的窑炉，余烬微光闪烁，周围环境静谧，窑灰如被风吹散般从画面边缘开始剥离、消散。悲凉静谧的氛围光，阴天散射光或黄昏余晖，低调暗沉影调。镜头静止。', NULL, 3),
(1779913923429, NULL, 1779904318831, 1, NULL, NULL, '画面风格和类型: 国风3D渲染，PBR材质，体积光，东方美学，典雅大气，电影风格，国风赛博朋克，新中式未来科技，霓虹全息中式元素，赛博化传统中式建筑，雨幕反光路面，霓虹氛围光效，高对比动态光影，东方古韵与未来科技深度融合，赛博国风场景，超写实3D质感\n\n参考定义:\n无参考资产\n\n生成一个由以下 1 个分镜组成的视频:\n\n场景:\n分镜过渡: 无\n\n分镜1 12s: 时间：白天，场景：院中，镜头：特写，平视，静止镜头，陈平安缓缓低头，双手从膝上抬起在眼前摊开，虎口和指腹布满老茧，十指微微蜷曲如经年拉坯留下的形状，像摘不下来的手套。指节轻动，老茧互相摩擦。陈平安内心OS：「师傅姓姚——去年暮秋，一个人坐在窑头前，闭了眼。没人知道他在那儿坐了多久。」音色：男声，青年音色，音调中等偏低，音色质朴略带沙哑，声音厚度适中，发音清晰，气息平稳舒缓，语速偏慢，带淡淡的怀念与哀伤。背景院中静谧，衣料摩擦微响，老茧摩擦细微沙沙声。光影氛围柔和自然光，细腻凸显老茧纹理与皮肤质感，安静而深沉的情绪。', NULL, 12),
(1779913928212, NULL, 1779904318831, 1, NULL, NULL, '画面风格和类型: 国风3D渲染，PBR材质，体积光，东方美学，典雅大气，电影风格，国风赛博朋克，新中式未来科技，霓虹全息中式元素，赛博化传统中式建筑，雨幕反光路面，霓虹氛围光效，高对比动态光影，东方古韵与未来科技深度融合，赛博国风场景，超写实3D质感\n\n参考定义:\n@参考1: 陈平安，布衣少年，气质朴实内敛的青年男性\n@参考2: 院中，古朴的院落场景，夜色笼罩\n\n生成一个由以下 1 个分镜组成的视频:\n\n场景:\n分镜过渡: 无\n\n分镜1 7s: 时间：夜晚，场景：院中，镜头：近景，平视，静止镜头，陈平安缓缓抬起头，嘴唇微抿，眉头轻皱，稍作停顿后眉头缓缓松开，眼神从挣扎转为平静，目光低垂凝视前方某处，神情落寞而认命，整体气质朴实隐忍，面色微暗，身体动作幅度极小，仅有面部微表情变化。陈平安内心OS：「师傅嫌我没悟性。榆木疙瘩，不开窍。我认。」音色：男声，青年音色，音调中等偏实，音色干净略带木讷感，声音厚度适中，发音咬字清晰但节奏偏慢，气息沉稳略带低沉，语速偏慢。角色嘴部紧闭不动。背景是夜色笼罩的院落，夜色浓重，远处隐约可见屋舍轮廓，近处地面纹理在夜色中模糊可见，整体环境安静寂寥。夜虫唧唧声渐起，氛围静谧孤寂。散射月光为主，冷调为主，光线柔和但偏暗，人物面部轮廓在微光中明暗分明，光感宁静而沉重。镜头静止。', NULL, 7),
(1779913933280, NULL, 1779904318831, 1, NULL, NULL, '画面风格和类型: 国风3D渲染，PBR材质，体积光，东方美学，典雅大气，电影风格，国风赛博朋克，新中式未来科技，霓虹全息中式元素，赛博化传统中式建筑，雨幕反光路面，霓虹氛围光效，高对比动态光影，东方古韵与未来科技深度融合，赛博国风场景，超写实3D质感\n\n参考定义:\n@参考1: 陈平安，年轻的习武男子，气质坚毅隐忍\n@参考2: 院中，传统中式院落场景\n\n生成一个由以下 1 个分镜组成的视频:\n\n场景:\n分镜过渡: 无\n\n分镜1 5s: 时间：夜，场景：院中，镜头：中景，平视，静止镜头，陈平安双手撑膝缓缓站起，脊梁挺直，走入院中央站定，双手自然垂在身侧，十指仍微微蜷着，面容沉静，眼神深邃而略带疲惫。陈平安内心OS：「可我这双手——从来没放下过。」音色：青年男声，音调偏低，音色质感内敛沉稳，声音厚度适中，发音清晰有力，气息控制适度，语速偏慢，带一丝沙哑与疲惫感。背景是夜色中的寂静院落，四周昏暗，唯有零星灯火或月光勾勒出环境轮廓。夜虫唧唧，脚步声在院中回响。镜头保持静止，聚焦人物从站起到转身走入院的完整动作。', NULL, 5),
